import { GoogleGenAI, Modality, GenerateContentResponse, Part } from "@google/genai";
import { Appointment, ChatMessage } from "../types";

if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

interface GroundingOptions {
    useSearch?: boolean;
    useMaps?: boolean;
    latitude?: number;
    longitude?: number;
}

const getCurrentTimestamp = () => {
    return new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

export const getAIResponse = async (userMessage: string, imagePart: Part | null, grounding: GroundingOptions): Promise<ChatMessage> => {
  try {
    const contents: { parts: Part[] } = { parts: [] };
    if (imagePart) {
        contents.parts.push(imagePart);
    }
    contents.parts.push({ text: userMessage });

    const tools: any[] = [];
    let toolConfig: any = {};

    if (grounding.useSearch) {
        tools.push({ googleSearch: {} });
    }
    if (grounding.useMaps) {
        tools.push({ googleMaps: {} });
        if (grounding.latitude && grounding.longitude) {
            toolConfig.retrievalConfig = {
                latLng: {
                    latitude: grounding.latitude,
                    longitude: grounding.longitude
                }
            };
        }
    }

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: contents,
      ...(tools.length > 0 && { config: { tools }, ...(Object.keys(toolConfig).length > 0 && { toolConfig }) }),
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = groundingChunks.map((chunk: any) => ({
      uri: chunk.web?.uri || chunk.maps?.uri || '#',
      title: chunk.web?.title || chunk.maps?.title || 'Source'
    }));

    return {
        sender: 'ai',
        text: response.text || "I'm having trouble understanding. Could you rephrase?",
        sources: sources.length > 0 ? sources : undefined,
        timestamp: getCurrentTimestamp(),
    };
  } catch (error) {
    console.error("Error generating content from Gemini API:", error);
    return { 
        sender: 'ai', 
        text: "I'm sorry, but I'm having trouble connecting right now. Please try again later.",
        timestamp: getCurrentTimestamp(),
    };
  }
};

export const getWordSuggestions = async (inputText: string, chatHistory: ChatMessage[]): Promise<string[]> => {
  if (!inputText.trim()) {
    return [];
  }
  try {
    const relevantHistory = chatHistory.length > 1 ? chatHistory.slice(-4) : [];
    const historyText = relevantHistory
      .map(msg => `${msg.sender === 'user' ? 'User' : 'AI'}: ${msg.text}`)
      .join('\n');

    const prompt = `You are a predictive text assistant. Suggest 3-4 short, relevant words or phrases the user might type next, based on their input and the conversation history.

Conversation History:
${historyText}

User is typing: "${inputText}"

Provide suggestions as a single, comma-separated string. Example: is normal,about my medication,the side effects are,I feel dizzy when`;

    const response = await ai.models.generateContent({
      model: 'gemini-flash-lite-latest',
      contents: { parts: [{ text: prompt }] },
    });

    const suggestionsText = response.text?.trim();
    if (!suggestionsText) return [];

    return suggestionsText.split(',').map(s => s.trim()).filter(s => s);
  } catch (error) {
    console.error("Error generating word suggestions:", error);
    return [];
  }
};

export const getAppointmentSummary = async (appointment: Appointment): Promise<string> => {
  try {
    const prompt = `Generate a professional medical summary of a patient's consultation (~300 words).

    Patient: Jane Doe
    Professional: ${appointment.doctorName} (${appointment.specialty})
    Date: ${appointment.date}, ${appointment.time}

    Notes: "${appointment.notes}"

    The summary should cover key discussion points, diagnoses, treatment plans, and next steps, in an easy-to-understand format for the patient.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: { parts: [{ text: prompt }] },
    });
    return response.text || "No summary available.";
  } catch (error) {
    console.error("Error generating appointment summary:", error);
    return "Could not generate summary at this time.";
  }
};

export const editImage = async (base64ImageData: string, mimeType: string, prompt: string): Promise<string | null> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    { inlineData: { data: base64ImageData, mimeType } },
                    { text: prompt },
                ],
            },
            config: {
                responseModalities: [Modality.IMAGE],
            },
        });
        const firstPart = response.candidates?.[0]?.content?.parts?.[0];
        if (firstPart && firstPart.inlineData) {
            return firstPart.inlineData.data;
        }
        return null;
    } catch (error) {
        console.error("Error editing image:", error);
        return null;
    }
};

const extractFrames = (videoFile: File): Promise<string[]> => {
    const FRAME_SAMPLE_RATE = 1; // frames per second
    const MAX_FRAMES = 50;
    return new Promise((resolve, reject) => {
        const video = document.createElement('video');
        video.src = URL.createObjectURL(videoFile);
        video.muted = true;

        const canvas = document.createElement('canvas');
        const context = canvas.getContext('2d');
        const frames: string[] = [];

        video.onloadedmetadata = () => {
            canvas.width = video.videoWidth;
            canvas.height = video.videoHeight;
            const duration = video.duration;
            const interval = 1 / FRAME_SAMPLE_RATE;
            let currentTime = 0;

            video.play();

            const captureFrame = () => {
                if (currentTime > duration || frames.length >= MAX_FRAMES) {
                    video.pause();
                    resolve(frames);
                    return;
                }

                video.currentTime = currentTime;
            };

            video.onseeked = () => {
                if (context) {
                    context.drawImage(video, 0, 0, video.videoWidth, video.videoHeight);
                    const base64Data = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];
                    frames.push(base64Data);
                }
                currentTime += interval;
                captureFrame();
            };

            captureFrame();
        };

        video.onerror = (err) => {
            reject('Error loading video file.');
        };
    });
};

export const analyzeVideo = async (videoFile: File, prompt: string): Promise<string> => {
    try {
        const frames = await extractFrames(videoFile);
         if (frames.length === 0) {
            throw new Error("Could not extract any frames from the video.");
        }
        const frameParts = frames.map(frame => ({
            inlineData: {
                mimeType: 'image/jpeg',
                data: frame,
            },
        }));

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-pro',
            contents: { parts: [...frameParts, { text: prompt }] },
        });

        return response.text || "No analysis available.";
    } catch (error) {
        console.error("Error analyzing video:", error);
        return "Sorry, I was unable to analyze the video at this time.";
    }
};

export const generateSpeech = async (text: string): Promise<string | null> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: 'Kore' },
                    },
                },
            },
        });
        const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        return audioData || null;
    } catch (error) {
        console.error("Error generating speech:", error);
        return null;
    }
};

export const generateHealthReport = async (healthData: any): Promise<string> => {
    try {
        const prompt = `As a medical professional AI, analyze the following patient health data and generate a comprehensive, easy-to-understand health report. The report should highlight key trends, potential areas of concern, and suggest lifestyle improvements or questions for their doctor.

Patient Data:
- Health Metrics: ${JSON.stringify(healthData.metrics)}
- Recent Alerts: ${JSON.stringify(healthData.alerts)}
- Medications: ${JSON.stringify(healthData.medications)}
- Upcoming Appointments: ${JSON.stringify(healthData.appointments)}

Generate a detailed report.`;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-pro',
            contents: { parts: [{ text: prompt }] },
            config: {
                thinkingConfig: { thinkingBudget: 32768 }
            }
        });

        return response.text || "No report generated.";
    } catch (error) {
        console.error("Error generating health report:", error);
        return "Could not generate the health report at this time.";
    }
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { getAIResponse, getWordSuggestions, generateSpeech, editImage, analyzeVideo } from '../services/geminiService';
import { ChatMessage, UserProfile } from '../types';
import { SendIcon, MicIcon, ThumbsUpIcon, ThumbsDownIcon, CopyIcon, TrashIcon, CheckCircleIcon, XIcon, UploadIcon, SpeakerIcon, MicOffIcon, EditIcon } from './Icons';
import { GoogleGenAI, LiveServerMessage, Modality, Blob, Part } from "@google/genai";

// General Helper
const fileToGenerativePart = async (file: File): Promise<Part> => {
    const base64EncodedDataPromise = new Promise<string>((resolve) => {
      const reader = new FileReader();
      reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
      reader.readAsDataURL(file);
    });
    return {
      inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
    };
};

const getCurrentTime = () => {
    return new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

// Audio Helper Functions
const decode = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

const encode = (bytes: Uint8Array) => {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> => {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

const createBlob = (data: Float32Array): Blob => {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

const MAX_CHARS = 1000;
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
let nextStartTime = 0;

interface ChatBotProps {
    userProfile: UserProfile;
}

const ChatBot: React.FC<ChatBotProps> = ({ userProfile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
        sender: 'ai', 
        text: "Hello! I'm Boticare AI. How can I help you with your health questions today?", 
        timestamp: getCurrentTime() 
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showClearConfirm, setShowClearConfirm] = useState(false);
  const [copiedMessageIndex, setCopiedMessageIndex] = useState<number | null>(null);
  const [uploadedFile, setUploadedFile] = useState<{ file: File; url: string; type: 'image' | 'video' } | null>(null);
  const [useGrounding, setUseGrounding] = useState(true); // Default grounding to true
  const [audioPlayingIndex, setAudioPlayingIndex] = useState<number | null>(null);

  // Live API State
  const [isLiveSessionActive, setIsLiveSessionActive] = useState(false);
  const sessionPromiseRef = useRef<ReturnType<typeof ai.live.connect> | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const suggestionTimeoutRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  // Mark messages as read after a delay
  useEffect(() => {
    if (messages.length > 0) {
        const lastMessage = messages[messages.length - 1];
        if (lastMessage.sender === 'user' && !lastMessage.isRead) {
            const timer = setTimeout(() => {
                setMessages(prev => prev.map((msg, idx) => 
                    idx === prev.length - 1 ? { ...msg, isRead: true } : msg
                ));
            }, 1000);
            return () => clearTimeout(timer);
        }
    }
  }, [messages.length]);

  useEffect(() => {
    if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current);
    if (input.trim().length > 3) {
      suggestionTimeoutRef.current = window.setTimeout(async () => {
        const fetchedSuggestions = await getWordSuggestions(input, messages);
        if (input.trim().length > 3) setSuggestions(fetchedSuggestions.slice(0, 4));
      }, 500);
    } else {
      setSuggestions([]);
    }
    return () => { if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current); };
  }, [input, messages]);

  const handleSend = async () => {
    if ((input.trim() === '' && !uploadedFile) || isLoading) return;

    setSuggestions([]);
    const currentFile = uploadedFile;
    const currentInput = input;
    const currentTime = getCurrentTime();

    const userMessage: ChatMessage = { 
        sender: 'user', 
        text: currentInput, 
        imageUrl: currentFile?.type === 'image' ? currentFile.url : undefined,
        timestamp: currentTime,
        isRead: false
    };
    setMessages(prev => [...prev, userMessage]);

    setInput('');
    setUploadedFile(null);
    setIsLoading(true);

    try {
        if (currentFile) {
            if (currentFile.type === 'image') {
                const imagePart = await fileToGenerativePart(currentFile.file);
                const aiMessage = await getAIResponse(currentInput, imagePart, { useSearch: useGrounding });
                setMessages(prev => [...prev, aiMessage]);
            } else { // Video analysis
                const analysisText = await analyzeVideo(currentFile.file, currentInput);
                const aiMessage: ChatMessage = { 
                    sender: 'ai', 
                    text: analysisText, 
                    timestamp: getCurrentTime() 
                };
                setMessages(prev => [...prev, aiMessage]);
            }
        } else { // Text only
             let groundingOptions = { useSearch: useGrounding, useMaps: false, latitude: undefined, longitude: undefined };
            if (useGrounding) {
                if (/\b(near me|nearby|closest|find a)\b/i.test(input)) {
                    groundingOptions.useMaps = true;
                    try {
                        const position = await new Promise<GeolocationPosition>((resolve, reject) => navigator.geolocation.getCurrentPosition(resolve, reject));
                        groundingOptions.latitude = position.coords.latitude;
                        groundingOptions.longitude = position.coords.longitude;
                    } catch (e) { console.warn("Could not get location for Maps grounding:", e); }
                }
            }
          const aiMessage = await getAIResponse(input, null, groundingOptions);
          setMessages(prev => [...prev, aiMessage]);
        }
    } catch (error) {
      const errorMessage: ChatMessage = { 
          sender: 'ai', 
          text: 'Sorry, something went wrong.', 
          timestamp: getCurrentTime() 
        };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEditImage = async () => {
    if (!uploadedFile || uploadedFile.type !== 'image' || !input.trim() || isLoading) return;

    setSuggestions([]);
    const currentFile = uploadedFile;
    const currentInput = input;
    const userMessage: ChatMessage = { 
        sender: 'user', 
        text: currentInput, 
        imageUrl: currentFile.url,
        timestamp: getCurrentTime(),
        isRead: false
    };
    setMessages(prev => [...prev, userMessage]);

    setInput('');
    setUploadedFile(null);
    setIsLoading(true);

    try {
        const imagePart = await fileToGenerativePart(currentFile.file);
        const editedB64 = await editImage(imagePart.inlineData.data, imagePart.inlineData.mimeType, currentInput);
        if (editedB64) {
            const aiMessage: ChatMessage = { 
                sender: 'ai', 
                text: 'Here is the edited image:', 
                imageUrl: `data:image/png;base64,${editedB64}`,
                timestamp: getCurrentTime()
            };
            setMessages(prev => [...prev, aiMessage]);
        } else {
            throw new Error("Editing failed to return an image.");
        }
    } catch (error) {
        const errorMessage: ChatMessage = { 
            sender: 'ai', 
            text: 'Sorry, I was unable to edit the image.', 
            timestamp: getCurrentTime()
        };
        setMessages(prev => [...prev, errorMessage]);
    } finally {
        setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleSuggestionClick = (suggestion: string) => {
    setInput(prev => (prev.endsWith(' ') ? prev : prev + ' ') + suggestion + ' ');
    setSuggestions([]);
  };

  const handleConfirmClear = () => {
    setMessages([{ 
        sender: 'ai', 
        text: "Hello! I'm Boticare AI. How can I help you with your health questions today?", 
        timestamp: getCurrentTime()
    }]);
    setShowClearConfirm(false);
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedMessageIndex(index);
    setTimeout(() => setCopiedMessageIndex(null), 2000);
  };

  const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        const fileType = file.type.startsWith('image/') ? 'image' : file.type.startsWith('video/') ? 'video' : null;
        if (fileType) {
            setUploadedFile({
                file,
                url: URL.createObjectURL(file),
                type: fileType,
            });
        }
    }
  };

  const handlePlayAudio = async (text: string, index: number) => {
    if (audioPlayingIndex === index) return;
    setAudioPlayingIndex(index);
    const audioData = await generateSpeech(text);
    if (audioData) {
        const audioBuffer = await decodeAudioData(decode(audioData), outputAudioContext, 24000, 1);
        const source = outputAudioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(outputAudioContext.destination);
        source.start();
        source.onended = () => setAudioPlayingIndex(null);
    } else {
        setAudioPlayingIndex(null);
    }
  };

  const stopLiveSession = useCallback(() => {
    if (sessionPromiseRef.current) {
        sessionPromiseRef.current.then(session => session.close());
        sessionPromiseRef.current = null;
    }
    if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
    }
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }
    if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    setIsLiveSessionActive(false);
    setInput('');
  }, []);

  const startLiveSession = useCallback(async () => {
    if (isLiveSessionActive) {
        stopLiveSession();
        return;
    }

    setIsLiveSessionActive(true);
    setInput("Listening... Speak now. Click the mic again to stop.");

    let currentInputTranscription = '';
    let currentOutputTranscription = '';

    sessionPromiseRef.current = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
            onopen: async () => {
                inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
                streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });
                const source = inputAudioContextRef.current.createMediaStreamSource(streamRef.current);
                scriptProcessorRef.current = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);

                scriptProcessorRef.current.onaudioprocess = (audioProcessingEvent) => {
                    const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                    const pcmBlob = createBlob(inputData);
                    sessionPromiseRef.current?.then((session) => {
                        session.sendRealtimeInput({ media: pcmBlob });
                    });
                };
                source.connect(scriptProcessorRef.current);
                scriptProcessorRef.current.connect(inputAudioContextRef.current.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
                const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (base64Audio) {
                    nextStartTime = Math.max(nextStartTime, outputAudioContext.currentTime);
                    const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
                    const source = outputAudioContext.createBufferSource();
                    source.buffer = audioBuffer;
                    source.connect(outputAudioContext.destination);
                    source.start(nextStartTime);
                    nextStartTime += audioBuffer.duration;
                }

                if (message.serverContent?.inputTranscription) {
                    currentInputTranscription += message.serverContent.inputTranscription.text;
                }
                if (message.serverContent?.outputTranscription) {
                    currentOutputTranscription += message.serverContent.outputTranscription.text;
                }

                if (message.serverContent?.turnComplete) {
                    if (currentInputTranscription.trim()) {
                        setMessages(prev => [...prev, { 
                            sender: 'user', 
                            text: currentInputTranscription.trim(), 
                            timestamp: getCurrentTime(),
                            isRead: true
                        }]);
                    }
                    if (currentOutputTranscription.trim()) {
                        setMessages(prev => [...prev, { 
                            sender: 'ai', 
                            text: currentOutputTranscription.trim(), 
                            timestamp: getCurrentTime()
                        }]);
                    }
                    currentInputTranscription = '';
                    currentOutputTranscription = '';
                }
            },
            onerror: (e: ErrorEvent) => { 
                console.error('Live session error:', e);
                setMessages(prev => [...prev, { 
                    sender: 'ai', 
                    text: "I'm sorry, the voice session disconnected due to an error. Please try again.", 
                    timestamp: getCurrentTime() 
                }]);
                stopLiveSession(); 
            },
            onclose: (e: CloseEvent) => { stopLiveSession(); },
        },
        config: {
            responseModalities: [Modality.AUDIO],
