          className="font-semibold text-gray-600 px-6 py-2 rounded-lg hover:bg-boticare-gray transition-colors dark:text-gray-300 dark:hover:bg-gray-700"
        >
          Reset to Default
        </button>
        <button
          onClick={onSaveChanges}
          className="bg-boticare-primary text-white font-semibold px-6 py-2 rounded-lg hover:bg-opacity-90 transition-colors dark:bg-blue-600 dark:hover:bg-blue-700"
        >
          Save Changes
        </button>
      </div>
    </div>
  );
};

export default AlertPreferences;

import React from 'react';
import { Appointment, AppointmentStatus } from '../types';
import { CalendarIcon, ClockIcon, VideoIcon, NotesIcon, EditIcon, MoreIcon } from './Icons';

interface AppointmentCardProps {
  appointment: Appointment;
  onReschedule?: (appointment: Appointment) => void;
  onCancel?: (appointment: Appointment) => void;
  onJoinVideo?: (appointment: Appointment) => void;
  onViewSummary?: (appointment: Appointment) => void;
  onEditNotes?: (appointment: Appointment) => void;
  onViewDetails?: (appointment: Appointment) => void;
}

const statusStyles = {
  [AppointmentStatus.Upcoming]: 'bg-boticare-blue text-boticare-blue-dark dark:bg-blue-900/50 dark:text-blue-300',
  [AppointmentStatus.Completed]: 'bg-boticare-green text-boticare-green-dark dark:bg-green-900/50 dark:text-green-300',
  [AppointmentStatus.Canceled]: 'bg-boticare-red text-boticare-red-dark dark:bg-red-900/50 dark:text-red-300',
  [AppointmentStatus.Rescheduled]: 'bg-boticare-yellow text-boticare-yellow-dark dark:bg-yellow-900/50 dark:text-yellow-300',
};

const AppointmentCard: React.FC<AppointmentCardProps> = ({ appointment, onReschedule, onCancel, onJoinVideo, onViewSummary, onEditNotes, onViewDetails }) => {
  const handleRescheduleClick = () => {
    if (onReschedule) {
      onReschedule(appointment);
    }
  };

  const handleCancelClick = () => {
    if (onCancel) {
      onCancel(appointment);
    }
  };

  const handleJoinVideoClick = () => {
      if (onJoinVideo) {
          onJoinVideo(appointment);
      }
  };

  const handleViewSummaryClick = () => {
    if (onViewSummary) {
      onViewSummary(appointment);
    }
  };

  const handleEditNotesClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if(onEditNotes) {
        onEditNotes(appointment);
    }
  }

  const handleCardClick = () => {
      if (onViewDetails) {
          onViewDetails(appointment);
      }
  }

  const getActionButtons = (e: React.MouseEvent) => {
    e.stopPropagation();
    const baseButtonClasses = "flex-1 px-4 py-2 rounded-lg text-sm font-semibold transition-colors";
    const primaryButton = `${baseButtonClasses} bg-boticare-primary text-white hover:bg-opacity-90 dark:bg-blue-600 dark:hover:bg-blue-700`;
    const secondaryButton = `${baseButtonClasses} bg-white border border-boticare-gray-medium hover:bg-boticare-gray dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200 dark:hover:bg-gray-600`;

    switch (appointment.status) {
      case AppointmentStatus.Upcoming:
        return (
          <div className="flex items-center space-x-2">
            <button onClick={handleJoinVideoClick} className={primaryButton}>Join Video</button>
            <button onClick={handleRescheduleClick} className={secondaryButton}>Reschedule</button>
            <button onClick={handleCancelClick} className="text-red-500 hover:text-red-700 dark:text-red-400 dark:hover:text-red-300 text-sm font-semibold px-2">Cancel</button>
          </div>
        );
      case AppointmentStatus.Completed:
        return (
          <div className="flex items-center space-x-2">
            <button onClick={handleViewSummaryClick} className={primaryButton}>View Summary</button>
            <button onClick={handleRescheduleClick} className={secondaryButton}>Book Follow-up</button>
          </div>
        );
      case AppointmentStatus.Canceled:
        return <button onClick={handleRescheduleClick} className={`w-full ${primaryButton}`}>Reschedule</button>;
      case AppointmentStatus.Rescheduled:
        return <button onClick={handleRescheduleClick} className={`w-full ${primaryButton}`}>View New Time</button>;
      default:
        return null;
    }
  };

  return (
    <div 
        onClick={handleCardClick}
        className="bg-white p-5 rounded-xl border border-boticare-gray-medium flex flex-col space-y-4 hover:shadow-md transition-all cursor-pointer dark:bg-gray-800 dark:border-gray-700 group"
    >
      <div className="flex items-start justify-between">
        <div className="flex items-center space-x-3">
          <img src={appointment.avatar} alt={appointment.doctorName} className="w-12 h-12 rounded-full" />
          <div>
            <p className="font-bold">{appointment.doctorName}</p>
            <p className="text-sm text-boticare-gray-dark dark:text-gray-400">{appointment.specialty} • <span className="font-medium">{appointment.type}</span></p>
          </div>
        </div>
        <div className="flex items-center space-x-2">
            <span className={`text-xs font-semibold px-2.5 py-1 rounded-full ${statusStyles[appointment.status]}`}>
            {appointment.status}
            </span>
             <MoreIcon className="w-5 h-5 text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity" />
        </div>
      </div>

      <div className="text-sm text-boticare-gray-dark dark:text-gray-400 flex items-center justify-between border-t border-b border-boticare-gray-medium dark:border-gray-600 py-3">
        <div className="flex items-center space-x-2">
          <CalendarIcon className="w-4 h-4" />
          <span>{appointment.date}</span>
        </div>
        <div className="flex items-center space-x-2">
          <ClockIcon className="w-4 h-4" />
          <span>{`${appointment.time} (${appointment.duration} mins)`}</span>
        </div>
      </div>

      <div className="bg-boticare-gray p-3 rounded-lg text-sm space-y-2 dark:bg-gray-700">
        <div className="flex items-center space-x-2 font-medium text-gray-800 dark:text-gray-200">
            <VideoIcon className="w-4 h-4" />
            <span>Video Consultation</span>
        </div>
        <div className="flex items-start justify-between text-boticare-gray-dark dark:text-gray-400">
            <div className="flex items-start space-x-2">
                <NotesIcon className="w-4 h-4 mt-0.5 flex-shrink-0" />
                <span className="pr-2 line-clamp-1">Notes: {appointment.notes}</span>
            </div>
            <button onClick={handleEditNotesClick} className="flex-shrink-0 text-boticare-gray-dark hover:text-boticare-primary p-1 -mr-1 -mt-1 dark:text-gray-400 dark:hover:text-white" aria-label="Edit notes">
                <EditIcon className="w-4 h-4" />
            </button>
        </div>
      </div>

      <div onClick={(e) => e.stopPropagation()}>{getActionButtons(e as any)}</div>
    </div>
  );
};

export default AppointmentCard;

import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA } from '../constants';
import AppointmentCard from './AppointmentCard';
import BookAppointmentForm from './ScheduleAppointmentForm';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import CancelAppointmentModal from './CancelAppointmentModal';
import { Appointment, AppointmentStatus, Page, Professional, NewAppointmentDetails, AppointmentType } from '../types';
import { PlusIcon, SearchIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const TABS: AppointmentStatus[] = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  setVideoCallProfessional: (professional: Professional | null) => void;
  defaultToScheduling?: boolean;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false }) => {
  const [activeTab, setActiveTab] = useState<AppointmentStatus>(AppointmentStatus.Upcoming);
  const [isScheduling, setIsScheduling] = useState(defaultToScheduling);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [appointmentToReschedule, setAppointmentToReschedule] = useState<Appointment | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [cancelingAppointment, setCancelingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => appointment.status === activeTab)
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        return (
            appointment.doctorName.toLowerCase().includes(lowerCaseQuery) ||
            appointment.specialty.toLowerCase().includes(lowerCaseQuery)
        );
    });

  const handleBookSuccess = (details: NewAppointmentDetails) => {
    const newAppointment: Appointment = {
        id: Math.max(...appointments.map(a => a.id), 0) + 1,
        doctorName: details.professional.name,
        specialty: details.professional.specialty,
        status: AppointmentStatus.Upcoming,
        type: AppointmentType.Consultation,
        date: details.date,
        time: details.time,
        duration: 30,
        notes: details.notes || `Consultation for ${details.professional.specialty}`,
        avatar: details.professional.avatar,
        patientName: 'Jane Doe', // Defaulting for now
        documents: []
    };

    setAppointments(prev => [newAppointment, ...prev]);
    setIsScheduling(false);
    setActiveTab(AppointmentStatus.Upcoming);
    setToastMessage('Appointment scheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRescheduleConfirm = (appointmentId: number, details: NewAppointmentDetails) => {
    setAppointments(prev => 
      prev.map(app => 
        app.id === appointmentId 
          ? { 
              ...app, 
              status: AppointmentStatus.Rescheduled, 
              date: details.date, 
              time: details.time,
              notes: details.notes,
            }
          : app
      )
    );
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    setActiveTab(AppointmentStatus.Rescheduled);
    setToastMessage('Appointment rescheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleStartReschedule = (appointment: Appointment) => {
    setAppointmentToReschedule(appointment);
    setIsScheduling(true);
  };

  const handleCancelAppointment = (appointmentId: number) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId
          ? { ...app, status: AppointmentStatus.Canceled }
          : app
      )
    );
    setActiveTab(AppointmentStatus.Canceled);
    setToastMessage('Appointment canceled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRequestCancel = (appointment: Appointment) => {
    setCancelingAppointment(appointment);
  };

  const handleCancelScheduling = () => {
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    if (defaultToScheduling) {
        setActivePage(Page.HealthMetrics);
    }
  }

  const handleJoinVideo = (appointment: Appointment) => {
    const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
    setVideoCallProfessional(professional);
    setActivePage(Page.VideoCall);
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    if (appointment.summary) {
      setSummaryModalState({ appointment, summary: appointment.summary, isLoading: false });
      return;
    }
    const summaryText = await getAppointmentSummary(appointment);
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointment.id ? { ...app, summary: summaryText } : app
      )
    );
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  const handleCloseSummaryModal = () => {
    setSummaryModalState({ appointment: null, summary: '', isLoading: false });
  };

  const handleOpenEditNotes = (appointment: Appointment) => {
    setEditingAppointment(appointment);
  };

  const handleViewDetails = (appointment: Appointment) => {
      setDetailsAppointment(appointment);
  };

  const handleCloseEditNotes = () => {
    setEditingAppointment(null);
  };

  const handleSaveNotes = (appointmentId: number, newNotes: string) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId ? { ...app, notes: newNotes } : app
      )
    );
    setEditingAppointment(null);
    setToastMessage('Appointment notes updated successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  if (isScheduling) {
    return (
      <BookAppointmentForm 
        appointmentToReschedule={appointmentToReschedule}
        onBook={handleBookSuccess}
        onReschedule={handleRescheduleConfirm}
        onCancel={handleCancelScheduling} 
      />
    );
  }

  return (
    <div className="space-y-6">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <AppointmentSummaryModal {...summaryModalState} onClose={handleCloseSummaryModal} />
      <EditNotesModal appointment={editingAppointment} onClose={handleCloseEditNotes} onSave={handleSaveNotes} />
      <AppointmentDetailsModal appointment={detailsAppointment} onClose={() => setDetailsAppointment(null)} />
      <CancelAppointmentModal 
        appointment={cancelingAppointment}
        onClose={() => setCancelingAppointment(null)}
        onConfirm={() => {
            if (cancelingAppointment) {
                handleCancelAppointment(cancelingAppointment.id);
                setCancelingAppointment(null);
            }
        }}
      />

      <div className="flex justify-between items-center">
        <div>
            <h2 className="text-2xl font-bold">Appointments</h2>
            <p className="text-boticare-gray-dark dark:text-gray-400">Manage your appointments and view your history.</p>
        </div>
        <button 
          onClick={() => setIsScheduling(true)}
          className="bg-boticare-primary text-white font-semibold px-4 py-2 rounded-lg flex items-center space-x-2 hover:bg-opacity-90 transition-colors dark:bg-blue-600 dark:hover:bg-blue-700"
        >
          <PlusIcon className="w-5 h-5" />
          <span>Schedule New Appointment</span>
        </button>
      </div>

      <div className="flex justify-between items-center border-b border-boticare-gray-medium dark:border-gray-700">
        <div className="flex items-center space-x-2 overflow-x-auto no-scrollbar">
            {TABS.map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`px-4 py-2 -mb-px text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
                  activeTab === tab
                    ? 'border-boticare-primary text-boticare-primary dark:border-blue-400 dark:text-blue-400'
                    : 'border-transparent text-boticare-gray-dark hover:text-boticare-primary dark:text-gray-400 dark:hover:text-gray-200'
                }`}
              >
                {tab}
              </button>
            ))}
        </div>
        <div className="relative hidden md:block">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <SearchIcon className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            placeholder="Search doctor or specialty..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-boticare-gray rounded-lg border-none pl-10 pr-4 py-2 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none text-sm dark:bg-gray-700 dark:text-gray-200 dark:placeholder-gray-400"
          />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {filteredAppointments.length > 0 ? (
          filteredAppointments.map((appointment) => (
            <AppointmentCard 
              key={appointment.id} 
              appointment={appointment} 
              onReschedule={handleStartReschedule}
              onCancel={handleRequestCancel} 
              onJoinVideo={handleJoinVideo}
              onViewSummary={handleViewSummary}
              onEditNotes={handleOpenEditNotes}
              onViewDetails={handleViewDetails}
            />
          ))
        ) : (
          <div className="lg:col-span-2 text-center py-12">
            <p className="text-boticare-gray-dark dark:text-gray-400">No {searchQuery ? 'matching' : activeTab.toLowerCase()} appointments found.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Appointments;

import React, { useState } from 'react';
import { XIcon, StarIcon } from './Icons';

interface FeedbackModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (rating: number, comment: string) => void;
  source: 'video_call' | 'general';
}

const FeedbackModal: React.FC<FeedbackModalProps> = ({ isOpen, onClose, onSubmit, source }) => {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');
  const [hoverRating, setHoverRating] = useState(0);

  if (!isOpen) return null;

  const handleSubmit = () => {
    onSubmit(rating, comment);
    setRating(0);
    setComment('');
  };

  const title = source === 'video_call' ? 'How was your call?' : 'Rate your experience';
  const placeholder = source === 'video_call' 
    ? 'How was the audio/video quality? Any issues?' 
    : 'Tell us what you like or how we can improve...';

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 z-[60] flex items-center justify-center animate-fade-in p-4">
      <div className="bg-white rounded-xl shadow-2xl p-8 max-w-sm w-full relative transform transition-all dark:bg-gray-800" role="dialog" aria-modal="true">
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
            <XIcon className="w-6 h-6" />
        </button>

        <div className="text-center mb-6">
            <h2 className="text-2xl font-bold mb-2">{title}</h2>
            <p className="text-boticare-gray-dark dark:text-gray-400">Your feedback helps us improve.</p>
        </div>

        <div className="flex justify-center space-x-2 mb-6">
            {[1, 2, 3, 4, 5].map((star) => (
                <button
                    key={star}
                    onClick={() => setRating(star)}
                    onMouseEnter={() => setHoverRating(star)}
                    onMouseLeave={() => setHoverRating(0)}
                    className="focus:outline-none transition-transform hover:scale-110"
                >
                    <StarIcon className={`w-10 h-10 ${star <= (hoverRating || rating) ? 'text-yellow-400' : 'text-gray-300 dark:text-gray-600'}`} />
                </button>
            ))}
        </div>

        <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder={placeholder}
            className="w-full bg-boticare-gray rounded-lg border-none p-4 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none resize-none mb-6 dark:bg-gray-700 dark:text-gray-200 dark:placeholder-gray-400"
            rows={4}
        />

        <div className="flex flex-col space-y-3">
             <button
                onClick={handleSubmit}
                disabled={rating === 0}
                className="w-full bg-boticare-primary text-white font-semibold py-3 rounded-lg hover:bg-opacity-90 transition-colors disabled:bg-gray-300 disabled:cursor-not-allowed dark:bg-blue-600 dark:hover:bg-blue-700 dark:disabled:bg-gray-600"
            >
                Submit Feedback
            </button>
            <button
                onClick={onClose}
                className="w-full text-gray-500 font-medium hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300"
            >
                Skip
            </button>
        </div>
      </div>
    </div>
  );
};

export default FeedbackModal;

import React, { useState, useEffect, useRef } from 'react';
import { Professional } from '../types';
import { BackIcon, MicIcon, MicOffIcon, VideoOnIcon, VideoOffIcon, EndCallIcon, UserIcon, AlertIcon } from './Icons';
import FeedbackModal from './FeedbackModal';

interface VideoCallProps {
  professional: Professional | null;
  onEndCall: () => void;
}

const VideoCall: React.FC<VideoCallProps> = ({ professional, onEndCall }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isCameraOn, setIsCameraOn] = useState(true);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [mediaError, setMediaError] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);
  const userVideoRef = useRef<HTMLVideoElement>(null);
  const userStreamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    const startStream = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' }, audio: true });
        userStreamRef.current = stream;
        if (userVideoRef.current) {
          userVideoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing media devices.", err);
        if (err instanceof Error) {
            if (err.name === "NotAllowedError" || err.name === "PermissionDeniedError") {
                setMediaError("Camera and microphone access denied. Please grant permissions in your browser settings to join the call.");
            } else if (err.name === "NotFoundError" || err.name === "DevicesNotFoundError") {
                setMediaError("No camera or microphone found. Please connect a device and try again.");
            } else {
                setMediaError("Could not access camera and microphone. Please check your hardware and permissions.");
            }
        } else {
            setMediaError("An unknown error occurred while accessing media devices.");
        }
      }
    };
    startStream();

    return () => {
      stopTracks();
    };
  }, []);

  useEffect(() => {
    const timerId = setInterval(() => {
      setElapsedTime(prevTime => prevTime + 1);
    }, 1000);

    return () => {
      clearInterval(timerId);
    };
  }, []);

  const stopTracks = () => {
      if (userStreamRef.current) {
          userStreamRef.current.getTracks().forEach(track => track.stop());
      }
  };

  const toggleMic = () => {
    if (userStreamRef.current) {
        userStreamRef.current.getAudioTracks().forEach(track => {
            track.enabled = !track.enabled;
        });
        setIsMuted(prev => !prev);
    }
  };

  const toggleCamera = () => {
    if (userStreamRef.current) {
        userStreamRef.current.getVideoTracks().forEach(track => {
            track.enabled = !track.enabled;
        });
        setIsCameraOn(prev => !prev);
    }
  };

  const handleEndCallClick = () => {
      stopTracks();
      setShowFeedback(true);
  };

  const handleFeedbackSubmit = (rating: number, comment: string) => {
      // Store feedback locally
      const feedback = {
          id: Date.now().toString(),
          rating,
          comment,
          date: new Date().toISOString(),
          source: 'video_call'
      };
      const existing = JSON.parse(localStorage.getItem('boticare-feedback') || '[]');
      localStorage.setItem('boticare-feedback', JSON.stringify([...existing, feedback]));

      setShowFeedback(false);
      onEndCall();
  };

  const handleFeedbackClose = () => {
      setShowFeedback(false);
      onEndCall();
  }

  const formatTime = (totalSeconds: number) => {
    const minutes = Math.floor(totalSeconds / 60).toString().padStart(2, '0');
    const seconds = (totalSeconds % 60).toString().padStart(2, '0');
    return `${minutes}:${seconds}`;
  };

  if (!professional) {
    return (
      <div className="flex flex-col items-center justify-center h-full">
        <p className="text-lg text-boticare-gray-dark dark:text-gray-400">Error: No professional selected for the call.</p>
        <button
          onClick={onEndCall}
          className="mt-4 bg-boticare-primary text-white font-semibold px-6 py-2 rounded-lg flex items-center space-x-2 hover:bg-opacity-90 transition-colors dark:bg-blue-600 dark:hover:bg-blue-700"
        >
          <BackIcon className="w-5 h-5" />
          <span>Go Back to Appointments</span>
        </button>
      </div>
    );
  }

  return (
    <div className="animate-fade-in space-y-4">
        {showFeedback && (
            <FeedbackModal 
                isOpen={true} 
                onClose={handleFeedbackClose} 
                onSubmit={handleFeedbackSubmit} 
                source="video_call"
            />
        )}
