import React from 'react';
import { Appointment, AppointmentStatus } from '../types';
import { CalendarIcon, ClockIcon, VideoIcon, NotesIcon, EditIcon, MoreIcon } from './Icons';

interface AppointmentCardProps {
  appointment: Appointment;
  onReschedule?: (appointment: Appointment) => void;
  onCancel?: (appointment: Appointment) => void;
  onJoinVideo?: (appointment: Appointment) => void;
  onViewSummary?: (appointment: Appointment) => void;
  onEditNotes?: (appointment: Appointment) => void;
  onViewDetails?: (appointment: Appointment) => void;
}

const statusStyles = {
  [AppointmentStatus.Upcoming]: 'bg-boticare-blue text-boticare-blue-dark dark:bg-blue-900/50 dark:text-blue-300',
  [AppointmentStatus.Completed]: 'bg-boticare-green text-boticare-green-dark dark:bg-green-900/50 dark:text-green-300',
  [AppointmentStatus.Canceled]: 'bg-boticare-red text-boticare-red-dark dark:bg-red-900/50 dark:text-red-300',
  [AppointmentStatus.Rescheduled]: 'bg-boticare-yellow text-boticare-yellow-dark dark:bg-yellow-900/50 dark:text-yellow-300',
};

const AppointmentCard: React.FC<AppointmentCardProps> = ({ appointment, onReschedule, onCancel, onJoinVideo, onViewSummary, onEditNotes, onViewDetails }) => {
  const handleRescheduleClick = () => {
    if (onReschedule) {
      onReschedule(appointment);
    }
  };

  const handleCancelClick = () => {
    if (onCancel) {
      onCancel(appointment);
    }
  };

  const handleJoinVideoClick = () => {
      if (onJoinVideo) {
          onJoinVideo(appointment);
      }
  };

  const handleViewSummaryClick = () => {
    if (onViewSummary) {
      onViewSummary(appointment);
    }
  };

  const handleEditNotesClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if(onEditNotes) {
        onEditNotes(appointment);
    }
  }

  const handleCardClick = () => {
      if (onViewDetails) {
          onViewDetails(appointment);
      }
  }

  const getActionButtons = () => {
    const baseButtonClasses = "flex-1 px-4 py-2 rounded-lg text-sm font-semibold transition-colors";
    const primaryButton = `${baseButtonClasses} bg-boticare-primary text-white hover:bg-opacity-90 dark:bg-blue-600 dark:hover:bg-blue-700`;
    const secondaryButton = `${baseButtonClasses} bg-white border border-boticare-gray-medium hover:bg-boticare-gray dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200 dark:hover:bg-gray-600`;

    switch (appointment.status) {
      case AppointmentStatus.Upcoming:
        return (
          <div className="flex items-center space-x-2">
            <button onClick={handleJoinVideoClick} className={primaryButton}>Join Video</button>
            <button onClick={handleRescheduleClick} className={secondaryButton}>Reschedule</button>
            <button onClick={handleCancelClick} className="text-red-500 hover:text-red-700 dark:text-red-400 dark:hover:text-red-300 text-sm font-semibold px-2">Cancel</button>
          </div>
        );
      case AppointmentStatus.Completed:
        return (
          <div className="flex items-center space-x-2">
            <button onClick={handleViewSummaryClick} className={primaryButton}>View Summary</button>
            <button onClick={handleRescheduleClick} className={secondaryButton}>Book Follow-up</button>
          </div>
        );
      case AppointmentStatus.Canceled:
        return <button onClick={handleRescheduleClick} className={`w-full ${primaryButton}`}>Reschedule</button>;
      case AppointmentStatus.Rescheduled:
        return <button onClick={handleRescheduleClick} className={`w-full ${primaryButton}`}>View New Time</button>;
      default:
        return null;
    }
  };

  return (
    <div 
        onClick={handleCardClick}
        className="bg-white p-5 rounded-xl border border-boticare-gray-medium flex flex-col space-y-4 hover:shadow-md transition-all cursor-pointer dark:bg-gray-800 dark:border-gray-700 group"
    >
      <div className="flex items-start justify-between">
        <div className="flex items-center space-x-3">
          <img src={appointment.avatar} alt={appointment.doctorName} className="w-12 h-12 rounded-full" />
          <div>
            <p className="font-bold">{appointment.doctorName}</p>
            <p className="text-sm text-boticare-gray-dark dark:text-gray-400">{appointment.specialty} • <span className="font-medium">{appointment.type}</span></p>
          </div>
        </div>
        <div className="flex items-center space-x-2">
            <span className={`text-xs font-semibold px-2.5 py-1 rounded-full ${statusStyles[appointment.status]}`}>
            {appointment.status}
            </span>
             <MoreIcon className="w-5 h-5 text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity" />
        </div>
      </div>

      <div className="text-sm text-boticare-gray-dark dark:text-gray-400 flex items-center justify-between border-t border-b border-boticare-gray-medium dark:border-gray-600 py-3">
        <div className="flex items-center space-x-2">
          <CalendarIcon className="w-4 h-4" />
          <span>{appointment.date}</span>
        </div>
        <div className="flex items-center space-x-2">
          <ClockIcon className="w-4 h-4" />
          <span>{`${appointment.time} (${appointment.duration} mins)`}</span>
        </div>
      </div>

      <div className="bg-boticare-gray p-3 rounded-lg text-sm space-y-2 dark:bg-gray-700">
        <div className="flex items-center space-x-2 font-medium text-gray-800 dark:text-gray-200">
            <VideoIcon className="w-4 h-4" />
            <span>Video Consultation</span>
        </div>
        <div className="flex items-start justify-between text-boticare-gray-dark dark:text-gray-400">
            <div className="flex items-start space-x-2">
                <NotesIcon className="w-4 h-4 mt-0.5 flex-shrink-0" />
                <span className="pr-2 line-clamp-1">Notes: {appointment.notes}</span>
            </div>
            <button onClick={handleEditNotesClick} className="flex-shrink-0 text-boticare-gray-dark hover:text-boticare-primary p-1 -mr-1 -mt-1 dark:text-gray-400 dark:hover:text-white" aria-label="Edit notes">
                <EditIcon className="w-4 h-4" />
            </button>
        </div>
      </div>

      <div onClick={(e) => e.stopPropagation()}>{getActionButtons()}</div>
    </div>
  );
};

export default AppointmentCard;

import React, { useState, useEffect, useRef } from 'react';
import { SearchIcon, AppointmentsIcon, MedicationsIcon, UserIcon, HeartIcon } from './Icons';
import { APPOINTMENTS_DATA, MEDICATIONS_DATA, PROFESSIONALS_DATA, HEALTH_METRICS_DATA } from '../constants';
import { UserProfile, Page } from '../types';

interface SearchSuggestion {
    type: 'Appointment' | 'Medication' | 'Professional' | 'Metric';
    label: string;
    id: string | number;
    icon: React.ComponentType<{ className?: string }>;
}

interface HeaderProps {
    userProfile: UserProfile;
    onNavigate: (page: Page) => void;
}

const Header: React.FC<HeaderProps> = ({ userProfile, onNavigate }) => {
    const [query, setQuery] = useState('');
    const [suggestions, setSuggestions] = useState<SearchSuggestion[]>([]);
    const [isSuggestionsVisible, setIsSuggestionsVisible] = useState(false);
    const searchContainerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (query.length < 2) {
            setSuggestions([]);
            return;
        }

        const handler = setTimeout(() => {
            const lowerCaseQuery = query.toLowerCase();

            const appointmentResults = APPOINTMENTS_DATA.filter(
                item => item.doctorName.toLowerCase().includes(lowerCaseQuery) || item.specialty.toLowerCase().includes(lowerCaseQuery)
            ).map(item => ({
                type: 'Appointment' as const,
                label: `${item.doctorName} (${item.specialty})`,
                id: item.id,
                icon: AppointmentsIcon
            }));

            const medicationResults = MEDICATIONS_DATA.filter(
                item => item.name.toLowerCase().includes(lowerCaseQuery)
            ).map(item => ({
                type: 'Medication' as const,
                label: `${item.name}`,
                id: item.id,
                icon: MedicationsIcon
            }));

            const professionalResults = PROFESSIONALS_DATA.filter(
                item => item.name.toLowerCase().includes(lowerCaseQuery) || item.specialty.toLowerCase().includes(lowerCaseQuery)
            ).map(item => ({
                type: 'Professional' as const,
                label: `${item.name} (${item.specialty})`,
                id: item.id,
                icon: UserIcon
            }));

            const metricResults = HEALTH_METRICS_DATA.filter(
                item => item.name.toLowerCase().includes(lowerCaseQuery)
            ).map(item => ({
                type: 'Metric' as const,
                label: `${item.name}`,
                id: item.id,
                icon: HeartIcon
            }));

            setSuggestions([...appointmentResults, ...metricResults, ...medicationResults, ...professionalResults]);
        }, 300);

        return () => {
            clearTimeout(handler);
        };
    }, [query]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
                setIsSuggestionsVisible(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setQuery(e.target.value);
        setIsSuggestionsVisible(true);
    };

    const handleSuggestionClick = (suggestion: SearchSuggestion) => {
        let targetPage = Page.Dashboard;
        switch(suggestion.type) {
            case 'Appointment': targetPage = Page.Appointments; break;
            case 'Medication': targetPage = Page.Medications; break;
            case 'Metric': targetPage = Page.HealthMetrics; break;
            case 'Professional': targetPage = Page.ScheduleAppointment; break;
            default: targetPage = Page.Dashboard;
        }
        onNavigate(targetPage);
        setIsSuggestionsVisible(false);
        setQuery('');
    };

    const groupedSuggestions = suggestions.reduce((acc, suggestion) => {
        if (!acc[suggestion.type]) {
            acc[suggestion.type] = [];
        }
        acc[suggestion.type].push(suggestion);
        return acc;
    }, {} as Record<string, SearchSuggestion[]>);

  return (
    <header className="bg-white border-b border-boticare-gray-medium p-4 flex items-center justify-between sticky top-0 z-20 dark:bg-gray-800 dark:border-gray-700">
      <div className="flex items-center space-x-4">
        <h1 className="text-xl font-bold text-boticare-primary dark:text-white">Boticare</h1>
        <span className="text-xs font-medium bg-gray-100 text-gray-600 px-2 py-1 rounded-md dark:bg-gray-700 dark:text-gray-300">HIPAA Compliant</span>
      </div>
      <div className="flex-1 max-w-lg">
        <div className="relative" ref={searchContainerRef}>
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <SearchIcon className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            placeholder="Search metrics, doctors, appointments..."
            value={query}
            onChange={handleInputChange}
            onFocus={() => setIsSuggestionsVisible(true)}
            className="w-full bg-boticare-gray rounded-lg border-none pl-10 pr-4 py-2 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none dark:bg-gray-700 dark:text-gray-200 dark:placeholder-gray-400"
          />
          {isSuggestionsVisible && suggestions.length > 0 && (
            <div className="absolute top-full mt-2 w-full bg-white rounded-lg shadow-lg border border-boticare-gray-medium z-30 animate-fade-in dark:bg-gray-800 dark:border-gray-700 overflow-hidden max-h-96 overflow-y-auto">
                {Object.entries(groupedSuggestions).map(([type, items]) => (
                    <div key={type} className="border-b border-gray-100 last:border-0 dark:border-gray-700">
                        <div className="px-4 py-2 bg-gray-50 text-xs font-semibold text-gray-500 uppercase tracking-wider dark:bg-gray-700/50 dark:text-gray-400">
                            {type}s
                        </div>
                        <ul className="py-1">
                            {items.slice(0, 3).map((suggestion) => (
                            <li key={`${suggestion.type}-${suggestion.id}`}>
                                <button 
                                    onClick={() => handleSuggestionClick(suggestion)}
                                    className="w-full flex items-center space-x-3 px-4 py-2 text-sm text-gray-700 hover:bg-boticare-gray transition-colors text-left dark:text-gray-300 dark:hover:bg-gray-700"
                                >
                                <div className="p-1.5 bg-gray-100 rounded-full dark:bg-gray-600">
                                    <suggestion.icon className="w-4 h-4 text-boticare-gray-dark dark:text-gray-300 flex-shrink-0" />
                                </div>
                                <span className="truncate">{suggestion.label}</span>
                                </button>
                            </li>
                            ))}
                        </ul>
                    </div>
                ))}
            </div>
          )}
        </div>
      </div>
      <div className="flex items-center space-x-3">
        <img
          src={userProfile.avatar}
          alt={userProfile.name}
          className="w-10 h-10 rounded-full object-cover"
        />
        <div>
          <p className="font-semibold text-sm">{userProfile.name}</p>
          <p className="text-xs text-boticare-gray-dark dark:text-gray-400">Patient</p>
        </div>
      </div>
    </header>
  );
};

export default Header;

