export default Layout;

import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA } from '../constants';
import AppointmentCard from './AppointmentCard';
import BookAppointmentForm from './ScheduleAppointmentForm';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import CancelAppointmentModal from './CancelAppointmentModal';
import { Appointment, AppointmentStatus, Page, Professional, NewAppointmentDetails, AppointmentType } from '../types';
import { PlusIcon, SearchIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const TABS: AppointmentStatus[] = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  setVideoCallProfessional: (professional: Professional | null) => void;
  defaultToScheduling?: boolean;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false }) => {
  const [activeTab, setActiveTab] = useState<AppointmentStatus>(AppointmentStatus.Upcoming);
  const [isScheduling, setIsScheduling] = useState(defaultToScheduling);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [appointmentToReschedule, setAppointmentToReschedule] = useState<Appointment | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [cancelingAppointment, setCancelingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => appointment.status === activeTab)
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        return (
            appointment.doctorName.toLowerCase().includes(lowerCaseQuery) ||
            appointment.specialty.toLowerCase().includes(lowerCaseQuery)
        );
    });

  const handleBookSuccess = (details: NewAppointmentDetails) => {
    const newAppointment: Appointment = {
        id: Math.max(...appointments.map(a => a.id), 0) + 1,
        doctorName: details.professional.name,
        specialty: details.professional.specialty,
        status: AppointmentStatus.Upcoming,
        type: AppointmentType.Consultation,
        date: details.date,
        time: details.time,
        duration: 30,
        notes: details.notes || `Consultation for ${details.professional.specialty}`,
        avatar: details.professional.avatar,
        patientName: 'Jane Doe', // Defaulting for now
        documents: []
    };

    setAppointments(prev => [newAppointment, ...prev]);
    setIsScheduling(false);
    setActiveTab(AppointmentStatus.Upcoming);
    setToastMessage('Appointment scheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRescheduleConfirm = (appointmentId: number, details: NewAppointmentDetails) => {
    setAppointments(prev => 
      prev.map(app => 
        app.id === appointmentId 
          ? { 
              ...app, 
              status: AppointmentStatus.Rescheduled, 
              date: details.date, 
              time: details.time,
              notes: details.notes,
            }
          : app
      )
    );
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    setActiveTab(AppointmentStatus.Rescheduled);
    setToastMessage('Appointment rescheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleStartReschedule = (appointment: Appointment) => {
    setAppointmentToReschedule(appointment);
    setIsScheduling(true);
  };

  const handleCancelAppointment = (appointmentId: number) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId
          ? { ...app, status: AppointmentStatus.Canceled }
          : app
      )
    );
    setActiveTab(AppointmentStatus.Canceled);
    setToastMessage('Appointment canceled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRequestCancel = (appointment: Appointment) => {
    setCancelingAppointment(appointment);
  };

  const handleCancelScheduling = () => {
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    if (defaultToScheduling) {
        setActivePage(Page.HealthMetrics);
    }
  }

  const handleJoinVideo = (appointment: Appointment) => {
    const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
    setVideoCallProfessional(professional);
    setActivePage(Page.VideoCall);
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    if (appointment.summary) {
      setSummaryModalState({ appointment, summary: appointment.summary, isLoading: false });
      return;
    }
    const summaryText = await getAppointmentSummary(appointment);
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointment.id ? { ...app, summary: summaryText } : app
      )
    );
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  const handleCloseSummaryModal = () => {
    setSummaryModalState({ appointment: null, summary: '', isLoading: false });
  };

  const handleOpenEditNotes = (appointment: Appointment) => {
    setEditingAppointment(appointment);
  };

  const handleViewDetails = (appointment: Appointment) => {
      setDetailsAppointment(appointment);
  };

  const handleCloseEditNotes = () => {
    setEditingAppointment(null);
  };

  const handleSaveNotes = (appointmentId: number, newNotes: string) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId ? { ...app, notes: newNotes } : app
      )
    );
    setEditingAppointment(null);
    setToastMessage('Appointment notes updated successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  if (isScheduling) {
    return (
      <BookAppointmentForm 
        appointmentToReschedule={appointmentToReschedule}
        onBook={handleBookSuccess}
        onReschedule={handleRescheduleConfirm}
        onCancel={handleCancelScheduling} 
      />
    );
  }

  return (
    <div className="space-y-6">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <AppointmentSummaryModal {...summaryModalState} onClose={handleCloseSummaryModal} />
      <EditNotesModal appointment={editingAppointment} onClose={handleCloseEditNotes} onSave={handleSaveNotes} />
      <AppointmentDetailsModal appointment={detailsAppointment} onClose={() => setDetailsAppointment(null)} />
      <CancelAppointmentModal 
        appointment={cancelingAppointment}
        onClose={() => setCancelingAppointment(null)}
        onConfirm={() => {
            if (cancelingAppointment) {
                handleCancelAppointment(cancelingAppointment.id);
                setCancelingAppointment(null);
            }
        }}
      />

      <div className="flex justify-between items-center">
        <div>
            <h2 className="text-2xl font-bold">Appointments</h2>
            <p className="text-boticare-gray-dark dark:text-gray-400">Manage your appointments and view your history.</p>
        </div>
        <button 
          onClick={() => setIsScheduling(true)}
          className="bg-boticare-primary text-white font-semibold px-4 py-2 rounded-lg flex items-center space-x-2 hover:bg-opacity-90 transition-colors dark:bg-blue-600 dark:hover:bg-blue-700"
        >
          <PlusIcon className="w-5 h-5" />
          <span>Schedule New Appointment</span>
        </button>
      </div>

      <div className="flex justify-between items-center border-b border-boticare-gray-medium dark:border-gray-700">
        <div className="flex items-center space-x-2 overflow-x-auto no-scrollbar">
            {TABS.map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`px-4 py-2 -mb-px text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
                  activeTab === tab
                    ? 'border-boticare-primary text-boticare-primary dark:border-blue-400 dark:text-blue-400'
                    : 'border-transparent text-boticare-gray-dark hover:text-boticare-primary dark:text-gray-400 dark:hover:text-gray-200'
                }`}
              >
                {tab}
              </button>
            ))}
        </div>
        <div className="relative hidden md:block">
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
            <SearchIcon className="h-5 w-5 text-gray-400" />
          </div>
          <input
            type="text"
            placeholder="Search doctor or specialty..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-boticare-gray rounded-lg border-none pl-10 pr-4 py-2 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none text-sm dark:bg-gray-700 dark:text-gray-200 dark:placeholder-gray-400"
          />
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {filteredAppointments.length > 0 ? (
          filteredAppointments.map((appointment) => (
            <AppointmentCard 
              key={appointment.id} 
              appointment={appointment} 
              onReschedule={handleStartReschedule}
              onCancel={handleRequestCancel} 
              onJoinVideo={handleJoinVideo}
              onViewSummary={handleViewSummary}
              onEditNotes={handleOpenEditNotes}
              onViewDetails={handleViewDetails}
            />
          ))
        ) : (
          <div className="lg:col-span-2 text-center py-12">
            <p className="text-boticare-gray-dark dark:text-gray-400">No {searchQuery ? 'matching' : activeTab.toLowerCase()} appointments found.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Appointments;

import React from 'react';

export enum Page {
  Dashboard = 'Dashboard',
  HealthMetrics = 'Health Metrics',
  Medications = 'Medications',
  Appointments = 'Appointments',
  ChatBot = 'Chat Bot',
  Settings = 'Settings',
  HelpSupport = 'Help & Support',
  VideoCall = 'Video Call',
  ScheduleAppointment = 'Schedule Appointment',
}

export enum AppointmentStatus {
  Upcoming = 'Upcoming',
  Completed = 'Completed',
  Canceled = 'Canceled',
  Rescheduled = 'Rescheduled',
}

export enum AppointmentType {
    CheckUp = 'Check-up',
    FollowUp = 'Follow-up',
    Consultation = 'Consultation',
    Initial = 'Initial',
}

export interface Document {
    id: string;
    name: string;
    type: 'pdf' | 'jpg' | 'png';
    date: string;
}

export interface Appointment {
  id: number;
  doctorName: string;
  specialty: string;
  status: AppointmentStatus;
  type: AppointmentType;
  date: string;
  time: string;
  duration: number;
  notes: string;
  avatar: string;
  summary?: string;
  patientName?: string;
  documents?: Document[];
}

export interface Medication {
  id: number;
  name: string;
  dosage: string;
  percentageLeft: number;
  nextDose: string;
  isTaken: boolean;
  refillNeeded?: string;
}

export enum HealthMetricStatus {
  Normal = 'Normal',
  Warning = 'Warning',
}

export interface HistoricalDataPoint {
    date: string;
    value: number;
}

export interface HealthMetric {
  id: string;
  name: string;
  value: string;
  unit: string;
  status: HealthMetricStatus;
  trend: string;
  trendDirection: 'up' | 'down' | 'stable';
  history: HistoricalDataPoint[];
}

export enum AlertLevel {
  High = 'High',
  Medium = 'Medium',
  Low = 'Low',
}

export interface HealthAlert {
  id: number;
  title: string;
  description: string;
  level: AlertLevel;
  time: string;
  icon: React.ComponentType<{ className?: string }>;
}

export interface Professional {
    id: number;
    name: string;
    specialty: string;
    avatar: string;
    rating: number;
}

export interface ChatMessage {
  sender: 'user' | 'ai';
  text: string;
  imageUrl?: string;
  sources?: Array<{ title: string; uri: string }>;
  timestamp: string;
  isRead?: boolean;
}

export interface NewAppointmentDetails {
    consultationType: 'video' | 'chat';
    professional: Professional;
    date: string;
    time: string;
    notes: string;
}

export interface UserProfile {
    name: string;
    email: string;
    phone: string;
    avatar: string;
}

export interface FeedbackSubmission {
    id: string;
    rating: number;
    comment: string;
    date: string;
    source: 'video_call' | 'general';
}

export interface Symptom {
    id: string;
    name: string;
    date: string;
    description: string;
    severity: 'Mild' | 'Moderate' | 'Severe';
}

export interface VideoCallRecord {
    id: string;
    professionalName: string;
    professionalAvatar: string;
    date: string;
    time: string;
    duration: string;
}

import React, { useState } from 'react';
import { XIcon, NotesIcon } from './Icons';
import { Symptom } from '../types';

interface LogSymptomModalProps {
  onClose: () => void;
  onSave: (symptom: Omit<Symptom, 'id'>) => void;
}

const LogSymptomModal: React.FC<LogSymptomModalProps> = ({ onClose, onSave }) => {
  const [name, setName] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [severity, setSeverity] = useState<'Mild' | 'Moderate' | 'Severe'>('Mild');
  const [description, setDescription] = useState('');

  const handleSave = () => {
    if (!name || !date) return;
    onSave({ name, date, severity, description });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center animate-fade-in p-4">
      <div className="bg-white rounded-xl shadow-2xl p-8 max-w-md w-full relative transform transition-all dark:bg-gray-800" role="dialog" aria-modal="true">
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
          <XIcon className="w-6 h-6" />
        </button>

        <h2 className="text-2xl font-bold mb-6">Log New Symptom</h2>

        <div className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1 dark:text-gray-300">Symptom Name</label>
                <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="e.g., Headache, Nausea"
                    className="w-full bg-boticare-gray rounded-lg border-none px-4 py-2 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none dark:bg-gray-700 dark:text-gray-200"
                />
            </div>

            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1 dark:text-gray-300">Date Observed</label>
                <input 
                    type="date" 
                    value={date}
                    onChange={(e) => setDate(e.target.value)}
                    className="w-full bg-boticare-gray rounded-lg border-none px-4 py-2 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none dark:bg-gray-700 dark:text-gray-200"
                />
            </div>

            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1 dark:text-gray-300">Severity</label>
                <select 
                    value={severity}
                    onChange={(e) => setSeverity(e.target.value as any)}
                    className="w-full bg-boticare-gray rounded-lg border-none px-4 py-2 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none dark:bg-gray-700 dark:text-gray-200"
                >
                    <option value="Mild">Mild</option>
                    <option value="Moderate">Moderate</option>
                    <option value="Severe">Severe</option>
                </select>
            </div>

            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1 dark:text-gray-300">Description</label>
                <textarea 
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Describe how you feel..."
                    rows={3}
                    className="w-full bg-boticare-gray rounded-lg border-none p-4 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none resize-none dark:bg-gray-700 dark:text-gray-200"
                />
            </div>
        </div>

        <div className="flex justify-end items-center space-x-3 pt-6 mt-4 border-t border-boticare-gray-medium dark:border-gray-700">
          <button onClick={onClose} className="px-4 py-2 rounded-lg font-semibold text-gray-600 hover:bg-boticare-gray dark:text-gray-400 dark:hover:bg-gray-700">
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={!name}
            className="px-6 py-2 rounded-lg font-semibold text-white bg-boticare-primary hover:bg-opacity-90 disabled:bg-gray-400 dark:bg-blue-600 dark:hover:bg-blue-700 dark:disabled:bg-gray-600"
          >
            Save Symptom
          </button>
        </div>
      </div>
    </div>
  );
};

export default LogSymptomModal;

import React, { useState } from 'react';
import { HEALTH_METRICS_DATA, HEALTH_ALERTS_DATA } from '../constants';
import HealthMetricCard from './HealthMetricCard';
import AlertCard from './AlertCard';
import MetricChart from './MetricChart';
import { PlusIcon } from './Icons';
import { HealthAlert, Page, Symptom } from '../types';
import MedicationReminderModal from './MedicationReminderModal';
import LogSymptomModal from './LogSymptomModal';
import Toast from './Toast';

interface HealthMetricsProps {
  setActivePage: (page: Page) => void;
}

const HealthMetrics: React.FC<HealthMetricsProps> = ({ setActivePage }) => {
  const [reminderModalAlert, setReminderModalAlert] = useState<HealthAlert | null>(null);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [selectedMetricId, setSelectedMetricId] = useState<string>(HEALTH_METRICS_DATA[0].id);
  const [isLogSymptomOpen, setIsLogSymptomOpen] = useState(false);
  const [symptoms, setSymptoms] = useState<Symptom[]>([
      { id: '1', name: 'Mild Headache', date: '2025-06-01', severity: 'Mild', description: 'Started in the afternoon after work.' }
  ]);

  const selectedMetric = HEALTH_METRICS_DATA.find(m => m.id === selectedMetricId);

  const handleTakeAction = (alert: HealthAlert) => {
    if (alert.title === 'Missed Medication') {
        setReminderModalAlert(alert);
    } else {
        // For 'Elevated Blood Glucose' and 'Upcoming Appointment'
        setActivePage(Page.ScheduleAppointment);
    }
  };

  const handleAddSymptom = (newSymptom: Omit<Symptom, 'id'>) => {
      const symptom: Symptom = {
          ...newSymptom,
          id: Date.now().toString()
      };
      setSymptoms([symptom, ...symptoms]);
      setToastMessage('Symptom logged successfully');
  };

  return (
    <div className="space-y-8">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <MedicationReminderModal
          alert={reminderModalAlert}
          onClose={() => setReminderModalAlert(null)}
          onConfirm={(newDate, newTime) => {
              setReminderModalAlert(null);
              setToastMessage(`Reminder set for ${newDate} at ${newTime}!`);
              setTimeout(() => setToastMessage(null), 3000);
          }}
      />
      {isLogSymptomOpen && (
          <LogSymptomModal 
            onClose={() => setIsLogSymptomOpen(false)}
            onSave={handleAddSymptom}
          />
      )}

      <div className="flex justify-between items-end">
        <div>
            <h2 className="text-2xl font-bold">Health Metrics</h2>
            <p className="text-boticare-gray-dark dark:text-gray-400">Track and analyze your vital signs.</p>
        </div>
        <button 
            onClick={() => setIsLogSymptomOpen(true)}
            className="bg-boticare-primary text-white font-semibold px-4 py-2 rounded-lg flex items-center space-x-2 hover:bg-opacity-90 transition-colors dark:bg-blue-600 dark:hover:bg-blue-700"
        >
            <PlusIcon className="w-5 h-5" />
            <span>Log Symptom</span>
        </button>
      </div>

      {/* Charts Section */}
      <div className="bg-white p-6 rounded-xl border border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700 animate-fade-in">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6">
            <h3 className="text-lg font-bold">Analytics Overview</h3>
            <div className="flex space-x-2 mt-2 md:mt-0">
                <button className="px-3 py-1 text-sm rounded-full bg-boticare-primary text-white dark:bg-blue-600">7 Days</button>
                <button className="px-3 py-1 text-sm rounded-full bg-boticare-gray text-gray-600 hover:bg-gray-200 dark:bg-gray-700 dark:text-gray-300">30 Days</button>
            </div>
        </div>
        {selectedMetric && (
            <MetricChart 
                data={selectedMetric.history} 
                color="#3B82F6" 
                label={selectedMetric.name} 
            />
        )}
      </div>

      <div>
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-xl font-bold">Key Metrics</h3>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {HEALTH_METRICS_DATA.map(metric => (
            <div 
                key={metric.id} 
                onClick={() => setSelectedMetricId(metric.id)}
                className={`cursor-pointer transition-all duration-200 rounded-xl ${selectedMetricId === metric.id ? 'ring-2 ring-boticare-primary shadow-lg scale-[1.02]' : 'hover:shadow-md'}`}
            >
                <HealthMetricCard metric={metric} />
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div>
            <div className="flex justify-between items-center mb-4">
            <h3 className="text-xl font-bold">Health Alerts</h3>
            </div>
            <div className="space-y-4">
            {HEALTH_ALERTS_DATA.map(alert => (
                <AlertCard key={alert.id} alert={alert} onTakeAction={handleTakeAction} />
            ))}
            </div>
        </div>

        <div>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold">Recent Symptoms</h3>
            </div>
            <div className="bg-white rounded-xl border border-boticare-gray-medium overflow-hidden dark:bg-gray-800 dark:border-gray-700">
                {symptoms.length > 0 ? (
                    <ul className="divide-y divide-boticare-gray-medium dark:divide-gray-700">
                        {symptoms.map(symptom => (
                            <li key={symptom.id} className="p-4 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
                                <div className="flex justify-between items-start mb-1">
                                    <h4 className="font-bold text-gray-800 dark:text-gray-100">{symptom.name}</h4>
                                    <span className="text-xs text-boticare-gray-dark dark:text-gray-400">{symptom.date}</span>
                                </div>
                                <div className="flex items-center gap-2 mb-2">
                                     <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase ${
                                         symptom.severity === 'Severe' ? 'bg-red-100 text-red-700 dark:bg-red-900/50 dark:text-red-300' :
                                         symptom.severity === 'Moderate' ? 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/50 dark:text-yellow-300' :
                                         'bg-green-100 text-green-700 dark:bg-green-900/50 dark:text-green-300'
                                     }`}>
                                         {symptom.severity}
                                     </span>
                                </div>
                                <p className="text-sm text-gray-600 dark:text-gray-300">{symptom.description}</p>
                            </li>
                        ))}
                    </ul>
                ) : (
                    <div className="p-8 text-center text-boticare-gray-dark dark:text-gray-400">
                        No symptoms logged recently.
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

