                                    <div className="absolute -bottom-1 -right-1 bg-white dark:bg-gray-800 rounded-full p-1 shadow-sm">
                                        <div className="bg-blue-500 rounded-full p-1">
                                            <VideoIcon className="w-2 h-2 text-white" />
                                        </div>
                                    </div>
                                </div>
                                <div>
                                    <h4 className="font-bold text-gray-800 dark:text-white">{call.professionalName}</h4>
                                    <p className="text-xs text-boticare-gray-dark dark:text-gray-400">{call.date} • {call.time}</p>
                                </div>
                            </div>
                            <div className="flex flex-col items-end">
                                <div className="flex items-center space-x-1.5 text-sm font-medium text-gray-600 dark:text-gray-400 bg-gray-100 dark:bg-gray-700 px-3 py-1 rounded-full">
                                    <ClockIcon className="w-3.5 h-3.5" />
                                    <span>{call.duration}</span>
                                </div>
                                <button className="text-xs text-boticare-blue-dark font-semibold mt-2 hover:underline dark:text-blue-400">View Details</button>
                            </div>
                        </div>
                    ))}
                  </div>
              ) : (
                  <div className="p-12 text-center text-gray-500 dark:text-gray-400">
                      No video call history available.
                  </div>
              )}
          </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in">
            {filteredAppointments.length > 0 ? (
            filteredAppointments.map((appointment) => (
                <AppointmentCard 
                key={appointment.id} 
                appointment={appointment} 
                onReschedule={handleStartReschedule}
                onCancel={handleRequestCancel} 
                onJoinVideo={handleJoinVideo}
                onViewSummary={handleViewSummary}
                onEditNotes={handleOpenEditNotes}
                onViewDetails={handleViewDetails}
                />
            ))
            ) : (
            <div className="lg:col-span-2 text-center py-20 bg-white rounded-xl border border-dashed border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700">
                <p className="text-boticare-gray-dark dark:text-gray-400 font-medium">No appointments found matching your filters.</p>
                <button 
                    onClick={() => { setActiveType('All'); setSearchQuery(''); }}
                    className="text-boticare-blue-dark text-sm font-bold mt-2 hover:underline dark:text-blue-400"
                >
                    Clear all filters
                </button>
            </div>
            )}
        </div>
      )}
    </div>
  );
};

