import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA, VIDEO_CALL_HISTORY_DATA } from '../constants';
import AppointmentCard from './AppointmentCard';
import BookAppointmentForm from './ScheduleAppointmentForm';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import CancelAppointmentModal from './CancelAppointmentModal';
import { Appointment, AppointmentStatus, Page, Professional, NewAppointmentDetails, AppointmentType } from '../types';
import { PlusIcon, SearchIcon, VideoIcon, ClockIcon, FilterIcon, CalendarIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const STATUS_TABS = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
  'Call History'
];

const TYPE_FILTERS = ['All', ...Object.values(AppointmentType)];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  setVideoCallProfessional: (professional: Professional | null) => void;
  defaultToScheduling?: boolean;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false }) => {
  const [activeTab, setActiveTab] = useState<string>(AppointmentStatus.Upcoming);
  const [activeType, setActiveType] = useState<string>('All');
  const [isScheduling, setIsScheduling] = useState(defaultToScheduling);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [appointmentToReschedule, setAppointmentToReschedule] = useState<Appointment | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [cancelingAppointment, setCancelingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => appointment.status === activeTab)
    .filter((appointment) => {
        if (activeType === 'All') return true;
        return appointment.type === activeType;
    })
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        return (
            appointment.doctorName.toLowerCase().includes(lowerCaseQuery) ||
            appointment.specialty.toLowerCase().includes(lowerCaseQuery)
        );
    });

  const handleBookSuccess = (details: NewAppointmentDetails) => {
    const newAppointment: Appointment = {
        id: Math.max(...appointments.map(a => a.id), 0) + 1,
        doctorName: details.professional.name,
        specialty: details.professional.specialty,
        status: AppointmentStatus.Upcoming,
        type: AppointmentType.Consultation,
        date: details.date,
        time: details.time,
        duration: 30,
        notes: details.notes || `Consultation for ${details.professional.specialty}`,
        avatar: details.professional.avatar,
        patientName: 'Jane Doe',
        documents: []
    };

    setAppointments(prev => [newAppointment, ...prev]);
    setIsScheduling(false);
    setActiveTab(AppointmentStatus.Upcoming);
    setToastMessage('Appointment scheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRescheduleConfirm = (appointmentId: number, details: NewAppointmentDetails) => {
    setAppointments(prev => 
      prev.map(app => 
        app.id === appointmentId 
          ? { 
              ...app, 
              status: AppointmentStatus.Rescheduled, 
              date: details.date, 
              time: details.time,
              notes: details.notes,
            }
          : app
      )
    );
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    setActiveTab(AppointmentStatus.Rescheduled);
    setToastMessage('Appointment rescheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleStartReschedule = (appointment: Appointment) => {
    setAppointmentToReschedule(appointment);
    setIsScheduling(true);
  };

  const handleCancelAppointment = (appointmentId: number) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId
          ? { ...app, status: AppointmentStatus.Canceled }
          : app
      )
    );
    setActiveTab(AppointmentStatus.Canceled);
    setToastMessage('Appointment canceled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRequestCancel = (appointment: Appointment) => {
    setCancelingAppointment(appointment);
  };

  const handleCancelScheduling = () => {
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    if (defaultToScheduling) {
        setActivePage(Page.HealthMetrics);
    }
  }

  const handleJoinVideo = (appointment: Appointment) => {
    const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
    setVideoCallProfessional(professional);
    setActivePage(Page.VideoCall);
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    if (appointment.summary) {
      setSummaryModalState({ appointment, summary: appointment.summary, isLoading: false });
      return;
    }
    const summaryText = await getAppointmentSummary(appointment);
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointment.id ? { ...app, summary: summaryText } : app
      )
    );
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  const handleCloseSummaryModal = () => {
    setSummaryModalState({ appointment: null, summary: '', isLoading: false });
  };

  const handleOpenEditNotes = (appointment: Appointment) => {
    setEditingAppointment(appointment);
  };

  const handleViewDetails = (appointment: Appointment) => {
      setDetailsAppointment(appointment);
  };

  const handleCloseEditNotes = () => {
    setEditingAppointment(null);
  };

  const handleSaveNotes = (appointmentId: number, newNotes: string) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId ? { ...app, notes: newNotes } : app
      )
    );
    setEditingAppointment(null);
    setToastMessage('Appointment notes updated successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  if (isScheduling) {
    return (
      <BookAppointmentForm 
        appointmentToReschedule={appointmentToReschedule}
        onBook={handleBookSuccess}
        onReschedule={handleRescheduleConfirm}
        onCancel={handleCancelScheduling} 
      />
    );
  }

  return (
    <div className="space-y-6">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <AppointmentSummaryModal {...summaryModalState} onClose={handleCloseSummaryModal} />
      <EditNotesModal appointment={editingAppointment} onClose={handleCloseEditNotes} onSave={handleSaveNotes} />
      <AppointmentDetailsModal appointment={detailsAppointment} onClose={() => setDetailsAppointment(null)} />
      <CancelAppointmentModal 
        appointment={cancelingAppointment}
        onClose={() => setCancelingAppointment(null)}
        onConfirm={() => {
            if (cancelingAppointment) {
                handleCancelAppointment(cancelingAppointment.id);
                setCancelingAppointment(null);
            }
        }}
      />

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h2 className="text-2xl font-bold">Appointments</h2>
            <p className="text-boticare-gray-dark dark:text-gray-400">Manage your consultations and medical records.</p>
        </div>
        <button 
          onClick={() => setIsScheduling(true)}
          className="bg-boticare-primary text-white font-semibold px-4 py-2 rounded-lg flex items-center space-x-2 hover:bg-opacity-90 transition-colors dark:bg-blue-600 dark:hover:bg-blue-700 w-full md:w-auto justify-center shadow-sm"
        >
          <PlusIcon className="w-5 h-5" />
          <span>New Appointment</span>
        </button>
      </div>

      {/* Search and Navigation Bar */}
      <div className="bg-white p-4 rounded-xl border border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700 shadow-sm space-y-4">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <nav className="flex items-center space-x-1 overflow-x-auto no-scrollbar pb-2 md:pb-0">
                {STATUS_TABS.map((tab) => (
                <button
                    key={tab}
                    onClick={() => { setActiveTab(tab); setActiveType('All'); }}
                    className={`px-4 py-2 text-sm font-semibold rounded-lg transition-all whitespace-nowrap ${
                    activeTab === tab
                        ? 'bg-boticare-primary text-white dark:bg-blue-600'
                        : 'text-boticare-gray-dark hover:bg-boticare-gray dark:text-gray-400 dark:hover:bg-gray-700'
                    }`}
                >
                    {tab}
                </button>
                ))}
            </nav>

            <div className="relative w-full md:w-72">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <SearchIcon className="h-4 w-4 text-gray-400" />
                </div>
                <input
                    type="text"
                    placeholder="Search doctor or specialty..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-boticare-gray rounded-lg border-none pl-10 pr-4 py-2 focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none text-sm dark:bg-gray-700 dark:text-gray-200 dark:placeholder-gray-400 shadow-inner"
                />
            </div>
        </div>

        {/* Secondary Filters (Type) - Hidden in Call History */}
        {activeTab !== 'Call History' && (
            <div className="flex items-center space-x-2 pt-3 border-t border-boticare-gray-medium dark:border-gray-700 overflow-x-auto no-scrollbar">
                <div className="flex items-center text-gray-400 mr-2 flex-shrink-0">
                    <FilterIcon className="w-4 h-4 mr-1.5" />
                    <span className="text-xs font-bold uppercase tracking-wider">Type:</span>
                </div>
                {TYPE_FILTERS.map((type) => (
                    <button
                        key={type}
                        onClick={() => setActiveType(type)}
                        className={`px-3 py-1 text-xs font-medium rounded-full border transition-all whitespace-nowrap ${
                            activeType === type
                                ? 'bg-boticare-blue text-boticare-blue-dark border-boticare-blue-dark dark:bg-blue-900/50 dark:text-blue-300 dark:border-blue-400'
                                : 'bg-transparent text-gray-500 border-gray-200 hover:border-gray-400 dark:text-gray-400 dark:border-gray-600'
                        }`}
                    >
                        {type}
                    </button>
                ))}
            </div>
        )}
      </div>

      {activeTab === 'Call History' ? (
          <div className="bg-white rounded-xl border border-boticare-gray-medium overflow-hidden dark:bg-gray-800 dark:border-gray-700 animate-fade-in shadow-sm">
              <div className="bg-gray-50 px-6 py-4 border-b border-boticare-gray-medium dark:bg-gray-700/50 dark:border-gray-600 flex justify-between items-center">
                  <h3 className="text-sm font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 flex items-center gap-2">
                    <VideoIcon className="w-4 h-4" /> Video Call History
                  </h3>
                  <span className="text-xs font-medium text-gray-400">{VIDEO_CALL_HISTORY_DATA.length} Total Logs</span>
              </div>
              {VIDEO_CALL_HISTORY_DATA.length > 0 ? (
                  <div className="divide-y divide-boticare-gray-medium dark:divide-gray-700">
                    {VIDEO_CALL_HISTORY_DATA.map((call) => (
                        <div key={call.id} className="p-6 flex flex-col sm:flex-row sm:items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors gap-4">
                            <div className="flex items-center space-x-4">
                                <div className="relative flex-shrink-0">
                                    <img src={call.professionalAvatar} alt={call.professionalName} className="w-14 h-14 rounded-full object-cover shadow-sm ring-2 ring-white dark:ring-gray-700" />
                                    <div className="absolute -bottom-1 -right-1 bg-white dark:bg-gray-800 rounded-full p-1 shadow-sm">
                                        <div className="bg-green-500 rounded-full p-1">
                                            <VideoIcon className="w-2.5 h-2.5 text-white" />
                                        </div>
                                    </div>
                                </div>
                                <div>
                                    <h4 className="font-bold text-gray-900 dark:text-white text-lg">{call.professionalName}</h4>
                                    <div className="flex items-center gap-3 text-sm text-boticare-gray-dark dark:text-gray-400 mt-0.5">
                                        <div className="flex items-center gap-1">
                                            <CalendarIcon className="w-3.5 h-3.5" />
                                            <span>{call.date}</span>
                                        </div>
                                        <div className="flex items-center gap-1">
                                            <ClockIcon className="w-3.5 h-3.5" />
                                            <span>{call.time}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center justify-between sm:justify-end gap-6">
                                <div className="flex items-center gap-1.5 text-sm font-bold text-boticare-blue-dark dark:text-blue-400 bg-boticare-blue dark:bg-blue-900/30 px-3 py-1.5 rounded-full">
                                    <ClockIcon className="w-4 h-4" />
                                    <span>{call.duration}</span>
                                </div>
                                <button className="text-sm text-gray-500 font-bold hover:text-boticare-primary dark:text-gray-400 dark:hover:text-white transition-colors underline decoration-dotted underline-offset-4">
                                    View Log
                                </button>
                            </div>
                        </div>
                    ))}
                  </div>
              ) : (
                  <div className="p-16 text-center text-gray-500 dark:text-gray-400">
                      <VideoIcon className="w-12 h-12 mx-auto mb-4 opacity-20" />
                      <p className="font-medium">No video call history available yet.</p>
                  </div>
              )}
          </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in pb-10">
            {filteredAppointments.length > 0 ? (
            filteredAppointments.map((appointment) => (
                <AppointmentCard 
                key={appointment.id} 
                appointment={appointment} 
                onReschedule={handleStartReschedule}
                onCancel={handleRequestCancel} 
                onJoinVideo={handleJoinVideo}
                onViewSummary={handleViewSummary}
                onEditNotes={handleOpenEditNotes}
                onViewDetails={handleViewDetails}
                />
            ))
            ) : (
            <div className="lg:col-span-2 text-center py-24 bg-white rounded-xl border-2 border-dashed border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700">
                <div className="bg-gray-50 dark:bg-gray-700 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                    <CalendarIcon className="w-8 h-8 text-gray-300 dark:text-gray-500" />
                </div>
                <p className="text-gray-500 dark:text-gray-400 font-bold text-lg">No matching appointments</p>
                <p className="text-sm text-gray-400 dark:text-gray-500 mb-6">Try adjusting your search or filters.</p>
                <button 
                    onClick={() => { setActiveType('All'); setSearchQuery(''); }}
                    className="text-boticare-blue-dark font-bold hover:bg-boticare-blue dark:text-blue-400 dark:hover:bg-blue-900/50 px-4 py-2 rounded-lg transition-colors border border-boticare-blue-dark dark:border-blue-400"
                >
                    Reset Filters
                </button>
            </div>
            )}
        </div>
      )}
    </div>
  );
};

export default Appointments;

