  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  // Mark messages as read after a delay
  useEffect(() => {
    if (messages.length > 0) {
        const lastMessage = messages[messages.length - 1];
        if (lastMessage.sender === 'user' && !lastMessage.isRead) {
            const timer = setTimeout(() => {
                setMessages(prev => prev.map((msg, idx) => 
                    idx === prev.length - 1 ? { ...msg, isRead: true } : msg
                ));
            }, 1000);
            return () => clearTimeout(timer);
        }
    }
  }, [messages.length]);

  useEffect(() => {
    if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current);
    if (input.trim().length > 3) {
      suggestionTimeoutRef.current = window.setTimeout(async () => {
        const fetchedSuggestions = await getWordSuggestions(input, messages);
        if (input.trim().length > 3) setSuggestions(fetchedSuggestions.slice(0, 4));
      }, 500);
    } else {
      setSuggestions([]);
    }
    return () => { if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current); };
  }, [input, messages]);

  const handleSend = async () => {
    if ((input.trim() === '' && !uploadedFile) || isLoading) return;

    setSuggestions([]);
    const currentFile = uploadedFile;
    const currentInput = input;
    const currentTime = getCurrentTime();

    const userMessage: ChatMessage = { 
        sender: 'user', 
        text: currentInput, 
        imageUrl: currentFile?.type === 'image' ? currentFile.url : undefined,
        timestamp: currentTime,
        isRead: false
    };
    setMessages(prev => [...prev, userMessage]);

    setInput('');
    setUploadedFile(null);
    setIsLoading(true);

    try {
        if (currentFile) {
            if (currentFile.type === 'image') {
                const imagePart = await fileToGenerativePart(currentFile.file);
                const aiMessage = await getAIResponse(currentInput, imagePart, { useSearch: useGrounding });
                setMessages(prev => [...prev, aiMessage]);
            } else { // Video analysis
                const analysisText = await analyzeVideo(currentFile.file, currentInput);
                const aiMessage: ChatMessage = { 
                    sender: 'ai', 
                    text: analysisText, 
                    timestamp: getCurrentTime() 
                };
                setMessages(prev => [...prev, aiMessage]);
            }
        } else { // Text only
             let groundingOptions = { useSearch: useGrounding, useMaps: false, latitude: undefined, longitude: undefined };
            if (useGrounding) {
                if (/\b(near me|nearby|closest|find a)\b/i.test(input)) {
                    groundingOptions.useMaps = true;
                    try {
                        const position = await new Promise<GeolocationPosition>((resolve, reject) => navigator.geolocation.getCurrentPosition(resolve, reject));
                        groundingOptions.latitude = position.coords.latitude;
                        groundingOptions.longitude = position.coords.longitude;
                    } catch (e) { console.warn("Could not get location for Maps grounding:", e); }
                }
            }
          const aiMessage = await getAIResponse(input, null, groundingOptions);
          setMessages(prev => [...prev, aiMessage]);
        }
    } catch (error) {
      const errorMessage: ChatMessage = { 
          sender: 'ai', 
          text: 'Sorry, something went wrong.', 
          timestamp: getCurrentTime() 
        };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleEditImage = async () => {
    if (!uploadedFile || uploadedFile.type !== 'image' || !input.trim() || isLoading) return;

    setSuggestions([]);
    const currentFile = uploadedFile;
    const currentInput = input;
    const userMessage: ChatMessage = { 
        sender: 'user', 
        text: currentInput, 
        imageUrl: currentFile.url,
        timestamp: getCurrentTime(),
        isRead: false
    };
    setMessages(prev => [...prev, userMessage]);

    setInput('');
    setUploadedFile(null);
    setIsLoading(true);

    try {
        const imagePart = await fileToGenerativePart(currentFile.file);
        const editedB64 = await editImage(imagePart.inlineData.data, imagePart.inlineData.mimeType, currentInput);
        if (editedB64) {
            const aiMessage: ChatMessage = { 
                sender: 'ai', 
                text: 'Here is the edited image:', 
                imageUrl: `data:image/png;base64,${editedB64}`,
                timestamp: getCurrentTime()
            };
            setMessages(prev => [...prev, aiMessage]);
        } else {
            throw new Error("Editing failed to return an image.");
        }
    } catch (error) {
        const errorMessage: ChatMessage = { 
            sender: 'ai', 
            text: 'Sorry, I was unable to edit the image.', 
            timestamp: getCurrentTime()
        };
        setMessages(prev => [...prev, errorMessage]);
    } finally {
        setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleSuggestionClick = (suggestion: string) => {
    setInput(prev => (prev.endsWith(' ') ? prev : prev + ' ') + suggestion + ' ');
    setSuggestions([]);
  };

  const handleConfirmClear = () => {
    setMessages([{ 
        sender: 'ai', 
        text: "Hello! I'm Boticare AI. How can I help you with your health questions today?", 
        timestamp: getCurrentTime()
    }]);
    setShowClearConfirm(false);
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedMessageIndex(index);
    setTimeout(() => setCopiedMessageIndex(null), 2000);
  };

  const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
        const fileType = file.type.startsWith('image/') ? 'image' : file.type.startsWith('video/') ? 'video' : null;
        if (fileType) {
            setUploadedFile({
                file,
                url: URL.createObjectURL(file),
                type: fileType,
            });
        }
    }
  };

  const handlePlayAudio = async (text: string, index: number) => {
    if (audioPlayingIndex === index) return;
    setAudioPlayingIndex(index);
    const audioData = await generateSpeech(text);
    if (audioData) {
        const audioBuffer = await decodeAudioData(decode(audioData), outputAudioContext, 24000, 1);
        const source = outputAudioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(outputAudioContext.destination);
        source.start();
        source.onended = () => setAudioPlayingIndex(null);
    } else {
        setAudioPlayingIndex(null);
    }
  };

  const stopLiveSession = useCallback(() => {
    if (sessionPromiseRef.current) {
        sessionPromiseRef.current.then(session => session.close());
        sessionPromiseRef.current = null;
    }
    if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
    }
    if (scriptProcessorRef.current) {
        scriptProcessorRef.current.disconnect();
        scriptProcessorRef.current = null;
    }
    if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
        inputAudioContextRef.current.close();
        inputAudioContextRef.current = null;
    }
    setIsLiveSessionActive(false);
    setInput('');
  }, []);

  const startLiveSession = useCallback(async () => {
    if (isLiveSessionActive) {
        stopLiveSession();
        return;
    }

    setIsLiveSessionActive(true);
    setInput("Listening... Speak now. Click the mic again to stop.");

    let currentInputTranscription = '';
    let currentOutputTranscription = '';

    sessionPromiseRef.current = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
            onopen: async () => {
                inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
                streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });
                const source = inputAudioContextRef.current.createMediaStreamSource(streamRef.current);
                scriptProcessorRef.current = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);

                scriptProcessorRef.current.onaudioprocess = (audioProcessingEvent) => {
                    const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                    const pcmBlob = createBlob(inputData);
                    sessionPromiseRef.current?.then((session) => {
                        session.sendRealtimeInput({ media: pcmBlob });
                    });
                };
                source.connect(scriptProcessorRef.current);
                scriptProcessorRef.current.connect(inputAudioContextRef.current.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
                const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (base64Audio) {
                    nextStartTime = Math.max(nextStartTime, outputAudioContext.currentTime);
                    const audioBuffer = await decodeAudioData(decode(base64Audio), outputAudioContext, 24000, 1);
                    const source = outputAudioContext.createBufferSource();
                    source.buffer = audioBuffer;
                    source.connect(outputAudioContext.destination);
                    source.start(nextStartTime);
                    nextStartTime += audioBuffer.duration;
                }

                if (message.serverContent?.inputTranscription) {
                    currentInputTranscription += message.serverContent.inputTranscription.text;
                }
                if (message.serverContent?.outputTranscription) {
                    currentOutputTranscription += message.serverContent.outputTranscription.text;
                }

                if (message.serverContent?.turnComplete) {
                    if (currentInputTranscription.trim()) {
                        setMessages(prev => [...prev, { 
                            sender: 'user', 
                            text: currentInputTranscription.trim(), 
                            timestamp: getCurrentTime(),
                            isRead: true
                        }]);
                    }
                    if (currentOutputTranscription.trim()) {
                        setMessages(prev => [...prev, { 
                            sender: 'ai', 
                            text: currentOutputTranscription.trim(), 
                            timestamp: getCurrentTime()
                        }]);
                    }
                    currentInputTranscription = '';
                    currentOutputTranscription = '';
                }
            },
            onerror: (e: ErrorEvent) => { 
                console.error('Live session error:', e);
                setMessages(prev => [...prev, { 
                    sender: 'ai', 
                    text: "I'm sorry, the voice session disconnected due to an error. Please try again.", 
                    timestamp: getCurrentTime() 
                }]);
                stopLiveSession(); 
            },
            onclose: (e: CloseEvent) => { stopLiveSession(); },
        },
        config: {
            responseModalities: [Modality.AUDIO],
            inputAudioTranscription: {},
            outputAudioTranscription: {},
        },
    });
  }, [isLiveSessionActive, stopLiveSession]);

  return (
    <div className="h-full flex flex-col max-w-4xl mx-auto px-1 md:px-0">
      {showClearConfirm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center animate-fade-in p-4">
          <div className="bg-white rounded-lg p-6 md:p-8 shadow-xl max-w-sm w-full dark:bg-gray-800">
            <h3 className="text-lg font-bold mb-2 dark:text-white">Clear Chat History</h3>
            <p className="text-sm text-boticare-gray-dark mb-6 dark:text-gray-400">This action cannot be undone.</p>
            <div className="flex justify-end space-x-3">
              <button onClick={() => setShowClearConfirm(false)} className="px-4 py-2 rounded-lg font-semibold text-gray-700 bg-boticare-gray hover:bg-boticare-gray-medium dark:bg-gray-700 dark:text-gray-200 dark:hover:bg-gray-600">Cancel</button>
              <button onClick={handleConfirmClear} className="px-4 py-2 rounded-lg font-semibold text-white bg-boticare-red-dark hover:bg-red-700">Confirm</button>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center mb-4">
        <div>
          <h2 className="text-xl md:text-2xl font-bold">Chat Bot</h2>
          <p className="hidden md:block text-boticare-gray-dark dark:text-gray-400">Ask health questions, upload images, and get grounded answers.</p>
        </div>
        <button onClick={() => setShowClearConfirm(true)} className="flex items-center space-x-2 text-xs md:text-sm font-medium text-boticare-gray-dark hover:text-boticare-red-dark transition-colors px-2 md:px-3 py-1.5 rounded-lg border border-boticare-gray-medium hover:border-boticare-red-dark/50 dark:text-gray-400 dark:border-gray-600 dark:hover:text-red-400 dark:hover:border-red-400/50">
          <TrashIcon className="w-4 h-4" /><span className="hidden sm:inline">Clear Chat</span>
        </button>
      </div>

      <div className="flex-grow bg-white rounded-xl border border-boticare-gray-medium overflow-hidden flex flex-col dark:bg-gray-800 dark:border-gray-700 shadow-sm">
        <div className="flex-grow p-4 md:p-6 overflow-y-auto space-y-4 md:space-y-6 no-scrollbar">
          {messages.map((msg, index) => (
            <div key={index} className={`flex items-end gap-2 md:gap-3 group ${msg.sender === 'user' ? 'justify-end' : ''}`}>
              {msg.sender === 'ai' && (
                <div className="w-7 h-7 md:w-8 md:h-8 rounded-full bg-gradient-to-br from-boticare-blue to-blue-200 flex items-center justify-center text-boticare-blue-dark font-bold text-xs md:text-sm flex-shrink-0 shadow-sm mb-1">B</div>
              )}

              <div className={`flex flex-col ${msg.sender === 'user' ? 'items-end' : 'items-start'} max-w-[85%] md:max-w-[80%]`}>
                  <div className={`p-3 md:p-4 rounded-2xl shadow-sm ${
                      msg.sender === 'ai' 
                        ? 'bg-gray-100 text-gray-800 rounded-bl-none dark:bg-gray-700 dark:text-gray-100' 
                        : 'bg-boticare-blue-dark text-white rounded-br-none'
                  }`}>
                    {msg.imageUrl && <img src={msg.imageUrl} alt="content" className="rounded-lg mb-3 max-h-48 md:max-h-64 w-full object-cover border border-black/10"/>}
                    <p className="whitespace-pre-wrap text-xs md:text-sm leading-relaxed">{msg.text.replace(/\*/g, '')}</p>

                    {msg.sender === 'ai' && msg.sources && (
                        <div className="mt-3 pt-2 border-t border-gray-200/50 dark:border-gray-600/50">
                            <h4 className="text-[9px] md:text-[10px] uppercase font-bold tracking-wider mb-1 opacity-70">Sources</h4>
                            <ul className="space-y-1">
                                {msg.sources.map((source, i) => (
                                    <li key={i}><a href={source.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] md:text-xs text-blue-600 hover:underline dark:text-blue-300 truncate block flex items-center gap-1">
                                        <span className="w-1 h-1 rounded-full bg-blue-500"></span>
                                        {source.title}
                                    </a></li>
                                ))}
                            </ul>
                        </div>
                    )}
                  </div>

                  <div className="flex items-center gap-1 mt-1 px-1">
                      <span className="text-[9px] md:text-[10px] text-gray-400 font-medium">{msg.timestamp}</span>
                      {msg.sender === 'user' && (
                          <span className="ml-1">
                              {msg.isRead ? (
                                  <div className="flex">
                                    <CheckCircleIcon className="w-2.5 h-2.5 md:w-3 md:h-3 text-blue-500" />
                                    <CheckCircleIcon className="w-2.5 h-2.5 md:w-3 md:h-3 text-blue-500 -ml-1.5 md:-ml-2" />
                                  </div>
                              ) : (
                                  <CheckCircleIcon className="w-2.5 h-2.5 md:w-3 md:h-3 text-gray-300" />
                              )}
                          </span>
                      )}
                  </div>

                  {msg.sender === 'ai' && index > 0 && (
                    <div className="flex items-center gap-3 mt-1 opacity-0 group-hover:opacity-100 transition-opacity px-1">
                       <button onClick={() => handlePlayAudio(msg.text, index)} className={`flex items-center gap-1 text-[9px] md:text-[10px] font-medium transition-colors ${audioPlayingIndex === index ? 'text-blue-500' : 'text-gray-400 hover:text-boticare-primary dark:text-gray-500 dark:hover:text-gray-300'}`}>
                            <SpeakerIcon className="w-2.5 h-2.5 md:w-3 md:h-3" /> {audioPlayingIndex === index ? 'Playing' : 'Listen'}
                        </button>
                       <button onClick={() => handleCopy(msg.text, index)} className="flex items-center gap-1 text-[9px] md:text-[10px] font-medium text-gray-400 hover:text-boticare-primary dark:text-gray-500 dark:hover:text-gray-300 transition-colors">
                          {copiedMessageIndex === index ? <CheckCircleIcon className="w-2.5 h-2.5 md:w-3 md:h-3 text-green-500" /> : <CopyIcon className="w-2.5 h-2.5 md:w-3 md:h-3" />}
                          {copiedMessageIndex === index ? 'Copied' : 'Copy'}
                       </button>
                       <div className="flex items-center gap-1 ml-2 border-l pl-2 border-gray-200 dark:border-gray-700">
                           <button className="text-gray-400 hover:text-green-500 transition-colors"><ThumbsUpIcon className="w-2.5 h-2.5 md:w-3 md:h-3" /></button>
                           <button className="text-gray-400 hover:text-red-500 transition-colors"><ThumbsDownIcon className="w-2.5 h-2.5 md:w-3 md:h-3" /></button>
                       </div>
                    </div>
                )}
              </div>

               {msg.sender === 'user' && (
                <img src={userProfile.avatar} alt="user" className="w-7 h-7 md:w-8 md:h-8 rounded-full object-cover shadow-sm mb-4" />
              )}
            </div>
          ))}

          {isLoading && (
             <div className="flex items-end gap-2 md:gap-3">
                <div className="w-7 h-7 md:w-8 md:h-8 rounded-full bg-gradient-to-br from-boticare-blue to-blue-200 flex items-center justify-center text-boticare-blue-dark font-bold text-xs md:text-sm flex-shrink-0 shadow-sm">B</div>
                <div className="bg-gray-100 p-3 md:p-4 rounded-2xl rounded-bl-none dark:bg-gray-700">
                    <div className="flex items-center justify-center space-x-1.5">
                        <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                        <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                        <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></div>
                    </div>
                </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <div className="p-3 md:p-4 bg-gray-50 border-t border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-3 px-1 gap-2">
            <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar pb-1 sm:pb-0">
                {suggestions.map((s, i) => (
                  <button key={i} onClick={() => handleSuggestionClick(s)} className="px-2.5 py-1 text-[10px] font-semibold bg-white border border-blue-100 text-blue-600 rounded-full hover:bg-blue-50 shadow-sm dark:bg-gray-700 dark:border-gray-600 dark:text-blue-300 dark:hover:bg-gray-600 transition-colors whitespace-nowrap">{s}</button>
                ))}
            </div>

            <div className="flex items-center gap-2 flex-shrink-0 self-end">
              <label htmlFor="grounding-toggle" className="flex items-center cursor-pointer group">
                <span className="text-[10px] font-bold text-gray-500 group-hover:text-gray-700 dark:text-gray-400 dark:group-hover:text-gray-200 mr-2 transition-colors">Web Search</span>
                <div className="relative">
                  <input type="checkbox" id="grounding-toggle" className="sr-only" checked={useGrounding} onChange={() => setUseGrounding(!useGrounding)} />
                  <div className={`block w-7 h-4 rounded-full transition-colors ${useGrounding ? 'bg-green-500' : 'bg-gray-300 dark:bg-gray-600'}`}></div>
                  <div className={`absolute left-0.5 top-0.5 bg-white w-3 h-3 rounded-full transition-transform shadow-sm ${useGrounding ? 'translate-x-3' : ''}`}></div>
                </div>
              </label>
            </div>
          </div>

          {uploadedFile && (
            <div className="mb-3 flex items-start gap-3 p-2 bg-white border border-gray-200 rounded-lg shadow-sm dark:bg-gray-700 dark:border-gray-600 animate-fade-in">
                {uploadedFile.type === 'image' ? (
                    <img src={uploadedFile.url} alt="upload preview" className="w-10 h-10 rounded-lg object-cover bg-gray-100 flex-shrink-0"/>
                ) : (
                    <video src={uploadedFile.url} className="w-16 h-10 rounded-lg bg-black object-cover flex-shrink-0" />
                )}
                <div className="flex-grow min-w-0">
                    <p className="text-[10px] font-bold text-gray-700 dark:text-gray-200 uppercase tracking-wide">
                        {uploadedFile.type === 'image' ? 'Image Attached' : 'Video Attached'}
                    </p>
                    <p className="text-[10px] text-gray-500 dark:text-gray-400 truncate">{uploadedFile.file.name}</p>
                </div>
                <button onClick={() => setUploadedFile(null)} className="p-1 text-gray-400 hover:text-red-500 transition-colors"><XIcon className="w-4 h-4"/></button>
            </div>
          )}

          <div className="relative flex items-center gap-1.5">
             <div className="flex items-center gap-0.5 md:gap-1 absolute left-1 md:left-2 top-1/2 -translate-y-1/2 z-10">
                 <input type="file" ref={fileInputRef} onChange={handleFileSelect} className="hidden" accept="image/*,video/*" />
                 <button 
                    onClick={() => fileInputRef.current?.click()} 
                    className="p-1.5 md:p-2 text-gray-400 hover:text-boticare-blue-dark hover:bg-gray-100 rounded-full transition-all dark:text-gray-500 dark:hover:text-blue-400 dark:hover:bg-gray-700" 
                    title="Upload"
                    disabled={isLiveSessionActive}
                 >
                     <UploadIcon className="w-5 h-5" />
                 </button>
                 <button 
                    onClick={startLiveSession} 
                    className={`p-1.5 md:p-2 rounded-full transition-all ${isLiveSessionActive ? 'text-white bg-red-500 animate-pulse' : 'text-gray-400 hover:text-boticare-blue-dark hover:bg-gray-100 dark:text-gray-500 dark:hover:text-blue-400 dark:hover:bg-gray-700'}`}
                    title="Voice"
                 >
                    {isLiveSessionActive ? <MicOffIcon className="w-5 h-5" /> : <MicIcon className="w-5 h-5" />}
                 </button>
             </div>

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder={isLiveSessionActive ? "Listening..." : "Message AI..."}
              className={`w-full bg-white border border-gray-300 rounded-2xl resize-none pl-16 md:pl-20 pr-20 md:pr-24 py-2.5 md:py-3 shadow-sm focus:outline-none focus:ring-2 focus:ring-boticare-blue-dark focus:border-transparent dark:bg-gray-700 dark:border-gray-600 dark:text-gray-200 dark:placeholder-gray-400 text-sm md:text-base transition-all ${isLiveSessionActive ? 'ring-2 ring-red-500 border-red-500' : ''}`}
              rows={1}
              maxLength={MAX_CHARS}
              disabled={isLoading || isLiveSessionActive}
            />

            <div className="absolute right-1.5 md:right-2 top-1/2 -translate-y-1/2 flex items-center gap-1 md:gap-1.5">
                {uploadedFile?.type === 'image' && (
                    <button onClick={handleEditImage} disabled={isLoading || isLiveSessionActive || !input.trim()} className="text-[10px] font-bold bg-green-100 text-green-700 hover:bg-green-200 rounded-full px-2 md:px-3 py-1.5 flex items-center gap-1 disabled:opacity-50 disabled:cursor-not-allowed transition-colors dark:bg-green-900/30 dark:text-green-400">
                        <EditIcon className="w-3 h-3" /> <span className="hidden sm:inline">Edit</span>
                    </button>
                )}
                 <button 
                    onClick={handleSend} 
                    disabled={isLoading || isLiveSessionActive || (input.trim() === '' && !uploadedFile)} 
                    className="bg-boticare-primary text-white p-2 rounded-xl flex items-center justify-center hover:bg-gray-800 disabled:bg-gray-300 disabled:cursor-not-allowed dark:bg-blue-600 dark:hover:bg-blue-700 dark:disabled:bg-gray-600 transition-all shadow-md"
                >
                    <SendIcon className="w-4 h-4 md:w-5 md:h-5 ml-0.5" />
                </button>
            </div>
          </div>
          <p className="text-[9px] md:text-[10px] text-center text-gray-400 mt-2 dark:text-gray-500">AI can make mistakes. Verify important medical info.</p>
        </div>
      </div>
    </div>
  );
};

export default ChatBot;

import React from 'react';

type IconProps = {
  className?: string;
};

const IconBase: React.FC<IconProps & { children: React.ReactNode }> = ({ className, children }) => (
    <svg className={className} xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        {children}
    </svg>
);

const FilledIconBase: React.FC<IconProps & { children: React.ReactNode, viewBox?: string }> = ({ className, children, viewBox = "0 0 24 24" }) => (
    <svg className={className} xmlns="http://www.w3.org/2000/svg" viewBox={viewBox} fill="currentColor">
        {children}
