const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [activePage, setActivePage] = useState<Page>(Page.Dashboard);
  const [videoCallProfessional, setVideoCallProfessional] = useState<Professional | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Loading...',
    email: '',
    phone: '',
    avatar: 'https://i.pravatar.cc/150?u=placeholder',
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('boticare-dark-mode');
    if (saved !== null) {
      return saved === 'true';
    }
    return window.matchMedia?.('(prefers-color-scheme: dark)').matches ?? false;
  });

  // Handle Dark Mode
  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) {
      root.classList.add('dark');
      localStorage.setItem('boticare-dark-mode', 'true');
    } else {
      root.classList.remove('dark');
      localStorage.setItem('boticare-dark-mode', 'false');
    }
  }, [isDarkMode]);

  // Handle Supabase Session & Profile Fetching
  useEffect(() => {
    if (!supabase) return;

    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    if (!supabase) return;

    try {
        const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

        if (error) {
            console.error('Error fetching profile:', error);
        } else if (data) {
            setUserProfile({
                name: data.name || 'User',
                email: data.email || '',
                phone: data.phone || '',
                avatar: data.avatar_url || 'https://i.pravatar.cc/150?u=default',
            });
        }
    } catch (err) {
        console.error("Unexpected error fetching profile", err);
    }
  };

  if (!session) {
    return (
        <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
            <Auth />
        </div>
    );
  }

  const renderPage = () => {
    switch (activePage) {
      case Page.Dashboard:
        return <Dashboard />;
      case Page.HealthMetrics:
        return <HealthMetrics setActivePage={setActivePage} />;
      case Page.Medications:
        return <Medications />;
      case Page.Appointments:
        return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} />;
      case Page.ScheduleAppointment:
        return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} defaultToScheduling />;
      case Page.ChatBot:
        return <ChatBot userProfile={userProfile} />;
      case Page.Settings:
        return <Settings userProfile={userProfile} setUserProfile={setUserProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
      case Page.HelpSupport:
        return <HelpSupport />;
      case Page.VideoCall:
        return <VideoCall professional={videoCallProfessional} onEndCall={() => setActivePage(Page.Appointments)} />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
      <Layout activePage={activePage} setActivePage={setActivePage} userProfile={userProfile}>
        {renderPage()}
      </Layout>
    </div>
  );
};

export default App;

