interface SettingsProps {
    userProfile: UserProfile;
    setUserProfile: (profile: UserProfile) => void;
    isDarkMode: boolean;
    setIsDarkMode: (isDark: boolean) => void;
}

const Settings: React.FC<SettingsProps> = ({ userProfile, setUserProfile, isDarkMode, setIsDarkMode }) => {
    const [activeView, setActiveView] = useState<SettingView>('main');
    const [toastMessage, setToastMessage] = useState<string | null>(null);
    const [editedProfile, setEditedProfile] = useState<UserProfile>(userProfile);

    useEffect(() => {
        setEditedProfile(userProfile);
    }, [userProfile]);

    const handleProfileSave = async () => {
        setToastMessage('Updating profile...');
        if (!supabase) return;

        try {
            const { error } = await supabase.from('profiles').update({
                name: editedProfile.name,
                phone: editedProfile.phone,
                // avatar_url would go here if we were uploading properly
            }).eq('email', editedProfile.email); // using email as identifier since it's in profile state, ideally use user ID

            if (error) throw error;

            setUserProfile(editedProfile);
            setToastMessage('Profile updated successfully!');
        } catch (err: any) {
             setToastMessage('Error updating profile: ' + err.message);
        }
    };

    const handleAvatarChange = (newProfileWithAvatar: UserProfile) => {
        setEditedProfile(newProfileWithAvatar); // Stage the change
        setUserProfile(newProfileWithAvatar); // Save it immediately for instant feedback
        setToastMessage('Profile picture updated!');
    };

    // State for Alert Preferences
    const [alertLevels, setAlertLevels] = useState({
        [AlertLevel.High]: true,
        [AlertLevel.Medium]: true,
        [AlertLevel.Low]: false,
    });
    const [glucoseThresholds, setGlucoseThresholds] = useState({
        low: 70,
        high: 180,
    });
    const [appointmentReminders, setAppointmentReminders] = useState({
        remind24h: true,
        remind1h: true,
    });

    const handleLevelChange = (level: AlertLevel, enabled: boolean) => {
        setAlertLevels(prev => ({ ...prev, [level]: enabled }));
    };

    const handleThresholdChange = (field: 'low' | 'high', value: number) => {
        setGlucoseThresholds(prev => ({ ...prev, [field]: value }));
    };

    const handleReminderChange = (field: 'remind24h' | 'remind1h', enabled: boolean) => {
        setAppointmentReminders(prev => ({ ...prev, [field]: enabled }));
    }

    const handleSaveChanges = () => {
        console.log('Saving preferences:', { alertLevels, glucoseThresholds, appointmentReminders });
        setToastMessage('Preferences saved successfully!');
    };

    const handleReset = () => {
        setAlertLevels({
            [AlertLevel.High]: true,
            [AlertLevel.Medium]: true,
            [AlertLevel.Low]: false,
        });
        setGlucoseThresholds({ low: 70, high: 180 });
        setAppointmentReminders({ remind24h: true, remind1h: true });
        setToastMessage('Preferences reset to default.');
    };

    const renderView = () => {
        switch (activeView) {
            case 'profile': return (
                <ProfileSettings
                    profile={editedProfile}
                    onDetailsChange={setEditedProfile}
                    onSave={handleProfileSave}
                    onAvatarChange={handleAvatarChange}
                    isDarkMode={isDarkMode}
                    setIsDarkMode={setIsDarkMode}
                />
            );
            case 'notifications': return (
                <AlertPreferences
                    alertLevels={alertLevels}
                    glucoseThresholds={glucoseThresholds}
                    appointmentReminders={appointmentReminders}
                    onLevelChange={handleLevelChange}
                    onThresholdChange={handleThresholdChange}
                    onReminderChange={handleReminderChange}
                    onSaveChanges={handleSaveChanges}
                    onReset={handleReset}
                />
            );
            case 'account': return <AccountSettings />;
            case 'health': return <HealthProfileSetup />;
            default: return <MainSettingsView setView={setActiveView} />;
        }
    };

    const getTitle = () => {
        if (activeView === 'main') return 'Settings';
        return settingItems.find(item => item.id === activeView)?.title || 'Settings';
    };

    return (
        <div className="max-w-4xl mx-auto">
             {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
            <div className="flex items-center mb-6">
                {activeView !== 'main' && (
                    <button onClick={() => setActiveView('main')} className="flex items-center space-x-2 text-sm font-medium text-boticare-gray-dark hover:text-boticare-primary dark:text-gray-400 dark:hover:text-white mr-4">
                        <BackIcon className="w-5 h-5" />
                    </button>
                )}
                <h2 className="text-2xl font-bold">{getTitle()}</h2>
            </div>

            <div className="bg-white p-6 rounded-xl border border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700">
                {renderView()}
            </div>
        </div>
    );
};

