      ) : activeTab === 'History' ? (
        <div className="bg-white rounded-xl border border-boticare-gray-medium overflow-hidden dark:bg-gray-800 dark:border-gray-700 animate-fade-in shadow-sm">
            <div className="bg-gray-50 px-6 py-4 border-b border-boticare-gray-medium dark:bg-gray-700/50 dark:border-gray-600 flex justify-between items-center">
                <h3 className="text-sm font-bold uppercase tracking-wider text-gray-500 dark:text-gray-400 flex items-center gap-2">
                    <FileIcon className="w-4 h-4" /> Consultation History
                </h3>
                <span className="text-xs font-medium text-gray-400">{filteredAppointments.length} Completed</span>
            </div>
            {filteredAppointments.length > 0 ? (
                <div className="divide-y divide-boticare-gray-medium dark:divide-gray-700">
                    {filteredAppointments.map((appointment) => (
                        <div key={appointment.id} className="p-6 flex flex-col sm:flex-row sm:items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors gap-4">
                            <div className="flex items-center space-x-4">
                                <img src={appointment.avatar} alt={appointment.doctorName} className="w-12 h-12 rounded-full object-cover shadow-sm flex-shrink-0" />
                                <div>
                                    <h4 className="font-bold text-gray-900 dark:text-white">{appointment.doctorName}</h4>
                                    <p className="text-sm text-boticare-gray-dark dark:text-gray-400">{appointment.specialty} • {appointment.type}</p>
                                    <div className="flex items-center gap-3 text-xs text-gray-500 mt-1">
                                        <div className="flex items-center gap-1">
                                            <CalendarIcon className="w-3 h-3" />
                                            <span>{appointment.date}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center justify-end gap-3">
                                <button 
                                    onClick={() => handleViewDetails(appointment)}
                                    className="px-4 py-2 text-sm font-medium text-gray-600 bg-gray-100 hover:bg-gray-200 rounded-lg dark:bg-gray-700 dark:text-gray-300 dark:hover:bg-gray-600 transition-colors"
                                >
                                    Details
                                </button>
                                <button 
                                    onClick={() => handleViewSummary(appointment)}
                                    className="px-4 py-2 text-sm font-medium text-white bg-boticare-primary hover:bg-opacity-90 rounded-lg dark:bg-blue-600 dark:hover:bg-blue-700 transition-colors flex items-center gap-2"
                                >
                                    <FileIcon className="w-4 h-4" />
                                    Summary
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="p-16 text-center text-gray-500 dark:text-gray-400">
                    <FileIcon className="w-12 h-12 mx-auto mb-4 opacity-20" />
                    <p className="font-medium">No completed appointment history found.</p>
                </div>
            )}
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-fade-in pb-10">
            {filteredAppointments.length > 0 ? (
            filteredAppointments.map((appointment) => (
                <AppointmentCard 
                key={appointment.id} 
                appointment={appointment} 
                onReschedule={handleStartReschedule}
                onCancel={handleRequestCancel} 
                onJoinVideo={handleJoinVideo}
                onViewSummary={handleViewSummary}
                onEditNotes={handleOpenEditNotes}
                onViewDetails={handleViewDetails}
                />
            ))
            ) : (
            <div className="lg:col-span-2 text-center py-24 bg-white rounded-xl border-2 border-dashed border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700">
                <div className="bg-gray-50 dark:bg-gray-700 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                    <CalendarIcon className="w-8 h-8 text-gray-300 dark:text-gray-500" />
                </div>
                <p className="text-gray-500 dark:text-gray-400 font-bold text-lg">No matching appointments</p>
                <p className="text-sm text-gray-400 dark:text-gray-500 mb-6">Try adjusting your search or filters.</p>
                <button 
                    onClick={() => { setActiveType('All'); setSearchQuery(''); }}
                    className="text-boticare-blue-dark font-bold hover:bg-boticare-blue dark:text-blue-400 dark:hover:bg-blue-900/50 px-4 py-2 rounded-lg transition-colors border border-boticare-blue-dark dark:border-blue-400"
                >
                    Reset Filters
                </button>
            </div>
            )}
        </div>
      )}
    </div>
  );
};

export default Appointments;

import React from 'react';

export type UserRole = 'patient' | 'professional';

export enum Page {
  // Patient Pages
  Dashboard = 'Dashboard',
  HealthMetrics = 'Health Metrics',
  Medications = 'Medications',
  Appointments = 'Appointments',
  ChatBot = 'Chat Bot',
  Settings = 'Settings',
  HelpSupport = 'Help & Support',
  VideoCall = 'Video Call',
  ScheduleAppointment = 'Schedule Appointment',

  // Professional Pages
  ProfessionalDashboard = 'Dashboard ', // Space added to differentiate enum key if needed, or just reuse Dashboard visually
  PatientList = 'Patient List',
  ProfessionalSchedule = 'My Schedule',
}

export enum AppointmentStatus {
  Upcoming = 'Upcoming',
  Completed = 'Completed',
  Canceled = 'Canceled',
  Rescheduled = 'Rescheduled',
}

export enum AppointmentType {
    CheckUp = 'Check-up',
    FollowUp = 'Follow-up',
    Consultation = 'Consultation',
    Initial = 'Initial',
}

export interface Document {
    id: string;
    name: string;
    type: 'pdf' | 'jpg' | 'png';
    date: string;
}

export interface Appointment {
  id: number;
  doctorName: string; // Used for Patient View
  patientName?: string; // Used for Professional View
  specialty: string;
  status: AppointmentStatus;
  type: AppointmentType;
  date: string;
  time: string;
  duration: number;
  notes: string;
  avatar: string; // Doctor avatar for patient view, Patient avatar for doc view
  summary?: string;
  documents?: Document[];
}

export interface Medication {
  id: number;
  name: string;
  dosage: string;
  percentageLeft: number;
  nextDose: string;
  isTaken: boolean;
  refillNeeded?: string;
}

export enum HealthMetricStatus {
  Normal = 'Normal',
  Warning = 'Warning',
}

export interface HistoricalDataPoint {
    date: string;
    value: number;
}

export interface HealthMetric {
  id: string;
  name: string;
  value: string;
  unit: string;
  status: HealthMetricStatus;
  trend: string;
  trendDirection: 'up' | 'down' | 'stable';
  history: HistoricalDataPoint[];
}

export enum AlertLevel {
  High = 'High',
  Medium = 'Medium',
  Low = 'Low',
}

export interface HealthAlert {
  id: number;
  title: string;
  description: string;
  level: AlertLevel;
  time: string;
  icon: React.ComponentType<{ className?: string }>;
}

export interface Professional {
    id: number;
    name: string;
    specialty: string;
    avatar: string;
    rating: number;
}

export interface Patient {
    id: string;
    name: string;
    age: number;
    gender: string;
    condition: string;
    status: 'Stable' | 'Critical' | 'Recovering';
    lastVisit: string;
    avatar: string;
}

export interface ChatMessage {
  sender: 'user' | 'ai';
  text: string;
  imageUrl?: string;
  sources?: Array<{ title: string; uri: string }>;
  timestamp: string;
  isRead?: boolean;
}

export interface NewAppointmentDetails {
    consultationType: 'video' | 'chat';
    professional: Professional;
    date: string;
    time: string;
    notes: string;
}

export interface UserProfile {
    name: string;
    email: string;
    phone: string;
    avatar: string;
    role?: UserRole;
}

export interface FeedbackSubmission {
    id: string;
    rating: number;
    comment: string;
    date: string;
    source: 'video_call' | 'general';
}

export interface Symptom {
    id: string;
    name: string;
    date: string;
    description: string;
    severity: 'Mild' | 'Moderate' | 'Severe';
}

export interface VideoCallRecord {
    id: string;
    professionalName: string;
    professionalAvatar: string;
    date: string;
    time: string;
    duration: string;
}

