import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { LockClosedIcon, UserIcon, ArrowRightIcon, EyeIcon, EyeOffIcon, BriefcaseIcon } from './Icons';
import { UserRole } from '../types';

const Auth: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [isSignUp, setIsSignUp] = useState(false);
  const [role, setRole] = useState<UserRole>('patient');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [fullName, setFullName] = useState(''); // Only for Sign Up
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setMessage(null);

    // Persist role selection
    localStorage.setItem('boticare-user-role', role);

    try {
      if (isSignUp) {
        const { error } = await (supabase!.auth as any).signUp({
          email,
          password,
          options: {
            data: {
              full_name: fullName,
              role: role,
            },
            emailRedirectTo: window.location.origin,
          },
        });
        if (error) throw error;
        setMessage('Check your email for the confirmation link!');
      } else {
        const { error } = await (supabase!.auth as any).signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      }
    } catch (error: any) {
      setError(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-900 px-4">
      <div className="max-w-md w-full space-y-8 bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-100 dark:border-gray-700">
        <div className="text-center">
            <div className="w-16 h-16 bg-gradient-to-br from-blue-100 to-teal-100 dark:from-blue-900/30 dark:to-teal-900/30 rounded-full flex items-center justify-center mx-auto mb-4">
                <span className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-teal-600 dark:from-blue-400 dark:to-teal-400">B</span>
            </div>
          <h2 className="text-3xl font-extrabold text-gray-900 dark:text-white">
            {role === 'patient' ? (isSignUp ? 'Create Patient Account' : 'Welcome Back') : (isSignUp ? 'Professional Sign Up' : 'Welcome, Doctor')}
          </h2>
          <p className="mt-2 text-sm text-gray-600 dark:text-gray-400">
            {isSignUp 
                ? (role === 'patient' ? 'Start your health journey today' : 'Join our network of healthcare professionals') 
                : (role === 'patient' ? 'Sign in to access your health dashboard' : 'Sign in to manage your patients')}
          </p>
        </div>

        {/* Role Toggle */}
        <div className="bg-gray-100 dark:bg-gray-700 p-1 rounded-xl flex">
            <button
                type="button"
                onClick={() => setRole('patient')}
                className={`flex-1 flex items-center justify-center py-2 px-4 rounded-lg text-sm font-semibold transition-all ${role === 'patient' ? 'bg-white text-blue-600 shadow-sm dark:bg-gray-600 dark:text-white' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400'}`}
            >
                <UserIcon className="w-4 h-4 mr-2" />
                Patient
            </button>
            <button
                type="button"
                onClick={() => setRole('professional')}
                className={`flex-1 flex items-center justify-center py-2 px-4 rounded-lg text-sm font-semibold transition-all ${role === 'professional' ? 'bg-white text-blue-600 shadow-sm dark:bg-gray-600 dark:text-white' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400'}`}
            >
                <BriefcaseIcon className="w-4 h-4 mr-2" />
                Professional
            </button>
        </div>

        <form className="mt-6 space-y-6" onSubmit={handleAuth}>
          <div className="rounded-md shadow-sm space-y-4">
            {isSignUp && (
              <div>
                <label htmlFor="fullName" className="sr-only">Full Name</label>
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <UserIcon className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                    id="fullName"
                    name="fullName"
                    type="text"
                    required
                    className="appearance-none rounded-lg relative block w-full px-3 py-3 pl-10 border border-gray-300 placeholder-gray-500 text-gray-900 bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 focus:z-10 sm:text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-white dark:placeholder-gray-400 transition-all"
                    placeholder="Full Name"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    />
                </div>
              </div>
            )}
            <div>
              <label htmlFor="email-address" className="sr-only">Email address</label>
              <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <UserIcon className="h-5 w-5 text-gray-400" />
                  </div>
                  <input
                    id="email-address"
                    name="email"
                    type="email"
                    autoComplete="email"
                    required
                    className="appearance-none rounded-lg relative block w-full px-3 py-3 pl-10 border border-gray-300 placeholder-gray-500 text-gray-900 bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 focus:z-10 sm:text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-white dark:placeholder-gray-400 transition-all"
                    placeholder="Email address"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                  />
              </div>
            </div>
            <div>
              <label htmlFor="password" className="sr-only">Password</label>
              <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <LockClosedIcon className="h-5 w-5 text-gray-400" />
                  </div>
                  <input
                    id="password"
                    name="password"
                    type={showPassword ? "text" : "password"}
                    autoComplete="current-password"
                    required
                    className="appearance-none rounded-lg relative block w-full pl-10 pr-10 py-3 border border-gray-300 placeholder-gray-500 text-gray-900 bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 focus:z-10 sm:text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-white dark:placeholder-gray-400 transition-all"
                    placeholder="Password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />
                  <div className="absolute inset-y-0 right-0 pr-3 flex items-center">
                    <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="text-gray-400 hover:text-gray-500 focus:outline-none focus:text-gray-500 dark:text-gray-400 dark:hover:text-gray-300"
                        aria-label={showPassword ? "Hide password" : "Show password"}
                    >
                        {showPassword ? (
                            <EyeOffIcon className="h-5 w-5" />
                        ) : (
                            <EyeIcon className="h-5 w-5" />
                        )}
                    </button>
                  </div>
              </div>
            </div>
          </div>

          {error && (
            <div className="text-red-500 text-sm text-center bg-red-50 dark:bg-red-900/20 p-2 rounded">
              {error}
            </div>
          )}

          {message && (
            <div className="text-green-500 text-sm text-center bg-green-50 dark:bg-green-900/20 p-2 rounded">
              {message}
            </div>
          )}

          <div>
            <button
              type="submit"
              disabled={isLoading}
              className="group relative w-full flex justify-center py-3 px-4 border border-transparent text-sm font-bold rounded-lg text-white bg-gradient-to-r from-blue-600 to-teal-500 hover:from-blue-700 hover:to-teal-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 shadow-lg transform transition-all active:scale-[0.98]"
            >
              {isLoading ? (
                  <span className="flex items-center">
                    <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Processing...
                  </span>
              ) : (
                <span className="flex items-center">
                    {isSignUp ? 'Sign Up' : 'Sign In'}
                    <ArrowRightIcon className="ml-2 h-4 w-4" />
                </span>
              )}
            </button>
          </div>

          <div className="text-center">
            <button
              type="button"
              className="text-sm font-medium text-blue-600 hover:text-teal-600 dark:text-blue-400 dark:hover:text-teal-400 transition-colors"
              onClick={() => {
                  setIsSignUp(!isSignUp);
                  setError(null);
                  setMessage(null);
              }}
            >
              {isSignUp ? 'Already have an account? Sign in' : "Don't have an account? Sign up"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Auth;

import React from 'react';
import { Page, UserRole } from '../types';
import { DashboardIcon, HealthMetricsIcon, MedicationsIcon, AppointmentsIcon, ChatIcon, SettingsIcon, HelpIcon, XIcon, UsersIcon, CalendarIcon } from './Icons';

interface SidebarProps {
  activePage: Page;
  setActivePage: (page: Page) => void;
  onClose?: () => void;
  userRole?: UserRole;
}

const patientMenuItems = [
  { name: Page.Dashboard, icon: DashboardIcon },
  { name: Page.HealthMetrics, icon: HealthMetricsIcon },
  { name: Page.Medications, icon: MedicationsIcon },
  { name: Page.Appointments, icon: AppointmentsIcon },
  { name: Page.ChatBot, icon: ChatIcon },
];

const professionalMenuItems = [
    { name: Page.ProfessionalDashboard, icon: DashboardIcon, label: 'Dashboard' },
    { name: Page.PatientList, icon: UsersIcon, label: 'Patient List' },
    { name: Page.ProfessionalSchedule, icon: CalendarIcon, label: 'My Schedule' },
    { name: Page.Appointments, icon: AppointmentsIcon, label: 'Appointments' }, // Reusing component but can be adapted
];

const supportItems = [
  { name: Page.Settings, icon: SettingsIcon },
  { name: Page.HelpSupport, icon: HelpIcon },
];

const Sidebar: React.FC<SidebarProps> = ({ activePage, setActivePage, onClose, userRole = 'patient' }) => {
  const items = userRole === 'professional' ? professionalMenuItems : patientMenuItems;

  return (
    <aside className="w-64 h-full bg-white border-r border-boticare-gray-medium p-6 flex flex-col justify-between dark:bg-gray-800 dark:border-gray-700 overflow-y-auto">
      <div>
        <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-boticare-primary dark:text-white">Boticare <span className="text-xs font-normal bg-boticare-blue text-boticare-blue-dark px-1.5 py-0.5 rounded ml-1 align-middle">{userRole === 'professional' ? 'PRO' : ''}</span></h2>
            {onClose && (
                <button onClick={onClose} className="lg:hidden p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg">
                    <XIcon className="w-5 h-5 text-gray-500" />
                </button>
            )}
        </div>

        <p className="text-[10px] text-boticare-gray-dark font-bold uppercase tracking-wider mb-3 dark:text-gray-500">Main Menu</p>
        <nav className="space-y-1">
          {items.map((item) => (
            <SidebarItem
              key={item.name}
              icon={item.icon}
              label={('label' in item) ? (item as any).label : item.name}
              isActive={activePage === item.name || (item.name === Page.Appointments && activePage === Page.ScheduleAppointment)}
              onClick={() => setActivePage(item.name)}
            />
          ))}
        </nav>
      </div>

      <div className="mt-8">
        <p className="text-[10px] text-boticare-gray-dark font-bold uppercase tracking-wider mb-3 dark:text-gray-500">Support</p>
        <nav className="space-y-1">
          {supportItems.map((item) => (
            <SidebarItem
              key={item.name}
              icon={item.icon}
              label={item.name}
              isActive={activePage === item.name}
              onClick={() => setActivePage(item.name)}
            />
          ))}
        </nav>

        {userRole === 'patient' && (
            <div className="mt-8 p-4 bg-boticare-blue/30 dark:bg-blue-900/20 rounded-xl border border-boticare-blue dark:border-blue-800/50">
                <p className="text-xs font-bold text-boticare-blue-dark dark:text-blue-300 mb-1">Emergency Help</p>
                <p className="text-[10px] text-gray-600 dark:text-gray-400 mb-3">Instant connection to our 24/7 care team.</p>
                <button className="w-full py-1.5 bg-boticare-blue-dark text-white text-[10px] font-bold rounded-lg hover:bg-blue-600 transition-colors">
                    Call Now
                </button>
            </div>
        )}
      </div>
    </aside>
  );
};

interface SidebarItemProps {
  icon: React.ComponentType<{ className?: string }>;
  label: string;
  isActive: boolean;
  onClick: () => void;
}

const SidebarItem: React.FC<SidebarItemProps> = ({ icon: Icon, label, isActive, onClick }) => {
  return (
    <a
      href="#"
      onClick={(e) => { e.preventDefault(); onClick(); }}
      className={`flex items-center space-x-3 px-4 py-2.5 rounded-lg transition-all duration-200 ${
        isActive
          ? 'bg-boticare-blue text-boticare-blue-dark dark:bg-blue-900/50 dark:text-blue-300 shadow-sm'
          : 'text-boticare-gray-dark hover:bg-boticare-gray dark:text-gray-400 dark:hover:bg-gray-700 hover:translate-x-1'
      }`}
    >
      <Icon className={`w-5 h-5 ${isActive ? 'scale-110' : ''}`} />
      <span className="font-semibold text-sm">{label}</span>
    </a>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProfessionalDashboard from './components/ProfessionalDashboard';
import PatientList from './components/PatientList';
import HealthMetrics from './components/HealthMetrics';
import Medications from './components/Medications';
import Appointments from './components/Appointments';
import ChatBot from './components/Community';
import Settings from './components/Settings';
import HelpSupport from './components/HelpSupport';
import VideoCall from './components/VideoCall';
import Auth from './components/Auth';
import { supabase } from './services/supabaseClient';
import { Page, Professional, UserProfile, UserRole } from './types';

const App: React.FC = () => {
  const [session, setSession] = useState<any | null>(null);
  const [userRole, setUserRole] = useState<UserRole>('patient');
  const [activePage, setActivePage] = useState<Page>(Page.Dashboard);
  const [videoCallProfessional, setVideoCallProfessional] = useState<Professional | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Loading...',
    email: '',
    phone: '',
    avatar: 'https://i.pravatar.cc/150?u=placeholder',
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('boticare-dark-mode');
    if (saved !== null) {
      return saved === 'true';
    }
    return window.matchMedia?.('(prefers-color-scheme: dark)').matches ?? false;
  });

  // Handle Dark Mode
  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) {
      root.classList.add('dark');
      localStorage.setItem('boticare-dark-mode', 'true');
    } else {
      root.classList.remove('dark');
      localStorage.setItem('boticare-dark-mode', 'false');
    }
  }, [isDarkMode]);

  // Handle Supabase Session & Profile Fetching
  useEffect(() => {
    if (!supabase) return;

    // Check for persisted role
    const savedRole = localStorage.getItem('boticare-user-role') as UserRole;
    if (savedRole) {
        setUserRole(savedRole);
        // Reset active page based on role to avoid 404-like states
        if (savedRole === 'professional') {
            setActivePage(Page.ProfessionalDashboard);
        } else {
            setActivePage(Page.Dashboard);
        }
    }

    (supabase.auth as any).getSession().then(({ data: { session } }: any) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });

    const {
      data: { subscription },
    } = (supabase.auth as any).onAuthStateChange((_event: any, session: any) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    if (!supabase) return;

    try {
        const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

        if (error) {
            console.error('Error fetching profile:', error);
        } else if (data) {
            setUserProfile({
                name: data.name || 'User',
                email: data.email || '',
                phone: data.phone || '',
                avatar: data.avatar_url || 'https://i.pravatar.cc/150?u=default',
            });
        }
    } catch (err) {
        console.error("Unexpected error fetching profile", err);
    }
  };

  if (!session) {
    return (
        <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
            <Auth />
        </div>
    );
  }

  const renderPage = () => {
    // Professional Views
    if (userRole === 'professional') {
        switch (activePage) {
            case Page.ProfessionalDashboard:
                return <ProfessionalDashboard />;
            case Page.PatientList:
                return <PatientList />;
            case Page.ProfessionalSchedule: // Reusing appointment component logic but could be separate
            case Page.Appointments:
                return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} />;
            case Page.ChatBot:
                return <ChatBot userProfile={userProfile} />;
            case Page.Settings:
                return <Settings userProfile={userProfile} setUserProfile={setUserProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
            case Page.HelpSupport:
                return <HelpSupport />;
            case Page.VideoCall:
                return <VideoCall professional={videoCallProfessional} onEndCall={() => setActivePage(Page.Appointments)} />;
            default:
                return <ProfessionalDashboard />;
        }
    }

    // Patient Views
    switch (activePage) {
      case Page.Dashboard:
        return <Dashboard />;
      case Page.HealthMetrics:
        return <HealthMetrics setActivePage={setActivePage} />;
      case Page.Medications:
        return <Medications />;
      case Page.Appointments:
        return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} />;
      case Page.ScheduleAppointment:
        return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} defaultToScheduling />;
      case Page.ChatBot:
        return <ChatBot userProfile={userProfile} />;
      case Page.Settings:
        return <Settings userProfile={userProfile} setUserProfile={setUserProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
      case Page.HelpSupport:
        return <HelpSupport />;
      case Page.VideoCall:
        return <VideoCall professional={videoCallProfessional} onEndCall={() => setActivePage(Page.Appointments)} />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
      <Layout activePage={activePage} setActivePage={setActivePage} userProfile={userProfile} userRole={userRole}>
        {renderPage()}
      </Layout>
    </div>
  );
};

