import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Patient, UserProfile } from '../types';
import { SendIcon, XIcon, UserIcon, ArrowRightIcon, BackIcon } from './Icons';

interface PersonalChatProps {
    recipient: Patient | UserProfile | null;
    userProfile: UserProfile;
    onClose: () => void;
}

const PersonalChat: React.FC<PersonalChatProps> = ({ recipient, userProfile, onClose }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [input, setInput] = useState('');
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(scrollToBottom, [messages]);

    const handleSend = () => {
        if (!input.trim()) return;
        const newMsg: ChatMessage = {
            sender: userProfile.role === 'professional' ? 'professional' : 'patient',
            text: input,
            timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            isRead: false
        };
        setMessages(prev => [...prev, newMsg]);
        setInput('');

        // Simulate reply after 1s
        setTimeout(() => {
            const reply: ChatMessage = {
                sender: userProfile.role === 'professional' ? 'patient' : 'professional',
                text: "I've received your message and will review it shortly. Thank you.",
                timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            };
            setMessages(prev => [...prev, reply]);
        }, 1500);
    };

    if (!recipient) return null;

    const recipientName = 'name' in recipient ? recipient.name : 'Unknown';
    const recipientAvatar = 'avatar' in recipient ? recipient.avatar : 'https://i.pravatar.cc/150';

    return (
        <div className="h-full flex flex-col bg-white dark:bg-gray-800 rounded-xl border border-boticare-gray-medium dark:border-gray-700 shadow-xl animate-fade-in overflow-hidden">
            {/* Header */}
            <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between bg-white dark:bg-gray-800 sticky top-0 z-10">
                <div className="flex items-center gap-3">
                    <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg lg:hidden">
                        <BackIcon className="w-5 h-5 text-gray-500" />
                    </button>
                    <div className="relative">
                        <img src={recipientAvatar} className="w-10 h-10 rounded-full object-cover" alt={recipientName} />
                        <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white dark:border-gray-800 rounded-full"></div>
                    </div>
                    <div>
                        <h3 className="font-bold text-gray-900 dark:text-white leading-tight">{recipientName}</h3>
                        <p className="text-[10px] text-green-600 font-bold uppercase tracking-wider">Online</p>
                    </div>
                </div>
                <button onClick={onClose} className="hidden lg:block p-2 text-gray-400 hover:text-gray-600"><XIcon className="w-6 h-6"/></button>
            </div>

            {/* Chat Area */}
            <div className="flex-grow p-4 md:p-6 overflow-y-auto space-y-4 no-scrollbar">
                <div className="text-center py-4">
                    <span className="text-[10px] font-bold text-gray-400 bg-gray-50 dark:bg-gray-700/50 px-3 py-1 rounded-full uppercase tracking-widest border border-gray-100 dark:border-gray-700">
                        Secure End-to-End Encrypted Session
                    </span>
                </div>
                {messages.length === 0 && (
                    <div className="text-center py-20 opacity-50">
                        <ChatIcon className="w-12 h-12 mx-auto mb-2 text-gray-300" />
                        <p className="text-sm font-medium">Start the conversation with {recipientName}</p>
                    </div>
                )}
                {messages.map((msg, idx) => (
                    <div key={idx} className={`flex ${msg.sender === (userProfile.role === 'professional' ? 'professional' : 'patient') ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[75%] p-3 rounded-2xl shadow-sm text-sm ${
                            msg.sender === (userProfile.role === 'professional' ? 'professional' : 'patient')
                                ? 'bg-blue-600 text-white rounded-br-none'
                                : 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-100 rounded-bl-none'
                        }`}>
                            <p>{msg.text}</p>
                            <span className="text-[9px] opacity-70 mt-1 block text-right">{msg.timestamp}</span>
                        </div>
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="p-4 bg-gray-50 dark:bg-gray-900/50 border-t border-gray-100 dark:border-gray-700">
                <div className="relative flex items-center">
                    <input 
                        type="text" 
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyPress={e => e.key === 'Enter' && handleSend()}
                        placeholder="Type a secure message..."
                        className="w-full bg-white dark:bg-gray-800 border-none rounded-xl pl-4 pr-12 py-3 shadow-inner focus:ring-2 focus:ring-blue-500 focus:outline-none dark:text-white"
                    />
                    <button 
                        onClick={handleSend}
                        className="absolute right-2 p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                    >
                        <SendIcon className="w-4 h-4" />
                    </button>
                </div>
                <p className="text-[9px] text-center text-gray-400 mt-2">Boticare encrypted chat protocol v2.4.1</p>
            </div>
        </div>
    );
};

export default PersonalChat;

