import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProfessionalDashboard from './components/ProfessionalDashboard';
import PatientList from './components/PatientList';
import HealthMetrics from './components/HealthMetrics';
import Medications from './components/Medications';
import Appointments from './components/Appointments';
import ChatBot from './components/Community';
import PersonalChat from './components/PersonalChat';
import Settings from './components/Settings';
import HelpSupport from './components/HelpSupport';
import VideoCall from './components/VideoCall';
import Auth from './components/Auth';
import { supabase } from './services/supabaseClient';
import { Page, Professional, UserProfile, UserRole, BoticareNotification, Patient } from './types';
import Toast from './components/Toast';

const App: React.FC = () => {
  const [session, setSession] = useState<any | null>(null);
  const [userRole, setUserRole] = useState<UserRole>('patient');
  const [activePage, setActivePage] = useState<Page>(Page.Dashboard);
  const [videoCallProfessional, setVideoCallProfessional] = useState<Professional | null>(null);
  const [videoCallPatient, setVideoCallPatient] = useState<Patient | null>(null);
  const [chatRecipient, setChatRecipient] = useState<Patient | UserProfile | null>(null);
  const [notifications, setNotifications] = useState<BoticareNotification[]>([]);
  const [activeToast, setActiveToast] = useState<string | null>(null);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Loading...',
    email: '',
    phone: '',
    avatar: 'https://i.pravatar.cc/150?u=placeholder',
    professionalTitle: 'Doctor',
    specialty: 'General Practice'
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('boticare-dark-mode');
    if (saved !== null) return saved === 'true';
    return window.matchMedia?.('(prefers-color-scheme: dark)').matches ?? false;
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) { root.classList.add('dark'); localStorage.setItem('boticare-dark-mode', 'true'); }
    else { root.classList.remove('dark'); localStorage.setItem('boticare-dark-mode', 'false'); }
  }, [isDarkMode]);

  useEffect(() => {
    if (!supabase) return;
    const savedRole = localStorage.getItem('boticare-user-role') as UserRole;
    if (savedRole) {
        setUserRole(savedRole);
        setActivePage(savedRole === 'professional' ? Page.ProfessionalDashboard : Page.Dashboard);
    }
    (supabase.auth as any).getSession().then(({ data: { session } }: any) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    const { data: { subscription } } = (supabase.auth as any).onAuthStateChange((_event: any, session: any) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    if (!supabase) return;
    try {
        const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single();
        if (data) {
            setUserProfile({
                name: data.name || 'User',
                email: data.email || '',
                phone: data.phone || '',
                avatar: data.avatar_url || 'https://i.pravatar.cc/150?u=default',
                role: userRole,
                professionalTitle: userRole === 'professional' ? 'Doctor' : undefined,
                specialty: userRole === 'professional' ? 'General Practice' : undefined
            });
        }
    } catch (err) { console.error("Profile fetch error", err); }
  };

  const handleAddNotification = (msg: string) => {
      const newNotif: BoticareNotification = {
          id: Date.now().toString(),
          message: msg,
          type: 'success',
          timestamp: new Date().toLocaleTimeString()
      };
      setNotifications(prev => [newNotif, ...prev]);
  };

  const startPersonalChat = (recipient: Patient | UserProfile) => {
      setChatRecipient(recipient);
      setActivePage(Page.PersonalChat);
  };

  if (!session) {
    return <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200"><Auth /></div>;
  }

  const renderPage = () => {
    if (userRole === 'professional') {
        switch (activePage) {
            case Page.ProfessionalDashboard: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
            case Page.PatientList: return <PatientList setActivePage={setActivePage} onStartChat={startPersonalChat} />;
            case Page.ProfessionalSchedule: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} isProfessionalView userRole={userRole} />;
            case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
            case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.PatientList)} />;
            case Page.Settings: return <Settings userProfile={userProfile} setUserProfile={setUserProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
            case Page.HelpSupport: return <HelpSupport />;
            case Page.VideoCall: return <VideoCall professional={videoCallProfessional} patient={videoCallPatient} isProfessionalView onEndCall={() => setActivePage(Page.ProfessionalSchedule)} />;
            default: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
        }
    }

    return (
      <div className="space-y-6">
        {notifications.length > 0 && notifications.map(n => (
            <div key={n.id} className="bg-blue-600 text-white p-4 rounded-xl shadow-lg flex items-center justify-between animate-fade-in mb-4">
                <div className="flex items-center gap-3">
                    <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                    <p className="text-sm font-bold">{n.message}</p>
                </div>
                <button onClick={() => setNotifications(prev => prev.filter(x => x.id !== n.id))} className="text-white/70 hover:text-white font-bold text-xs px-3 py-1 bg-white/10 rounded-lg">Dismiss</button>
            </div>
        ))}
        {(() => {
            switch (activePage) {
                case Page.Dashboard: return <Dashboard />;
                case Page.HealthMetrics: return <HealthMetrics setActivePage={setActivePage} />;
                case Page.Medications: return <Medications />;
                case Page.Appointments: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} />;
                case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
                case Page.Settings: return <Settings userProfile={userProfile} setUserProfile={setUserProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
                case Page.HelpSupport: return <HelpSupport />;
                case Page.VideoCall: return <VideoCall professional={videoCallProfessional} onEndCall={() => setActivePage(Page.Appointments)} />;
                default: return <Dashboard />;
            }
        })()}
      </div>
    );
  };

  return (
    <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
      <Layout activePage={activePage} setActivePage={setActivePage} userProfile={userProfile} userRole={userRole}>
        {renderPage()}
      </Layout>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Patient, Professional } from '../types';
import { BackIcon, MicIcon, MicOffIcon, VideoOnIcon, VideoOffIcon, EndCallIcon, UserIcon, AlertIcon } from './Icons';
import FeedbackModal from './FeedbackModal';

interface VideoCallProps {
  professional?: Professional | null;
  patient?: Patient | null;
  isProfessionalView?: boolean;
  onEndCall: () => void;
}

const VideoCall: React.FC<VideoCallProps> = ({ professional, patient, isProfessionalView, onEndCall }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isCameraOn, setIsCameraOn] = useState(true);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [mediaError, setMediaError] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);
  const userVideoRef = useRef<HTMLVideoElement>(null);
  const userStreamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    const startStream = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' }, audio: true });
        userStreamRef.current = stream;
        if (userVideoRef.current) userVideoRef.current.srcObject = stream;
      } catch (err) {
        setMediaError("Could not access camera/microphone. Please check permissions.");
      }
    };
    startStream();
    return () => { if (userStreamRef.current) userStreamRef.current.getTracks().forEach(track => track.stop()); };
  }, []);

  useEffect(() => {
    const timerId = setInterval(() => setElapsedTime(prev => prev + 1), 1000);
    return () => clearInterval(timerId);
  }, []);

  const toggleMic = () => { if (userStreamRef.current) { userStreamRef.current.getAudioTracks().forEach(t => t.enabled = !t.enabled); setIsMuted(!isMuted); } };
  const toggleCamera = () => { if (userStreamRef.current) { userStreamRef.current.getVideoTracks().forEach(t => t.enabled = !t.enabled); setIsCameraOn(!isCameraOn); } };

  const handleEndCallClick = () => { if (userStreamRef.current) userStreamRef.current.getTracks().forEach(t => t.stop()); setShowFeedback(true); };

  const targetName = isProfessionalView ? (patient?.name || 'Patient') : (professional?.name || 'Practitioner');
  const targetAvatar = isProfessionalView ? (patient?.avatar || `https://i.pravatar.cc/150?u=patient`) : (professional?.avatar || 'https://i.pravatar.cc/150?u=pro');

  return (
    <div className="animate-fade-in space-y-4 pb-10">
        {showFeedback && <FeedbackModal isOpen onClose={() => onEndCall()} onSubmit={() => onEndCall()} source="video_call" />}

        <div className="flex items-center space-x-4 p-4 bg-white dark:bg-gray-800 rounded-2xl border border-boticare-gray-medium dark:border-gray-700 shadow-sm">
            <span className="relative flex h-3 w-3">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
            </span>
            <span className="text-[10px] font-black bg-green-100 text-green-800 px-2.5 py-1 rounded-lg dark:bg-green-900/50 dark:text-green-300 uppercase tracking-widest">Live Consultation</span>
            <h2 className="text-lg font-bold truncate">Session with {targetName}</h2>
            <span className="text-sm font-mono font-bold text-blue-600 ml-auto">{Math.floor(elapsedTime / 60)}:{String(elapsedTime % 60).padStart(2, '0')}</span>
        </div>

        <div className="relative bg-gray-900 rounded-3xl overflow-hidden aspect-video flex flex-col shadow-2xl group">
            {mediaError && <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center p-8 z-20 text-center text-white space-y-4"><AlertIcon className="w-12 h-12 text-red-500" /><p>{mediaError}</p></div>}

            <div className="flex-grow relative">
                <img src={targetAvatar} className="w-full h-full object-cover opacity-80" alt={targetName} />
                <div className="absolute bottom-6 left-6 text-white bg-black/50 backdrop-blur-md px-4 py-2 rounded-xl border border-white/20">
                    <p className="font-bold text-sm">{targetName}</p>
                </div>
            </div>

            <div className="absolute top-6 right-6 w-48 h-32 bg-gray-800 rounded-2xl overflow-hidden border-2 border-white/30 shadow-2xl z-10">
                <video ref={userVideoRef} autoPlay muted playsInline className={`w-full h-full object-cover ${isCameraOn ? 'block' : 'hidden'}`} />
                 {!isCameraOn && <div className="w-full h-full flex items-center justify-center bg-gray-700"><UserIcon className="w-12 h-12 text-gray-500" /></div>}
                <div className="absolute bottom-2 left-2 text-[10px] font-bold text-white bg-black/50 px-2 py-0.5 rounded-lg">You</div>
            </div>

            <div className="absolute bottom-6 left-0 right-0 flex items-center justify-center space-x-6 z-10 translate-y-2 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300">
                <button onClick={toggleMic} className={`p-4 rounded-2xl transition-all shadow-xl ${isMuted ? 'bg-red-500 text-white' : 'bg-white/20 backdrop-blur-md text-white hover:bg-white/40 border border-white/30'}`}><MicIcon className="w-6 h-6" /></button>
                <button onClick={toggleCamera} className={`p-4 rounded-2xl transition-all shadow-xl ${!isCameraOn ? 'bg-red-500 text-white' : 'bg-white/20 backdrop-blur-md text-white hover:bg-white/40 border border-white/30'}`}><VideoOnIcon className="w-6 h-6" /></button>
                <button onClick={handleEndCallClick} className="w-16 h-16 rounded-3xl bg-red-600 hover:bg-red-700 text-white flex items-center justify-center shadow-xl hover:scale-105 transition-all"><EndCallIcon className="w-8 h-8" /></button>
            </div>
        </div>
    </div>
  );
};

export default VideoCall;

import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA, VIDEO_CALL_HISTORY_DATA } from '../constants';
import AppointmentCard from './AppointmentCard';
import BookAppointmentForm from './ScheduleAppointmentForm';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import CancelAppointmentModal from './CancelAppointmentModal';
import { Appointment, AppointmentStatus, Page, Professional, NewAppointmentDetails, AppointmentType, UserRole } from '../types';
import { PlusIcon, SearchIcon, VideoIcon, ClockIcon, FilterIcon, CalendarIcon, FileIcon, ChevronRightIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const STATUS_TABS = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
  'Call History',
  'History'
];

const TYPE_FILTERS = ['All', ...Object.values(AppointmentType)];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  setVideoCallProfessional: (professional: Professional | null) => void;
  defaultToScheduling?: boolean;
  isProfessionalView?: boolean;
  userRole?: UserRole;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false, isProfessionalView, userRole }) => {
  const [activeTab, setActiveTab] = useState<string>(AppointmentStatus.Upcoming);
  const [activeType, setActiveType] = useState<string>('All');
  const [isScheduling, setIsScheduling] = useState(defaultToScheduling);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [appointmentToReschedule, setAppointmentToReschedule] = useState<Appointment | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [cancelingAppointment, setCancelingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => {
        if (activeTab === 'History') return appointment.status === AppointmentStatus.Completed;
        return appointment.status === activeTab;
    })
    .filter((appointment) => {
        if (activeType === 'All') return true;
        return appointment.type === activeType;
    })
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        const targetSearchName = isProfessionalView ? appointment.patientName : appointment.doctorName;
        return (
            targetSearchName.toLowerCase().includes(lowerCaseQuery) ||
            appointment.specialty.toLowerCase().includes(lowerCaseQuery)
        );
    });

  const handleBookSuccess = (details: NewAppointmentDetails) => {
    const newAppointment: Appointment = {
        id: Math.max(...appointments.map(a => a.id), 0) + 1,
        doctorName: details.professional.name,
        specialty: details.professional.specialty,
        status: AppointmentStatus.Upcoming,
        type: AppointmentType.Consultation,
        date: details.date,
        time: details.time,
        duration: 30,
        notes: details.notes || `Consultation for ${details.professional.specialty}`,
        avatar: details.professional.avatar,
        patientName: 'Jane Doe',
        documents: []
    };

    setAppointments(prev => [newAppointment, ...prev]);
    setIsScheduling(false);
    setActiveTab(AppointmentStatus.Upcoming);
    setToastMessage('Appointment scheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRescheduleConfirm = (appointmentId: number, details: NewAppointmentDetails) => {
    setAppointments(prev => 
      prev.map(app => 
        app.id === appointmentId 
          ? { 
              ...app, 
              status: AppointmentStatus.Rescheduled, 
              date: details.date, 
              time: details.time,
              notes: details.notes,
            }
          : app
      )
    );
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    setActiveTab(AppointmentStatus.Rescheduled);
    setToastMessage('Appointment rescheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleStartReschedule = (appointment: Appointment) => {
    setAppointmentToReschedule(appointment);
    setIsScheduling(true);
  };

  const handleCancelAppointment = (appointmentId: number) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId
          ? { ...app, status: AppointmentStatus.Canceled }
          : app
      )
    );
    setActiveTab(AppointmentStatus.Canceled);
    setToastMessage('Appointment canceled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRequestCancel = (appointment: Appointment) => {
    setCancelingAppointment(appointment);
  };

  const handleCancelScheduling = () => {
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    if (defaultToScheduling) {
        setActivePage(Page.HealthMetrics);
    }
  }

  const handleJoinVideo = (appointment: Appointment) => {
    if (isProfessionalView) {
        // As a professional, join the session with the patient
        setActivePage(Page.VideoCall);
    } else {
        const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
        setVideoCallProfessional(professional);
        setActivePage(Page.VideoCall);
    }
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    if (appointment.summary) {
      setSummaryModalState({ appointment, summary: appointment.summary, isLoading: false });
      return;
    }
    const summaryText = await getAppointmentSummary(appointment);
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointment.id ? { ...app, summary: summaryText } : app
      )
    );
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  const handleCloseSummaryModal = () => {
    setSummaryModalState({ appointment: null, summary: '', isLoading: false });
  };

