import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProfessionalDashboard from './components/ProfessionalDashboard';
import PatientList from './components/PatientList';
import HealthMetrics from './components/HealthMetrics';
import Medications from './components/Medications';
import Appointments from './components/Appointments';
import MyDoctors from './components/MyDoctors';
import ChatBot from './components/Community';
import PersonalChat from './components/PersonalChat';
import Settings from './components/Settings';
import HelpSupport from './components/HelpSupport';
import VideoCall from './components/VideoCall';
import Auth from './components/Auth';
import { supabase } from './services/supabaseClient';
import { Page, Professional, UserProfile, UserRole, BoticareNotification, Patient } from './types';

const App: React.FC = () => {
  const [session, setSession] = useState<any | null>(null);
  const [userRole, setUserRole] = useState<UserRole>('patient');
  const [activePage, setActivePage] = useState<Page>(Page.Dashboard);
  const [videoCallProfessional, setVideoCallProfessional] = useState<Professional | null>(null);
  const [videoCallPatient, setVideoCallPatient] = useState<Patient | null>(null);
  const [chatRecipient, setChatRecipient] = useState<Patient | UserProfile | null>(null);
  const [notifications, setNotifications] = useState<BoticareNotification[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Loading...',
    email: '',
    phone: '',
    avatar: 'https://i.pravatar.cc/150?u=placeholder',
    professionalTitle: 'Doctor',
    specialty: 'General Practice'
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('boticare-dark-mode');
    return saved ? saved === 'true' : window.matchMedia?.('(prefers-color-scheme: dark)').matches;
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) { root.classList.add('dark'); } else { root.classList.remove('dark'); }
    localStorage.setItem('boticare-dark-mode', String(isDarkMode));
  }, [isDarkMode]);

  useEffect(() => {
    if (!supabase) return;
    const savedRole = localStorage.getItem('boticare-user-role') as UserRole;
    if (savedRole) {
        setUserRole(savedRole);
        setActivePage(savedRole === 'professional' ? Page.ProfessionalDashboard : Page.Dashboard);
    }
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    if (!supabase) return;
    try {
        const { data } = await supabase.from('profiles').select('*').eq('id', userId).single();
        if (data) {
            setUserProfile({
                name: data.name || 'User',
                email: data.email || '',
                phone: data.phone || '',
                avatar: data.avatar_url || 'https://i.pravatar.cc/150?u=default',
                role: userRole,
                professionalTitle: userRole === 'professional' ? (data.professional_title || 'Doctor') : undefined,
                specialty: userRole === 'professional' ? (data.specialty || 'General Practice') : undefined
            });
        }
    } catch (err) { console.error("Profile fetch error", err); }
  };

  const handleAddNotification = (msg: string) => {
      const newNotif: BoticareNotification = {
          id: Date.now().toString(),
          message: msg,
          type: 'success',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          read: false
      };
      setNotifications(prev => [newNotif, ...prev]);
  };

  const handleMarkNotificationsAsRead = () => {
      setTimeout(() => {
          setNotifications(prev => prev.map(n => ({...n, read: true})));
      }, 2000);
  };

  const startPersonalChat = (recipient: Patient | UserProfile) => {
      setChatRecipient(recipient);
      setActivePage(Page.PersonalChat);
  };

  if (!session) {
    return <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200"><Auth /></div>;
  }

  const renderPage = () => {
    if (userRole === 'professional') {
        switch (activePage) {
            case Page.ProfessionalDashboard: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
            case Page.PatientList: return <PatientList setActivePage={setActivePage} onStartChat={startPersonalChat} />;
            case Page.ProfessionalSchedule: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} isProfessionalView userRole={userRole} />;
            case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
            case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.PatientList)} />;
            case Page.Settings: return <Settings userProfile={userProfile} setUserProfile={setUserProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
            case Page.HelpSupport: return <HelpSupport />;
            case Page.VideoCall: return <VideoCall professional={videoCallProfessional} patient={videoCallPatient} isProfessionalView onEndCall={() => setActivePage(Page.ProfessionalSchedule)} />;
            default: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
        }
    }

    // Patient View
    switch (activePage) {
        case Page.Dashboard: return <Dashboard />;
        case Page.HealthMetrics: return <HealthMetrics setActivePage={setActivePage} />;
        case Page.Medications: return <Medications />;
        case Page.Appointments: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={setVideoCallProfessional} />;
        case Page.MyDoctors: return <MyDoctors onStartChat={startPersonalChat} />;
        case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
        case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.MyDoctors)} />;
        case Page.Settings: return <Settings userProfile={userProfile} setUserProfile={setUserProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
        case Page.HelpSupport: return <HelpSupport />;
        case Page.VideoCall: return <VideoCall professional={videoCallProfessional} onEndCall={() => setActivePage(Page.Appointments)} />;
        default: return <Dashboard />;
    }
  };

  return (
    <div className="bg-boticare-gray text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
      <Layout 
        activePage={activePage} 
        setActivePage={setActivePage} 
        userProfile={userProfile} 
        userRole={userRole}
        notifications={notifications}
        onMarkNotificationsAsRead={handleMarkNotificationsAsRead}
      >
        {renderPage()}
      </Layout>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import Header from './Header';
import Sidebar from './Sidebar';
import { Page, UserProfile, UserRole, BoticareNotification } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activePage: Page;
  setActivePage: (page: Page) => void;
  userProfile: UserProfile;
  userRole: UserRole;
  notifications: BoticareNotification[];
  onMarkNotificationsAsRead: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activePage, setActivePage, userProfile, userRole, notifications, onMarkNotificationsAsRead }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);
  const closeSidebar = () => setIsSidebarOpen(false);

  return (
    <div className="flex h-screen bg-boticare-gray dark:bg-gray-900 overflow-hidden relative">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-30 lg:hidden animate-fade-in"
          onClick={closeSidebar}
        />
      )}

      {/* Sidebar - Hidden on mobile, overlay on small/medium screens, fixed on large */}
      <div className={`
        fixed inset-y-0 left-0 transform lg:relative lg:translate-x-0 transition duration-200 ease-in-out z-40
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <Sidebar 
          activePage={activePage} 
          setActivePage={(page) => {
            setActivePage(page);
            closeSidebar();
          }} 
          onClose={closeSidebar}
          userRole={userRole}
        />
      </div>

      <div className="flex-1 flex flex-col overflow-hidden min-w-0">
        <Header 
          userProfile={userProfile} 
          onNavigate={(page) => {
            setActivePage(page);
            closeSidebar();
          }} 
          onToggleSidebar={toggleSidebar}
          notifications={notifications}
          onMarkNotificationsAsRead={onMarkNotificationsAsRead}
        />
        <main className="flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-8">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;

