                        <button onClick={() => setLocalProfile({...localProfile, professionalTitle: 'Doctor'})} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${localProfile.professionalTitle === 'Doctor' ? 'bg-white shadow-sm text-blue-600 dark:bg-gray-600 dark:text-white' : 'text-gray-500'}`}>Doctor</button>
                        <button onClick={() => setLocalProfile({...localProfile, professionalTitle: 'Pharmacist'})} className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${localProfile.professionalTitle === 'Pharmacist' ? 'bg-white shadow-sm text-blue-600 dark:bg-gray-600 dark:text-white' : 'text-gray-500'}`}>Pharmacist</button>
