                    <div className="flex-1"><label className="block text-xs font-bold uppercase tracking-wider text-gray-500 mb-1">End Time</label><input type="time" defaultValue="17:00" className="w-full bg-boticare-gray dark:bg-gray-700 border-none rounded-xl px-4 py-3 font-bold text-lg"/></div>
