};

const Settings: React.FC<{ userProfile: UserProfile, setUserProfile: (p: UserProfile) => void, isDarkMode: boolean, setIsDarkMode: (d: boolean) => void; }> = ({ userProfile, setUserProfile, isDarkMode, setIsDarkMode }) => {
    const [activeView, setActiveView] = useState<SettingView>('main');
    const [toast, setToast] = useState<string | null>(null);
    const isProfessional = userProfile.role === 'professional';

    const handleSave = (updated: UserProfile) => { setUserProfile(updated); setToast("Settings updated successfully"); };

    const renderView = () => {
        switch (activeView) {
            case 'profile': return <ProfileSettings profile={userProfile} onSave={handleSave} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
            case 'practice': return <PracticeDetails profile={userProfile} onSave={handleSave} />;
            case 'availability': return <AvailabilitySettings />;
            case 'account': return <AccountSettings />;
            case 'notifications': return <AlertPreferences alertLevels={{[AlertLevel.High]: true, [AlertLevel.Medium]: true, [AlertLevel.Low]: false}} glucoseThresholds={{low: 70, high: 140}} appointmentReminders={{remind24h: true, remind1h: true}} onLevelChange={()=>{}} onThresholdChange={()=>{}} onReminderChange={()=>{}} onSaveChanges={()=>{}} onReset={()=>{}} />;
            default: return <MainSettingsView setView={setActiveView} isProfessional={isProfessional} />;
        }
    };

    return (
        <div className="max-w-4xl mx-auto pb-20">
            {toast && <Toast message={toast} type="success" onClose={() => setToast(null)} />}
            <div className="flex items-center mb-8">
                {activeView !== 'main' && (<button onClick={() => setActiveView('main')} className="p-2 bg-gray-100 dark:bg-gray-800 rounded-xl mr-4"><BackIcon className="w-5 h-5" /></button>)}
                <h2 className="text-3xl font-black">{activeView === 'main' ? 'Settings' : 'Manage ' + activeView.charAt(0).toUpperCase() + activeView.slice(1)}</h2>
            </div>
            <div className="bg-white p-2 md:p-8 rounded-2xl border border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700 shadow-sm">{renderView()}</div>
        </div>
    );
};

export default Settings;

