import React from 'react';
import { Page, Professional, UserProfile } from '../types';
import { PROFESSIONALS_DATA } from '../constants';
import { ChatIcon, StarIcon } from './Icons';

interface MyDoctorsProps {
    onStartChat: (recipient: Professional) => void;
}

const MyDoctors: React.FC<MyDoctorsProps> = ({ onStartChat }) => {
    return (
        <div className="space-y-6">
            <div>
                <h2 className="text-2xl font-black">My Doctors</h2>
                <p className="text-boticare-gray-dark dark:text-gray-400">Your dedicated healthcare team. Start a secure conversation anytime.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {PROFESSIONALS_DATA.map(pro => (
                    <div key={pro.id} className="bg-white p-6 rounded-2xl border border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700 shadow-sm flex flex-col items-center text-center">
                        <div className="relative mb-4">
                            <img src={pro.avatar} alt={pro.name} className="w-24 h-24 rounded-full border-4 border-white dark:border-gray-600 shadow-lg" />
                            <div className="absolute -bottom-1 right-0 bg-white dark:bg-gray-800 rounded-full p-1 shadow-md">
                                <div className="flex items-center gap-1 bg-yellow-100 text-yellow-800 dark:bg-yellow-900/50 dark:text-yellow-300 px-2 py-0.5 rounded-full">
                                    <StarIcon className="w-3 h-3" />
                                    <span className="text-xs font-bold">{pro.rating.toFixed(1)}</span>
                                </div>
                            </div>
                        </div>
                        <h3 className="font-bold text-lg text-gray-900 dark:text-white">{pro.name}</h3>
                        <p className="text-sm text-blue-600 dark:text-blue-400 font-semibold mb-4">{pro.specialty}</p>
                        <button 
                            onClick={() => onStartChat(pro)}
                            className="w-full bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-colors shadow-lg shadow-blue-100 dark:shadow-none flex items-center justify-center gap-2"
                        >
                            <ChatIcon className="w-5 h-5"/>
                            Send Secure Message
                        </button>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default MyDoctors;

