import React from 'react';
import { Page, UserRole } from '../types';
import { DashboardIcon, HealthMetricsIcon, MedicationsIcon, AppointmentsIcon, ChatIcon, SettingsIcon, HelpIcon, XIcon, UsersIcon, CalendarIcon, SparklesIcon } from './Icons';

interface SidebarProps {
  activePage: Page;
  setActivePage: (page: Page) => void;
  onClose?: () => void;
  userRole?: UserRole;
}

const patientMenuItems = [
  { name: Page.Dashboard, icon: DashboardIcon, label: 'Dashboard' },
  { name: Page.HealthMetrics, icon: HealthMetricsIcon, label: 'Health Metrics' },
  { name: Page.Medications, icon: MedicationsIcon, label: 'Medications' },
  { name: Page.Appointments, icon: AppointmentsIcon, label: 'Appointments' },
  { name: Page.MyDoctors, icon: ChatIcon, label: 'Messages' },
  { name: Page.ChatBot, icon: SparklesIcon, label: 'AI Assistant' },
];

const professionalMenuItems = [
    { name: Page.ProfessionalDashboard, icon: DashboardIcon, label: 'Dashboard' },
    { name: Page.PatientList, icon: UsersIcon, label: 'Patient List' },
    { name: Page.ProfessionalSchedule, icon: CalendarIcon, label: 'My Schedule' },
    { name: Page.ChatBot, icon: SparklesIcon, label: 'AI Assistant' },
];

const supportItems = [
  { name: Page.Settings, icon: SettingsIcon },
  { name: Page.HelpSupport, icon: HelpIcon },
];

const Sidebar: React.FC<SidebarProps> = ({ activePage, setActivePage, onClose, userRole = 'patient' }) => {
  const isProfessional = userRole === 'professional';
  const items = isProfessional ? professionalMenuItems : patientMenuItems;

  return (
    <aside className="w-64 h-full bg-white border-r border-boticare-gray-medium p-6 flex flex-col justify-between dark:bg-gray-800 dark:border-gray-700 overflow-y-auto">
      <div>
        <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold text-boticare-primary dark:text-white">Boticare <span className="text-[10px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded ml-1 align-middle uppercase">{isProfessional ? 'Pro' : ''}</span></h2>
            {onClose && (
                <button onClick={onClose} className="lg:hidden p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg">
                    <XIcon className="w-5 h-5 text-gray-500" />
                </button>
            )}
        </div>

        <p className="text-[10px] text-boticare-gray-dark font-bold uppercase tracking-wider mb-3 dark:text-gray-500">{isProfessional ? 'Practice Portal' : 'Patient Portal'}</p>
        <nav className="space-y-1">
          {items.map((item) => (
            <SidebarItem
              key={item.label}
              icon={item.icon}
              label={item.label}
              isActive={activePage === item.name || (item.name === Page.Appointments && activePage === Page.ScheduleAppointment)}
              onClick={() => setActivePage(item.name)}
            />
          ))}
        </nav>
      </div>

      <div className="mt-8">
        <p className="text-[10px] text-boticare-gray-dark font-bold uppercase tracking-wider mb-3 dark:text-gray-500">Preferences</p>
        <nav className="space-y-1">
          {supportItems.map((item) => (
            <SidebarItem
              key={item.name}
              icon={item.icon}
              label={item.name}
              isActive={activePage === item.name}
              onClick={() => setActivePage(item.name)}
            />
          ))}
        </nav>

        {!isProfessional && (
            <div className="mt-8 p-4 bg-boticare-blue/30 dark:bg-blue-900/20 rounded-xl border border-boticare-blue dark:border-blue-800/50">
                <p className="text-xs font-bold text-boticare-blue-dark dark:text-blue-300 mb-1">Emergency Help</p>
                <p className="text-[10px] text-gray-600 dark:text-gray-400 mb-3">Instant connection to our 24/7 care team.</p>
                <button className="w-full py-1.5 bg-boticare-blue-dark text-white text-[10px] font-bold rounded-lg hover:bg-blue-600 transition-colors">
                    Call Now
                </button>
            </div>
        )}
      </div>
    </aside>
  );
};

interface SidebarItemProps {
  icon: React.ComponentType<{ className?: string }>;
  label: string;
  isActive: boolean;
  onClick: () => void;
}

const SidebarItem: React.FC<SidebarItemProps> = ({ icon: Icon, label, isActive, onClick }) => {
  return (
    <a
      href="#"
      onClick={(e) => { e.preventDefault(); onClick(); }}
      className={`flex items-center space-x-3 px-4 py-2.5 rounded-lg transition-all duration-200 ${
        isActive
          ? 'bg-boticare-blue text-boticare-blue-dark dark:bg-blue-900/50 dark:text-blue-300 shadow-sm border border-blue-200 dark:border-blue-800'
          : 'text-boticare-gray-dark hover:bg-boticare-gray dark:text-gray-400 dark:hover:bg-gray-700 hover:translate-x-1'
      }`}
    >
      <Icon className={`w-5 h-5 ${isActive ? 'scale-110' : ''}`} />
      <span className="font-semibold text-sm">{label}</span>
    </a>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { Professional } from '../types';
import { PROFESSIONALS_DATA } from '../constants';
import { ChatIcon, SearchIcon, ArrowRightIcon } from './Icons';

interface MyDoctorsProps {
    onStartChat: (recipient: Professional) => void;
}

const MyDoctors: React.FC<MyDoctorsProps> = ({ onStartChat }) => {
    const [searchTerm, setSearchTerm] = useState('');

    // Simulate "Previous Chats" by taking a subset of professionals
    // In a real app, this would come from a `chat_sessions` table
    const previousChats = PROFESSIONALS_DATA.slice(0, 3).map((pro, index) => ({
        ...pro,
        lastMessage: index === 0 ? "Please update me on your blood pressure readings." : "The prescription has been sent to your pharmacy.",
        lastMessageTime: index === 0 ? "10:30 AM" : "Yesterday",
        unread: index === 0
    }));

    const filteredProfessionals = PROFESSIONALS_DATA.filter(pro => 
        pro.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        pro.specialty.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6 max-w-4xl mx-auto h-[calc(100vh-140px)] flex flex-col">
            <div className="flex-shrink-0">
                <h2 className="text-2xl font-black mb-1">Messages</h2>
                <p className="text-boticare-gray-dark dark:text-gray-400 mb-6">Connect with your care team securely.</p>

                {/* Search / Start New Chat Input */}
                <div className="relative mb-6">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                        <SearchIcon className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        placeholder="Start a new chat with a doctor..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-11 pr-4 py-4 bg-white dark:bg-gray-800 rounded-2xl border border-boticare-gray-medium dark:border-gray-700 shadow-sm focus:ring-2 focus:ring-blue-500 focus:outline-none text-base transition-all"
                    />
                </div>
            </div>

            {/* Content Area */}
            <div className="flex-grow overflow-y-auto pr-2 no-scrollbar space-y-6">

                {/* Search Results (if searching) */}
                {searchTerm && (
                    <div className="animate-fade-in">
                        <h3 className="text-xs font-black uppercase tracking-widest text-gray-500 mb-3 ml-1">Search Results</h3>
                        <div className="bg-white dark:bg-gray-800 rounded-2xl border border-boticare-gray-medium dark:border-gray-700 overflow-hidden">
                            {filteredProfessionals.length > 0 ? (
                                filteredProfessionals.map((pro) => (
                                    <button 
                                        key={pro.id}
                                        onClick={() => onStartChat(pro)}
                                        className="w-full flex items-center p-4 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors border-b border-gray-100 dark:border-gray-700 last:border-0 text-left"
                                    >
                                        <img src={pro.avatar} alt={pro.name} className="w-12 h-12 rounded-full border border-gray-200 dark:border-gray-600 mr-4" />
                                        <div className="flex-grow">
                                            <h4 className="font-bold text-gray-900 dark:text-white">{pro.name}</h4>
                                            <p className="text-sm text-blue-600 dark:text-blue-400 font-medium">{pro.specialty}</p>
                                        </div>
                                        <div className="p-2 bg-blue-50 dark:bg-blue-900/30 rounded-xl text-blue-600 dark:text-blue-400">
                                            <ChatIcon className="w-5 h-5" />
                                        </div>
                                    </button>
                                ))
                            ) : (
                                <div className="p-8 text-center text-gray-500">No doctors found matching "{searchTerm}"</div>
                            )}
                        </div>
                    </div>
                )}

                {/* Recent Conversations List */}
                {!searchTerm && (
                    <div>
                        <h3 className="text-xs font-black uppercase tracking-widest text-gray-500 mb-3 ml-1">Recent Conversations</h3>
                        <div className="bg-white dark:bg-gray-800 rounded-2xl border border-boticare-gray-medium dark:border-gray-700 overflow-hidden shadow-sm">
                            {previousChats.map((chat) => (
                                <button 
                                    key={chat.id}
                                    onClick={() => onStartChat(chat)}
                                    className="w-full flex items-center p-5 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors border-b border-gray-100 dark:border-gray-700 last:border-0 text-left group relative"
                                >
                                    <div className="relative mr-4">
                                        <img src={chat.avatar} alt={chat.name} className="w-14 h-14 rounded-full border-2 border-white dark:border-gray-600 shadow-sm" />
                                        {chat.unread && <div className="absolute top-0 right-0 w-3.5 h-3.5 bg-blue-500 border-2 border-white dark:border-gray-800 rounded-full"></div>}
                                    </div>
                                    <div className="flex-grow min-w-0 pr-4">
                                        <div className="flex justify-between items-baseline mb-1">
                                            <h4 className={`text-base ${chat.unread ? 'font-black text-gray-900 dark:text-white' : 'font-bold text-gray-700 dark:text-gray-200'}`}>{chat.name}</h4>
                                            <span className={`text-xs ${chat.unread ? 'font-bold text-blue-600' : 'text-gray-400'}`}>{chat.lastMessageTime}</span>
                                        </div>
                                        <p className={`text-sm truncate ${chat.unread ? 'font-semibold text-gray-800 dark:text-gray-300' : 'text-gray-500'}`}>
                                            {chat.lastMessage}
                                        </p>
                                    </div>
                                    <ArrowRightIcon className="w-5 h-5 text-gray-300 group-hover:text-blue-500 transition-colors opacity-0 group-hover:opacity-100" />
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default MyDoctors;

import React, { useState, useEffect, useRef } from 'react';
import { Patient, Professional } from '../types';
import { MicIcon, MicOffIcon, VideoOnIcon, VideoOffIcon, EndCallIcon, UserIcon, AlertIcon } from './Icons';
import FeedbackModal from './FeedbackModal';

interface VideoCallProps {
  professional?: Professional | null;
  patient?: Patient | null;
  isProfessionalView?: boolean;
  onEndCall: () => void;
}

const VideoCall: React.FC<VideoCallProps> = ({ professional, patient, isProfessionalView, onEndCall }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isCameraOn, setIsCameraOn] = useState(true);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [connectionState, setConnectionState] = useState<'connecting' | 'connected' | 'failed'>('connecting');
  const [mediaError, setMediaError] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);
  const userVideoRef = useRef<HTMLVideoElement>(null);
  const userStreamRef = useRef<MediaStream | null>(null);

  // Initialize Local Media Stream
  useEffect(() => {
    let mounted = true;

    const startStream = async () => {
      try {
        // Explicitly request constraints to improve compatibility on mobile/cloud run
        const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { 
                width: { ideal: 1280 },
                height: { ideal: 720 },
                facingMode: 'user'
            }, 
            audio: {
                echoCancellation: true,
                noiseSuppression: true
            } 
        });

        if (mounted) {
            userStreamRef.current = stream;
            if (userVideoRef.current) {
                userVideoRef.current.srcObject = stream;
                // Ensure video plays (some browsers require explicit play)
                await userVideoRef.current.play().catch(e => console.error("Video play failed", e));
            }
        }
      } catch (err: any) {
        console.error("Media Error:", err);
        if (mounted) {
            setMediaError("Unable to access camera or microphone. Please ensure you have granted permissions and are using HTTPS.");
            setConnectionState('failed');
        }
      }
    };

    startStream();

    // Cleanup function to stop tracks when component unmounts
    return () => {
      mounted = false;
      if (userStreamRef.current) {
        userStreamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  // Simulate Connection Establishment
  useEffect(() => {
    if (mediaError) return;

    // Simulate a connection delay common in real WebRTC
    const connectTimer = setTimeout(() => {
        setConnectionState('connected');
    }, 2500);

    return () => clearTimeout(connectTimer);
  }, [mediaError]);

  // Timer for call duration
  useEffect(() => {
    if (connectionState !== 'connected') return;
    const timerId = setInterval(() => setElapsedTime(prev => prev + 1), 1000);
    return () => clearInterval(timerId);
  }, [connectionState]);

  const toggleMic = () => { 
      if (userStreamRef.current) { 
          userStreamRef.current.getAudioTracks().forEach(t => t.enabled = !t.enabled); 
          setIsMuted(!isMuted); 
      } 
  };

  const toggleCamera = () => { 
      if (userStreamRef.current) { 
          userStreamRef.current.getVideoTracks().forEach(t => t.enabled = !t.enabled); 
          setIsCameraOn(!isCameraOn); 
      } 
  };

  const handleEndCallClick = () => { 
      if (userStreamRef.current) {
          userStreamRef.current.getTracks().forEach(t => t.stop()); 
      }
      setShowFeedback(true); 
  };

  const targetName = isProfessionalView ? (patient?.name || 'Patient') : (professional?.name || 'Practitioner');
  const targetAvatar = isProfessionalView ? (patient?.avatar || `https://i.pravatar.cc/150?u=patient`) : (professional?.avatar || 'https://i.pravatar.cc/150?u=pro');

  return (
    <div className="animate-fade-in space-y-4 pb-10 h-[calc(100vh-140px)] flex flex-col">
        {showFeedback && <FeedbackModal isOpen onClose={() => onEndCall()} onSubmit={() => onEndCall()} source="video_call" />}

        {/* Call Header */}
        <div className="flex items-center space-x-4 p-4 bg-white dark:bg-gray-800 rounded-2xl border border-boticare-gray-medium dark:border-gray-700 shadow-sm flex-shrink-0">
            {connectionState === 'connected' ? (
                <span className="relative flex h-3 w-3">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
                </span>
            ) : (
                <div className="w-3 h-3 rounded-full bg-yellow-400 animate-pulse"></div>
            )}

            <span className={`text-[10px] font-black px-2.5 py-1 rounded-lg uppercase tracking-widest ${connectionState === 'connected' ? 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300' : 'bg-yellow-100 text-yellow-800'}`}>
                {connectionState === 'connected' ? 'Live Encrypted' : 'Connecting...'}
            </span>

            <h2 className="text-lg font-bold truncate">Session with {targetName}</h2>
            <span className="text-sm font-mono font-bold text-blue-600 ml-auto">{Math.floor(elapsedTime / 60)}:{String(elapsedTime % 60).padStart(2, '0')}</span>
        </div>

        {/* Main Video Area */}
        <div className="relative flex-grow bg-gray-900 rounded-3xl overflow-hidden shadow-2xl group border border-gray-800">

            {/* Remote Video (Simulated for this demo) */}
            <div className="absolute inset-0 flex items-center justify-center">
                {connectionState === 'connected' ? (
                    <img src={targetAvatar} className="w-full h-full object-cover opacity-80" alt={targetName} />
                ) : connectionState === 'failed' ? (
                    <div className="text-center p-8 space-y-4">
                        <AlertIcon className="w-16 h-16 text-red-500 mx-auto" />
                        <p className="text-white font-bold text-lg">{mediaError || "Connection Failed"}</p>
                    </div>
                ) : (
                    <div className="flex flex-col items-center space-y-4">
                        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                        <p className="text-white font-bold tracking-wider uppercase text-sm">Establishing Secure Connection...</p>
                    </div>
                )}
            </div>

            {/* Call Info Overlay */}
            {connectionState === 'connected' && (
                <div className="absolute bottom-6 left-6 text-white bg-black/50 backdrop-blur-md px-4 py-2 rounded-xl border border-white/20 z-10">
                    <p className="font-bold text-sm">{targetName}</p>
                    <p className="text-[10px] opacity-70 uppercase tracking-wider">Remote Stream • HD</p>
                </div>
            )}

            {/* Local User Video (PIP) */}
            <div className="absolute top-6 right-6 w-32 h-48 md:w-48 md:h-32 bg-gray-800 rounded-2xl overflow-hidden border-2 border-white/30 shadow-2xl z-20 transition-all hover:scale-105">
                <video 
                    ref={userVideoRef} 
                    autoPlay 
                    muted 
                    playsInline 
                    className={`w-full h-full object-cover transform scale-x-[-1] ${isCameraOn ? 'block' : 'hidden'}`} 
                />
                 {!isCameraOn && <div className="w-full h-full flex items-center justify-center bg-gray-700"><UserIcon className="w-12 h-12 text-gray-500" /></div>}
                <div className="absolute bottom-2 left-2 text-[10px] font-bold text-white bg-black/50 px-2 py-0.5 rounded-lg">You</div>
            </div>

            {/* Controls */}
            <div className="absolute bottom-8 left-0 right-0 flex items-center justify-center space-x-6 z-30 transition-all duration-300">
                <button onClick={toggleMic} className={`p-4 rounded-full transition-all shadow-lg hover:scale-110 active:scale-95 ${isMuted ? 'bg-white text-red-600' : 'bg-white/20 backdrop-blur-md text-white hover:bg-white/30 border border-white/20'}`}>
                    {isMuted ? <MicOffIcon className="w-6 h-6" /> : <MicIcon className="w-6 h-6" />}
                </button>

                <button onClick={handleEndCallClick} className="w-16 h-16 rounded-full bg-red-600 hover:bg-red-700 text-white flex items-center justify-center shadow-xl hover:scale-110 active:scale-95 transition-all">
                    <EndCallIcon className="w-8 h-8" />
                </button>

                <button onClick={toggleCamera} className={`p-4 rounded-full transition-all shadow-lg hover:scale-110 active:scale-95 ${!isCameraOn ? 'bg-white text-red-600' : 'bg-white/20 backdrop-blur-md text-white hover:bg-white/30 border border-white/20'}`}>
                    {!isCameraOn ? <VideoOffIcon className="w-6 h-6" /> : <VideoOnIcon className="w-6 h-6" />}
                </button>
            </div>
        </div>
    </div>
  );
};

export default VideoCall;

