{
  "name": "Boticare Health App",
  "description": "A modern, AI-powered healthcare dashboard for patients to manage appointments, medications, health metrics, and chat with an AI assistant. This application provides a comprehensive overview of a patient's health journey in a clean and intuitive interface.",
  "requestFramePermissions": [
    "camera",
    "microphone",
    "geolocation"
  ]
}

import React from 'react';

export type UserRole = 'patient' | 'professional';
export type ProfessionalTitle = 'Doctor' | 'Pharmacist';

export enum Page {
  // Patient Pages
  Dashboard = 'Dashboard',
  HealthMetrics = 'Health Metrics',
  Medications = 'Medications',
  Appointments = 'Appointments',
  MyDoctors = 'My Doctors',
  ChatBot = 'Chat Bot',
  Settings = 'Settings',
  HelpSupport = 'Help & Support',
  VideoCall = 'Video Call',
  ScheduleAppointment = 'Schedule Appointment',

  // Professional Pages
  ProfessionalDashboard = 'Dashboard ',
  PatientList = 'Patient List',
  ProfessionalSchedule = 'My Schedule',
  PersonalChat = 'Personal Chat',
}

export enum AppointmentStatus {
  Upcoming = 'Upcoming',
  Completed = 'Completed',
  Canceled = 'Canceled',
  Rescheduled = 'Rescheduled',
}

export enum AppointmentType {
    CheckUp = 'Check-up',
    FollowUp = 'Follow-up',
    Consultation = 'Consultation',
    Initial = 'Initial',
}

export interface Document {
    id: string;
    name: string;
    type: 'pdf' | 'jpg' | 'png';
    date: string;
}

export interface Appointment {
  id: number;
  doctorName: string; 
  patientName: string;
  specialty: string;
  status: AppointmentStatus;
  type: AppointmentType;
  date: string;
  time: string;
  duration: number;
  notes: string;
  avatar: string; 
  summary?: string;
  documents?: Document[];
}

export interface Medication {
  id: number;
  name: string;
  dosage: string;
  percentageLeft: number;
  nextDose: string;
  isTaken: boolean;
  refillNeeded?: string;
}

export interface PrescriptionRefillRequest {
    id: number;
    patientName: string;
    drugName: string;
    timeAgo: string;
}

// Added HealthMetricStatus enum
export enum HealthMetricStatus {
  Normal = 'Normal',
  Warning = 'Warning',
}

// Added HistoricalDataPoint interface
export interface HistoricalDataPoint {
  date: string;
  value: number;
}

// Updated HealthMetric to use enums and interfaces
export interface HealthMetric {
  id: string;
  name: string;
  value: string;
  unit: string;
  status: HealthMetricStatus;
  trend: string;
  trendDirection: 'up' | 'down' | 'stable';
  history: HistoricalDataPoint[];
}

// Added AlertLevel enum
export enum AlertLevel {
  Low = 'Low',
  Medium = 'Medium',
  High = 'High',
}

// Added HealthAlert interface
export interface HealthAlert {
  id: number;
  title: string;
  description: string;
  level: AlertLevel;
  time: string;
  icon: React.ComponentType<{ className?: string }>;
}

export interface Professional {
    id: number;
    name: string;
    specialty: string;
    avatar: string;
    rating: number;
    // Added for MyDoctors component for displaying chat history
    lastMessage?: string; 
    lastMessageTime?: string;
    unread?: boolean;
}

export interface Patient {
    id: string;
    name: string;
    age: number;
    gender: string;
    condition: string;
    status: 'Stable' | 'Critical' | 'Recovering';
    lastVisit: string;
    avatar: string;
}

export interface ChatMessage {
  sender: 'user' | 'ai' | 'professional' | 'patient';
  text: string;
  imageUrl?: string;
  sources?: Array<{ title: string; uri: string }>;
  timestamp: string;
  isRead?: boolean; // Added read status for messages
}

export interface UserProfile {
    name: string;
    email: string;
    phone: string;
    avatar: string;
    role?: UserRole;
    professionalTitle?: ProfessionalTitle; // Now can be 'Doctor' or 'Pharmacist'
    specialty?: string;
}

export interface BoticareNotification {
    id: string;
    message: string;
    type: 'info' | 'success' | 'warning';
    timestamp: string;
    read: boolean;
}

// Added VideoCallRecord interface
export interface VideoCallRecord {
    id: string;
    professionalName: string;
    professionalAvatar: string;
    date: string;
    time: string;
    duration: string;
}

// Added Symptom interface
export interface Symptom {
    id: string;
    name: string;
    date: string;
    severity: 'Mild' | 'Moderate' | 'Severe';
    description: string;
}

// Added NewAppointmentDetails interface
export interface NewAppointmentDetails {
    consultationType: 'video' | 'chat';
    professional: Professional;
    date: string;
    time: string;
    notes: string;
}

-- Profiles table with role-based fields
create table public.profiles (
  id uuid references auth.users on delete cascade not null primary key,
  updated_at timestamp with time zone,
  name text,
  email text,
  avatar_url text,
  phone text,
  role text default 'patient', -- 'patient' or 'professional'
  professional_title text, -- 'Doctor' or 'Pharmacist'
  specialty text
);

-- Appointments and Clinical Schedule
create table public.appointments (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references public.profiles(id) not null,
  professional_id uuid references public.profiles(id) not null,
  scheduled_at timestamp with time zone not null,
  status text default 'upcoming', -- upcoming, completed, canceled, rescheduled
  type text not null, -- check-up, follow-up, etc.
  duration_minutes integer default 30,
  notes text,
  summary text, -- AI-generated or doctor-written summary
  created_at timestamp with time zone default now()
);

-- Video Call Sessions Log
create table public.video_call_sessions (
  id uuid default gen_random_uuid() primary key,
  appointment_id uuid references public.appointments(id) not null,
  started_at timestamp with time zone default now(),
  ended_at timestamp with time zone,
  duration_seconds integer,
  recording_url text,
  quality_rating integer
);

-- Prescription Refill Requests
create table public.requested_drug_refills (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references public.profiles(id) not null,
  professional_id uuid references public.profiles(id),
  drug_name text not null,
  dosage text not null,
  status text default 'pending', -- pending, approved, declined
  requested_at timestamp with time zone default now(),
  responded_at timestamp with time zone,
  pharmacist_notes text
);

-- Patient AI Chatbot Sessions
create table public.patient_chatbot_sessions (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references public.profiles(id) not null,
  transcript jsonb, -- array of messages
  last_activity timestamp with time zone default now()
);

-- Personalized Secure Messaging (HP <-> Patient)
create table public.personalized_chat_messages (
  id uuid default gen_random_uuid() primary key,
  sender_id uuid references public.profiles(id) not null,
  recipient_id uuid references public.profiles(id) not null,
  content text not null,
  is_read boolean default false,
  sent_at timestamp with time zone default now()
);

-- Security Policies (RLS)
alter table public.profiles enable row level security;
alter table public.appointments enable row level security;
alter table public.personalized_chat_messages enable row level security;
alter table public.requested_drug_refills enable row level security;

-- Simple policy examples
create policy "Users can see their own data" on public.profiles for select using (auth.uid() = id);
create policy "HPs can see assigned appointments" on public.appointments for select using (auth.uid() = professional_id);
create policy "Patients can see their own refills" on public.requested_drug_refills for select using (auth.uid() = patient_id);
create policy "HPs can see patients they interact with" on public.profiles for select using (
  id IN (SELECT patient_id FROM public.appointments WHERE professional_id = auth.uid()) OR
  id IN (SELECT patient_id FROM public.requested_drug_refills WHERE professional_id = auth.uid()) OR
  id IN (SELECT recipient_id FROM public.personalized_chat_messages WHERE sender_id = auth.uid())
);
create policy "Patients can see their HPs" on public.profiles for select using (
  id IN (SELECT professional_id FROM public.appointments WHERE patient_id = auth.uid()) OR
  id IN (SELECT professional_id FROM public.requested_drug_refills WHERE patient_id = auth.uid()) OR
  id IN (SELECT sender_id FROM public.personalized_chat_messages WHERE recipient_id = auth.uid())
);
create policy "Everyone can create profiles" on public.profiles for insert with check (true);
create policy "Users can update their own profile" on public.profiles for update using (auth.uid() = id);

create policy "HPs can manage their own appointments" on public.appointments
  for all using (professional_id = auth.uid()) with check (professional_id = auth.uid());
create policy "Patients can view their appointments" on public.appointments
  for select using (patient_id = auth.uid());
create policy "Patients can create their own appointments" on public.appointments
  for insert with check (patient_id = auth.uid());

create policy "Users can send and receive personal messages" on public.personalized_chat_messages
  for all using (sender_id = auth.uid() OR recipient_id = auth.uid()) with check (sender_id = auth.uid());

create policy "HPs can manage refill requests for their patients" on public.requested_drug_refills
  for all using (professional_id = auth.uid()) with check (professional_id = auth.uid());
create policy "Patients can view and create their own refill requests" on public.requested_drug_refills
  for all using (patient_id = auth.uid()) with check (patient_id = auth.uid());

create policy "Patients can manage their chatbot sessions" on public.patient_chatbot_sessions
  for all using (patient_id = auth.uid()) with check (patient_id = auth.uid());

import React from 'react';

type IconProps = {
  className?: string;
