}

const Settings: React.FC<SettingsProps> = ({ userProfile, onProfileUpdate, isDarkMode, setIsDarkMode }) => {
    const [activeView, setActiveView] = useState<SettingView>('main');
    const [toast, setToast] = useState<string | null>(null);
    const isProfessional = userProfile.role === 'professional';

    const handleSave = (updated: UserProfile) => { 
        onProfileUpdate(updated); 
        setToast("Settings updated successfully"); 
    };

    const renderView = () => {
        switch (activeView) {
            case 'profile': return <ProfileSettings profile={userProfile} onSave={handleSave} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
