// --- Supabase Interaction Functions ---

export const getProfessionalAvailability = async (professionalId: string): Promise<AvailabilitySlot[]> => {
    if (!supabase) return [];
    const { data, error } = await supabase
        .from('professional_availability')
        .select('*')
        .eq('professional_id', professionalId);

    if (error) {
        console.error("Error fetching professional availability:", error);
        return [];
    }
    return data.map(slot => ({
        id: slot.id,
        dayOfWeek: slot.day_of_week,
        startTime: slot.start_time,
        endTime: slot.end_time,
        isEnabled: true, // Assuming fetched slots are enabled
    }));
};

export const saveProfessionalAvailability = async (professionalId: string, slots: AvailabilitySlot[]): Promise<boolean> => {
    if (!supabase) return false;

    // First, delete existing availability for the professional to avoid conflicts
    const { error: deleteError } = await supabase
        .from('professional_availability')
        .delete()
        .eq('professional_id', professionalId);

    if (deleteError) {
        console.error("Error deleting old availability:", deleteError);
        return false;
    }

    const enabledSlotsToInsert = slots
        .filter(slot => slot.isEnabled)
        .map(slot => ({
            professional_id: professionalId,
            day_of_week: slot.dayOfWeek,
            start_time: slot.startTime,
            end_time: slot.endTime,
        }));

    if (enabledSlotsToInsert.length === 0) return true; // No slots to insert, consider it a success.

    const { error: insertError } = await supabase
        .from('professional_availability')
        .insert(enabledSlotsToInsert);

    if (insertError) {
        console.error("Error saving professional availability:", insertError);
        return false;
    }
    return true;
};

export const updateRefillRequest = async (requestId: number, updates: {drugName?: string, dosage?: string, status?: 'pending' | 'approved' | 'declined'}): Promise<boolean> => {
    if (!supabase) return false;

    const dbUpdates: { drug_name?: string, dosage?: string, status?: string, responded_at?: string } = {};
    if (updates.drugName !== undefined) dbUpdates.drug_name = updates.drugName;
    if (updates.dosage !== undefined) dbUpdates.dosage = updates.dosage;
    if (updates.status !== undefined) {
        dbUpdates.status = updates.status;
        dbUpdates.responded_at = new Date().toISOString(); // Set response time on status change
    }

    const { error } = await supabase
        .from('requested_drug_refills')
        .update(dbUpdates)
        .eq('id', requestId);

    if (error) {
        console.error("Error updating refill request:", error);
        return false;
    }
    return true;
};

export const logVideoCallSession = async (
    sessionId: string,
    appointmentId: string,
    professionalId: string,
    patientId: string,
    startTime: string,
    endTime: string,
    durationSeconds: number,
    recordingUrl?: string
): Promise<boolean> => {
    if (!supabase) return false;

    const { error } = await supabase
        .from('video_call_sessions')
        .insert({
            id: sessionId,
            appointment_id: appointmentId,
            professional_id: professionalId, // Assuming professional_id column exists
            patient_id: patientId, // Assuming patient_id column exists
            started_at: startTime,
            ended_at: endTime,
            duration_seconds: durationSeconds,
            recording_url: recordingUrl,
        });

    if (error) {
        console.error("Error logging video call session:", error);
        return false;
    }
    return true;
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProfessionalDashboard from './components/ProfessionalDashboard';
import PatientList from './components/PatientList';
import HealthMetrics from './components/HealthMetrics';
import Medications from './components/Medications';
import Appointments from './components/Appointments';
import MyDoctors from './components/MyDoctors';
import ChatBot from './components/Community';
import PersonalChat from './components/PersonalChat';
import Settings from './components/Settings';
import HelpSupport from './components/HelpSupport';
import VideoCall from './components/VideoCall';
import Auth from './components/Auth';
import { supabase } from './services/supabaseClient';
import { Page, Professional, UserProfile, UserRole, BoticareNotification, Patient, ProfessionalTitle, Appointment } from './types';

const App: React.FC = () => {
  const [session, setSession] = useState<any | null>(null);
  const [userRole, setUserRole] = useState<UserRole>('patient');
  const [activePage, setActivePage] = useState<Page>(Page.Dashboard);
  const [videoCallProfessional, setVideoCallProfessional] = useState<Professional | null>(null);
  const [videoCallPatient, setVideoCallPatient] = useState<Patient | null>(null);
  // FIX: Update the type of chatRecipient to include Professional.
  const [chatRecipient, setChatRecipient] = useState<Patient | Professional | UserProfile | null>(null);
  const [videoCallAppointment, setVideoCallAppointment] = useState<Appointment | null>(null); // New state for appointment object
  const [notifications, setNotifications] = useState<BoticareNotification[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Loading...',
    email: '',
    phone: '',
    avatar: 'https://i.pravatar.cc/150?u=placeholder',
    professionalTitle: 'Doctor', // Default for professionals
    specialty: 'General Practice' // Default for professionals
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('boticare-dark-mode');
    return saved ? saved === 'true' : window.matchMedia?.('(prefers-color-scheme: dark)').matches;
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) { root.classList.add('dark'); } else { root.classList.remove('dark'); }
    localStorage.setItem('boticare-dark-mode', String(isDarkMode));
  }, [isDarkMode]);

  useEffect(() => {
    if (!supabase) return;
    const savedRole = localStorage.getItem('boticare-user-role') as UserRole;
    if (savedRole) {
        setUserRole(savedRole);
        setActivePage(savedRole === 'professional' ? Page.ProfessionalDashboard : Page.Dashboard);
    }
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    if (!supabase) return;
    try {
        const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single();
        if (error) throw error;
        if (data) {
            setUserProfile({
                name: data.name || 'User',
                email: data.email || '',
                phone: data.phone || '',
                avatar: data.avatar_url || 'https://i.pravatar.cc/150?u=default',
                role: (data.role as UserRole) || 'patient', // Ensure role from DB is used
                professionalTitle: (data.professional_title as ProfessionalTitle) || 'Doctor',
                specialty: data.specialty || 'General Practice',
                supabaseId: data.id // Store supabaseId in userProfile
            });
            // Update the userRole state based on fetched profile
            if (data.role !== userRole) {
                setUserRole(data.role as UserRole);
                setActivePage(data.role === 'professional' ? Page.ProfessionalDashboard : Page.Dashboard);
            }
        }
    } catch (err) { console.error("Profile fetch error", err); }
  };

  const handleUpdateProfile = async (updatedProfile: UserProfile) => {
    if (!session || !supabase) return;
    try {
        const { error } = await supabase.from('profiles')
            .update({ 
                name: updatedProfile.name, 
                phone: updatedProfile.phone, 
                avatar_url: updatedProfile.avatar,
                professional_title: updatedProfile.professionalTitle,
                specialty: updatedProfile.specialty
            })
            .eq('id', session.user.id);
        if (error) throw error;
        setUserProfile(updatedProfile); // Update local state after successful DB update
        console.log("Profile updated successfully!");
    } catch (error) {
        console.error("Error updating profile:", error);
    }
  };


  const handleAddNotification = (msg: string) => {
      const newNotif: BoticareNotification = {
          id: Date.now().toString(),
          message: msg,
          type: 'success',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          read: false
      };
      setNotifications(prev => [newNotif, ...prev]);
  };

  const handleMarkNotificationsAsRead = () => {
      setTimeout(() => {
          setNotifications(prev => prev.map(n => ({...n, read: true})));
      }, 2000);
  };

  const handleStartVideoCall = (appointment: Appointment, professional: Professional | null = null, patient: Patient | null = null) => {
    setVideoCallAppointment(appointment);
    setVideoCallProfessional(professional);
    setVideoCallPatient(patient);
    setActivePage(Page.VideoCall);
  };


  const startPersonalChat = (recipient: Patient | Professional | UserProfile) => {
      setChatRecipient(recipient);
      setActivePage(Page.PersonalChat);
  };

  if (!session) {
    return <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200"><Auth /></div>;
  }

  // Separate rendering logic for Patient and Professional UIs
  const renderPatientPage = () => {
    switch (activePage) {
        case Page.Dashboard: return <Dashboard />;
        case Page.HealthMetrics: return <HealthMetrics setActivePage={setActivePage} />;
        case Page.Medications: return <Medications />;
        case Page.Appointments: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={handleStartVideoCall} />;
        case Page.MyDoctors: return <MyDoctors onStartChat={startPersonalChat} />;
        case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
        case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.MyDoctors)} />;
        case Page.Settings: return <Settings userProfile={userProfile} onProfileUpdate={handleUpdateProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
        case Page.HelpSupport: return <HelpSupport />;
        // Pass the appointment object to VideoCall
        case Page.VideoCall: return <VideoCall appointment={videoCallAppointment} professional={videoCallProfessional} onEndCall={() => setActivePage(Page.Appointments)} />;
        default: return <Dashboard />;
    }
  };

  const renderProfessionalPage = () => {
    switch (activePage) {
        case Page.ProfessionalDashboard: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
        case Page.PatientList: return <PatientList setActivePage={setActivePage} onStartChat={startPersonalChat} />;
        case Page.ProfessionalSchedule: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={handleStartVideoCall} isProfessionalView userRole={userRole} />;
        case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
        case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.PatientList)} />;
        case Page.Settings: return <Settings userProfile={userProfile} onProfileUpdate={handleUpdateProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
        case Page.HelpSupport: return <HelpSupport />;
        // Pass the appointment object to VideoCall
        case Page.VideoCall: return <VideoCall appointment={videoCallAppointment} professional={videoCallProfessional} patient={videoCallPatient} isProfessionalView onEndCall={() => setActivePage(Page.ProfessionalSchedule)} />;
        default: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
    }
  };

  return (
    <div className="bg-boticare-gray text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
      <Layout 
        activePage={activePage} 
        setActivePage={setActivePage} 
        userProfile={userProfile} 
        userRole={userRole}
        notifications={notifications}
        onMarkNotificationsAsRead={handleMarkNotificationsAsRead}
      >
        {userRole === 'professional' ? renderProfessionalPage() : renderPatientPage()}
      </Layout>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA, VIDEO_CALL_HISTORY_DATA, MOCK_PATIENTS } from '../constants';
import AppointmentCard from './AppointmentCard';
import BookAppointmentForm from './ScheduleAppointmentForm';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import CancelAppointmentModal from './CancelAppointmentModal';
import { Appointment, AppointmentStatus, Page, Professional, NewAppointmentDetails, AppointmentType, UserRole, Patient } from '../types';
import { PlusIcon, SearchIcon, VideoIcon, ClockIcon, FilterIcon, CalendarIcon, FileIcon, ChevronRightIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const STATUS_TABS = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
  'Call History',
  'History'
];

const TYPE_FILTERS = ['All', ...Object.values(AppointmentType)];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  // Updated signature to pass the full appointment and optionally professional/patient
  setVideoCallProfessional: (appointment: Appointment, professional?: Professional | null, patient?: Patient | null) => void;
  defaultToScheduling?: boolean;
  isProfessionalView?: boolean;
  userRole?: UserRole;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false, isProfessionalView, userRole }) => {
  const [activeTab, setActiveTab] = useState<string>(AppointmentStatus.Upcoming);
  const [activeType, setActiveType] = useState<string>('All');
  const [isScheduling, setIsScheduling] = useState(defaultToScheduling);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [appointmentToReschedule, setAppointmentToReschedule] = useState<Appointment | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [cancelingAppointment, setCancelingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => {
        if (activeTab === 'History') return appointment.status === AppointmentStatus.Completed;
        return appointment.status === activeTab;
    })
    .filter((appointment) => {
        if (activeType === 'All') return true;
        return appointment.type === activeType;
    })
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        const targetSearchName = isProfessionalView ? appointment.patientName : appointment.doctorName;
        return (
            targetSearchName.toLowerCase().includes(lowerCaseQuery) ||
            appointment.specialty.toLowerCase().includes(lowerCaseQuery)
        );
    });

  const handleBookSuccess = (details: NewAppointmentDetails) => {
    // Mock userProfile.supabaseId for now, will come from actual user profile
    const mockUserSupabaseId = userRole === 'patient' ? 'patient1_supabase_id' : 'pro1_supabase_id';

    const newAppointment: Appointment = {
        id: Math.max(...appointments.map(a => a.id), 0) + 1,
        doctorName: details.professional.name,
        specialty: details.professional.specialty,
        status: AppointmentStatus.Upcoming,
        type: AppointmentType.Consultation,
        date: details.date,
        time: details.time,
        duration: 30,
        notes: details.notes || `Consultation for ${details.professional.specialty}`,
        avatar: details.professional.avatar,
        patientName: 'Jane Doe', // Assuming current patient is Jane Doe for this mock
        patientId: mockUserSupabaseId, // Link to current user's (patient) supabase ID
        professionalId: details.professional.supabaseId, // Link to selected professional's supabase ID
        documents: []
    };

    setAppointments(prev => [newAppointment, ...prev]);
    setIsScheduling(false);
    setActiveTab(AppointmentStatus.Upcoming);
    setToastMessage('Appointment scheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRescheduleConfirm = (appointmentId: number, details: NewAppointmentDetails) => {
    setAppointments(prev => 
      prev.map(app => 
        app.id === appointmentId 
          ? { 
              ...app, 
              status: AppointmentStatus.Rescheduled, 
              date: details.date, 
              time: details.time,
              notes: details.notes,
            }
          : app
      )
    );
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    setActiveTab(AppointmentStatus.Rescheduled);
    setToastMessage('Appointment rescheduled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleStartReschedule = (appointment: Appointment) => {
    setAppointmentToReschedule(appointment);
    setIsScheduling(true);
  };

  const handleCancelAppointment = (appointmentId: number) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId
          ? { ...app, status: AppointmentStatus.Canceled }
          : app
      )
    );
    setActiveTab(AppointmentStatus.Canceled);
    setToastMessage('Appointment canceled successfully!');
    setTimeout(() => setToastMessage(null), 3000);
  };

  const handleRequestCancel = (appointment: Appointment) => {
    setCancelingAppointment(appointment);
  };

  const handleCancelScheduling = () => {
    setIsScheduling(false);
    setAppointmentToReschedule(null);
    if (defaultToScheduling) {
        setActivePage(Page.HealthMetrics);
    }
  }

  const handleJoinVideo = (appointment: Appointment) => {
    const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
    let patient: Patient | null = null;

    if (isProfessionalView) {
        // In professional view, the 'patientName' in appointment is the actual patient
        patient = MOCK_PATIENTS.find(p => p.name === appointment.patientName) || null;
    } else {
        // In patient view, the current user is the patient
        // For mock purposes, we'll assume a generic patient profile
        patient = MOCK_PATIENTS.find(p => p.name === appointment.patientName) || null;
    }

    // Pass the full appointment object, and the identified professional/patient for context
    setVideoCallProfessional(appointment, professional, patient);
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    if (appointment.summary) {
      setSummaryModalState({ appointment, summary: appointment.summary, isLoading: false });
      return;
    }
    const summaryText = await getAppointmentSummary(appointment);
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointment.id ? { ...app, summary: summaryText } : app
      )
    );
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  const handleCloseSummaryModal = () => {
    setSummaryModalState({ appointment: null, summary: '', isLoading: false });
  };

  const handleOpenEditNotes = (appointment: Appointment) => {
    setEditingAppointment(appointment);
  };

  const handleViewDetails = (appointment: Appointment) => {
      setDetailsAppointment(appointment);
  };

  const handleCloseEditNotes = () => {
    setEditingAppointment(null);
  };

  const handleSaveNotes = (appointmentId: number, newNotes: string) => {
    setAppointments(prev =>
      prev.map(app =>
        app.id === appointmentId ? { ...app, notes: newNotes } : app
      )
