interface AvailabilitySettingsProps {
    userProfile: UserProfile;
    onSave: (message: string, type: 'success') => void;
}

const AvailabilitySettings: React.FC<AvailabilitySettingsProps> = ({ userProfile, onSave }) => {
    const daysOfWeek = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
    const [availability, setAvailability] = useState<Record<string, AvailabilitySlot>>({});
    const [isLoading, setIsLoading] = useState(false);

    // Initialize availability state
    useEffect(() => {
        if (userProfile.supabaseId) {
            const fetchAvailability = async () => {
                setIsLoading(true);
                const fetchedSlots = await getProfessionalAvailability(userProfile.supabaseId as string);
                const initialAvailability: Record<string, AvailabilitySlot> = {};
                daysOfWeek.forEach(day => {
                    const existing = fetchedSlots.find(slot => slot.dayOfWeek === day);
                    initialAvailability[day] = existing || { dayOfWeek: day, startTime: '09:00', endTime: '17:00', isEnabled: false };
                });
                setAvailability(initialAvailability);
                setIsLoading(false);
            };
            fetchAvailability();
        }
    }, [userProfile.supabaseId]);

    const handleToggleDay = (day: string, enabled: boolean) => {
        setAvailability(prev => ({
            ...prev,
            [day]: { ...prev[day], isEnabled: enabled }
        }));
    };

    const handleTimeChange = (day: string, field: 'startTime' | 'endTime', value: string) => {
        setAvailability(prev => ({
            ...prev,
            [day]: { ...prev[day], [field]: value }
        }));
    };

    const handleSaveAvailability = async () => {
        if (!userProfile.supabaseId) return;

        setIsLoading(true);
        const slotsToSave = Object.values(availability);
        const success = await saveProfessionalAvailability(userProfile.supabaseId, slotsToSave);
        if (success) {
            onSave("Availability updated successfully!", 'success');
        } else {
            onSave("Failed to update availability. Please try again.", 'success'); // Using success toast for now, ideally an error type
        }
        setIsLoading(false);
    };

    return (
        <div className="space-y-6">
            <h3 className="text-xl font-bold mb-2">Consultation Availability</h3>
            <div className="p-6 border border-boticare-gray-medium rounded-lg dark:border-gray-700">
                <h4 className="font-bold mb-4">Set Your Weekly Schedule</h4>
                {isLoading ? (
                    <div className="flex items-center justify-center py-10">
                        <div className="w-8 h-8 border-4 border-b-2 border-blue-500 rounded-full animate-spin"></div>
                        <p className="ml-3 text-gray-500 dark:text-gray-400">Loading availability...</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {daysOfWeek.map(day => (
                            <div key={day} className="flex flex-col md:flex-row items-start md:items-center justify-between p-3 bg-boticare-gray dark:bg-gray-700 rounded-lg">
                                <div className="flex items-center space-x-3 mb-3 md:mb-0">
                                    <ToggleSwitch
                                        id={`toggle-${day}`}
                                        enabled={availability[day]?.isEnabled || false}
                                        onChange={(enabled) => handleToggleDay(day, enabled)}
                                        label={''} // Label is rendered separately
                                    />
                                    <span className="font-bold text-gray-800 dark:text-gray-100 w-24">{day}</span>
                                </div>
                                {availability[day]?.isEnabled ? (
                                    <div className="flex items-center space-x-3 w-full md:w-auto">
                                        <input
                                            type="time"
                                            value={availability[day]?.startTime || '09:00'}
                                            onChange={(e) => handleTimeChange(day, 'startTime', e.target.value)}
                                            className="w-full md:w-32 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-lg px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500 dark:text-gray-200"
                                        />
                                        <span className="text-gray-500 dark:text-gray-400">-</span>
                                        <input
                                            type="time"
                                            value={availability[day]?.endTime || '17:00'}
                                            onChange={(e) => handleTimeChange(day, 'endTime', e.target.value)}
                                            className="w-full md:w-32 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-lg px-3 py-2 text-sm focus:ring-blue-500 focus:border-blue-500 dark:text-gray-200"
                                        />
                                    </div>
                                ) : (
                                    <span className="text-sm text-gray-500 dark:text-gray-400 italic md:w-auto w-full text-left md:text-right">Not available</span>
                                )}
                            </div>
                        ))}
                    </div>
                )}
            </div>
            <div className="flex justify-end pt-4">
                <button
                    onClick={handleSaveAvailability}
                    disabled={isLoading}
                    className="bg-blue-600 text-white font-bold px-8 py-3 rounded-xl hover:bg-blue-700 shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {isLoading ? 'Saving...' : 'Save Availability'}
                </button>
            </div>
        </div>
    );
};


