import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ProfessionalDashboard from './components/ProfessionalDashboard';
import PatientList from './components/PatientList';
import HealthMetrics from './components/HealthMetrics';
import Medications from './components/Medications';
import Appointments from './components/Appointments';
import MyDoctors from './components/MyDoctors';
import ChatBot from './components/Community';
import PersonalChat from './components/PersonalChat';
import Settings from './components/Settings';
import HelpSupport from './components/HelpSupport';
import VideoCall from './components/VideoCall';
import Auth from './components/Auth';
import { supabase } from './services/supabaseClient';
import { Page, Professional, UserProfile, UserRole, BoticareNotification, Patient, ProfessionalTitle, Appointment } from './types';

const App: React.FC = () => {
  const [session, setSession] = useState<any | null>(null);
  const [userRole, setUserRole] = useState<UserRole>('patient');
  const [activePage, setActivePage] = useState<Page>(Page.Dashboard);
  const [videoCallProfessional, setVideoCallProfessional] = useState<Professional | null>(null);
  const [videoCallPatient, setVideoCallPatient] = useState<Patient | null>(null);
  // FIX: Update the type of chatRecipient to include Professional.
  const [chatRecipient, setChatRecipient] = useState<Patient | Professional | UserProfile | null>(null);
  const [videoCallAppointment, setVideoCallAppointment] = useState<Appointment | null>(null); // New state for appointment object
  const [notifications, setNotifications] = useState<BoticareNotification[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Loading...',
    email: '',
    phone: '',
    avatar: 'https://i.pravatar.cc/150?u=placeholder',
    professionalTitle: 'Doctor', // Default for professionals
    specialty: 'General Practice' // Default for professionals
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('boticare-dark-mode');
    return saved ? saved === 'true' : window.matchMedia?.('(prefers-color-scheme: dark)').matches;
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) { root.classList.add('dark'); } else { root.classList.remove('dark'); }
    localStorage.setItem('boticare-dark-mode', String(isDarkMode));
  }, [isDarkMode]);

  useEffect(() => {
    if (!supabase) return;
    const savedRole = localStorage.getItem('boticare-user-role') as UserRole;
    if (savedRole) {
        setUserRole(savedRole);
        // Set initial page based on saved role to prevent flicker, 
        // but fetchProfile will be the source of truth.
        setActivePage(savedRole === 'professional' ? Page.ProfessionalDashboard : Page.Dashboard);
    }
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    if (!supabase) return;
    try {
        const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single();
        if (error) throw error;
        if (data) {
            const dbRole = (data.role as UserRole) || 'patient';

            setUserProfile({
                name: data.name || 'User',
                email: data.email || '',
                phone: data.phone || '',
                avatar: data.avatar_url || 'https://i.pravatar.cc/150?u=default',
                role: dbRole,
                professionalTitle: (data.professional_title as ProfessionalTitle) || 'Doctor',
                specialty: data.specialty || 'General Practice',
                supabaseId: data.id 
            });

            setUserRole(dbRole);

            // Critical Fix: Enforce redirection based on the DB role.
            // If the user is a professional, always route them to the Professional Dashboard on load.
            // This overrides any potential mismatch from local storage or default state.
            if (dbRole === 'professional') {
                setActivePage(Page.ProfessionalDashboard);
            } else if (dbRole === 'patient' && activePage === Page.ProfessionalDashboard) {
                // Prevent patients from being on the professional dashboard
                setActivePage(Page.Dashboard);
            }
        }
    } catch (err) { console.error("Profile fetch error", err); }
  };

  const handleUpdateProfile = async (updatedProfile: UserProfile) => {
    if (!session || !supabase) return;
    try {
        const { error } = await supabase.from('profiles')
            .update({ 
                name: updatedProfile.name, 
                phone: updatedProfile.phone, 
                avatar_url: updatedProfile.avatar,
                professional_title: updatedProfile.professionalTitle,
                specialty: updatedProfile.specialty
            })
            .eq('id', session.user.id);
        if (error) throw error;
        setUserProfile(updatedProfile); // Update local state after successful DB update
        console.log("Profile updated successfully!");
    } catch (error) {
        console.error("Error updating profile:", error);
    }
  };


  const handleAddNotification = (msg: string) => {
      const newNotif: BoticareNotification = {
          id: Date.now().toString(),
          message: msg,
          type: 'success',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          read: false
      };
      setNotifications(prev => [newNotif, ...prev]);
  };

  const handleMarkNotificationsAsRead = () => {
      setTimeout(() => {
          setNotifications(prev => prev.map(n => ({...n, read: true})));
      }, 2000);
  };

  // FIX: Updated setVideoCallProfessional to handle the appointment object.
  const handleStartVideoCall = (appointment: Appointment, professional: Professional | null = null, patient: Patient | null = null) => {
    setVideoCallAppointment(appointment);
    setVideoCallProfessional(professional);
    setVideoCallPatient(patient);
    setActivePage(Page.VideoCall);
  };


  const startPersonalChat = (recipient: Patient | Professional | UserProfile) => {
      setChatRecipient(recipient);
      setActivePage(Page.PersonalChat);
  };

  if (!session) {
    return <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200"><Auth /></div>;
  }

  // Separate rendering logic for Patient and Professional UIs
  const renderPatientPage = () => {
    switch (activePage) {
        case Page.Dashboard: return <Dashboard />;
        case Page.HealthMetrics: return <HealthMetrics setActivePage={setActivePage} />;
        case Page.Medications: return <Medications />;
        case Page.Appointments: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={handleStartVideoCall} />;
        case Page.MyDoctors: return <MyDoctors onStartChat={startPersonalChat} />;
        case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
        case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.MyDoctors)} />;
        case Page.Settings: return <Settings userProfile={userProfile} onProfileUpdate={handleUpdateProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
        case Page.HelpSupport: return <HelpSupport />;
        // Pass the appointment object to VideoCall
        case Page.VideoCall: return <VideoCall appointment={videoCallAppointment} professional={videoCallProfessional} onEndCall={() => setActivePage(Page.Appointments)} />;
        default: return <Dashboard />;
    }
  };

  const renderProfessionalPage = () => {
    switch (activePage) {
        case Page.ProfessionalDashboard: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
        case Page.PatientList: return <PatientList setActivePage={setActivePage} onStartChat={startPersonalChat} />;
        case Page.ProfessionalSchedule: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={handleStartVideoCall} isProfessionalView userRole={userRole} />;
        case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
        case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.PatientList)} />;
        case Page.Settings: return <Settings userProfile={userProfile} onProfileUpdate={handleUpdateProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
        case Page.HelpSupport: return <HelpSupport />;
        // Pass the appointment object to VideoCall
        case Page.VideoCall: return <VideoCall appointment={videoCallAppointment} professional={videoCallProfessional} patient={videoCallPatient} isProfessionalView onEndCall={() => setActivePage(Page.ProfessionalSchedule)} />;
        default: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
    }
  };

  return (
    <div className="bg-boticare-gray text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
      <Layout 
        activePage={activePage} 
        setActivePage={setActivePage} 
        userProfile={userProfile} 
        userRole={userRole}
        notifications={notifications}
        onMarkNotificationsAsRead={handleMarkNotificationsAsRead}
      >
        {userRole === 'professional' ? renderProfessionalPage() : renderPatientPage()}
      </Layout>
    </div>
  );
};

export default App;

-- Enable pgcrypto for gen_random_uuid()
create extension if not exists pgcrypto;

-- Profiles table with role-based fields
create table if not exists public.profiles (
  id uuid references auth.users on delete cascade not null primary key,
  updated_at timestamp with time zone,
  name text,
  email text,
  avatar_url text,
  phone text,
  role text default 'patient', -- 'patient' or 'professional'
  professional_title text, -- 'Doctor' or 'Pharmacist'
  specialty text
);

-- Appointments and Clinical Schedule
create table if not exists public.appointments (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references public.profiles(id) not null,
  professional_id uuid references public.profiles(id) not null,
  scheduled_at timestamp with time zone not null,
  status text default 'upcoming', -- upcoming, completed, canceled, rescheduled
  type text not null, -- check-up, follow-up, etc.
  duration_minutes integer default 30,
  notes text,
  summary text, -- AI-generated or doctor-written summary
  created_at timestamp with time zone default now()
);

-- Video Call Sessions Log
create table if not exists public.video_call_sessions (
  id uuid default gen_random_uuid() primary key,
  appointment_id uuid references public.appointments(id) not null,
  professional_id uuid references public.profiles(id),
  patient_id uuid references public.profiles(id),
  started_at timestamp with time zone default now(),
  ended_at timestamp with time zone,
  duration_seconds integer,
  recording_url text,
  quality_rating integer
);

-- Prescription Refill Requests
create table if not exists public.requested_drug_refills (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references public.profiles(id) not null,
  professional_id uuid references public.profiles(id),
  drug_name text not null,
  dosage text not null,
  status text default 'pending', -- pending, approved, declined
  requested_at timestamp with time zone default now(),
  responded_at timestamp with time zone,
  pharmacist_notes text
);

-- Patient AI Chatbot Sessions
create table if not exists public.patient_chatbot_sessions (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references public.profiles(id) not null,
  transcript jsonb, -- array of messages
  last_activity timestamp with time zone default now()
);

-- Personalized Secure Messaging (HP <-> Patient)
create table if not exists public.personalized_chat_messages (
  id uuid default gen_random_uuid() primary key,
  sender_id uuid references public.profiles(id) not null,
  recipient_id uuid references public.profiles(id) not null,
  content text not null,
  is_read boolean default false,
  sent_at timestamp with time zone default now()
);

-- Professional Availability
create table if not exists public.professional_availability (
  id uuid default gen_random_uuid() primary key,
  professional_id uuid references public.profiles(id) not null,
  day_of_week text not null, -- e.g., 'Monday', 'Tuesday'
  start_time time not null,
  end_time time not null,
  created_at timestamp with time zone default now(),
  unique (professional_id, day_of_week) -- Only one availability slot per day per professional
);

-- Security Policies (RLS)
alter table public.profiles enable row level security;
alter table public.appointments enable row level security;
alter table public.personalized_chat_messages enable row level security;
alter table public.requested_drug_refills enable row level security;
alter table public.professional_availability enable row level security;
alter table public.video_call_sessions enable row level security;

-- Drop existing policies to allow re-running script without errors
drop policy if exists "Users can see their own data" on public.profiles;
drop policy if exists "HPs can see patients they interact with" on public.profiles;
drop policy if exists "Patients can see their HPs" on public.profiles;
drop policy if exists "Everyone can create profiles" on public.profiles;
drop policy if exists "Users can update their own profile" on public.profiles;

drop policy if exists "HPs can manage their own appointments" on public.appointments;
drop policy if exists "Patients can view their appointments" on public.appointments;
drop policy if exists "Patients can create their own appointments" on public.appointments;

drop policy if exists "Users can send and receive personal messages" on public.personalized_chat_messages;

drop policy if exists "HPs can manage refill requests for their patients" on public.requested_drug_refills;
drop policy if exists "Patients can view and create their own refill requests" on public.requested_drug_refills;

drop policy if exists "Patients can manage their chatbot sessions" on public.patient_chatbot_sessions;

drop policy if exists "Professionals can manage their own availability" on public.professional_availability;

drop policy if exists "Users can view their own video call sessions" on public.video_call_sessions;
drop policy if exists "Users can create video call sessions linked to their appointments" on public.video_call_sessions;

-- Re-create Policies

-- Profiles
create policy "Users can see their own data" on public.profiles for select using (auth.uid() = id);
create policy "HPs can see patients they interact with" on public.profiles for select using (
  id IN (SELECT patient_id FROM public.appointments WHERE professional_id = auth.uid()) OR
  id IN (SELECT patient_id FROM public.requested_drug_refills WHERE professional_id = auth.uid()) OR
  id IN (SELECT recipient_id FROM public.personalized_chat_messages WHERE sender_id = auth.uid())
);
create policy "Patients can see their HPs" on public.profiles for select using (
  id IN (SELECT professional_id FROM public.appointments WHERE patient_id = auth.uid()) OR
  id IN (SELECT professional_id FROM public.requested_drug_refills WHERE patient_id = auth.uid()) OR
  id IN (SELECT sender_id FROM public.personalized_chat_messages WHERE recipient_id = auth.uid())
);
create policy "Everyone can create profiles" on public.profiles for insert with check (true);
create policy "Users can update their own profile" on public.profiles for update using (auth.uid() = id);

-- Appointments
create policy "HPs can manage their own appointments" on public.appointments
  for all using (professional_id = auth.uid()) with check (professional_id = auth.uid());
create policy "Patients can view their appointments" on public.appointments
  for select using (patient_id = auth.uid());
create policy "Patients can create their own appointments" on public.appointments
  for insert with check (patient_id = auth.uid());

-- Personalized Chat Messages
create policy "Users can send and receive personal messages" on public.personalized_chat_messages
  for all using (sender_id = auth.uid() OR recipient_id = auth.uid()) with check (sender_id = auth.uid());

-- Requested Drug Refills
create policy "HPs can manage refill requests for their patients" on public.requested_drug_refills
  for all using (professional_id = auth.uid()) with check (professional_id = auth.uid());
create policy "Patients can view and create their own refill requests" on public.requested_drug_refills
  for all using (patient_id = auth.uid()) with check (patient_id = auth.uid());

-- Patient Chatbot Sessions
create policy "Patients can manage their chatbot sessions" on public.patient_chatbot_sessions
  for all using (patient_id = auth.uid()) with check (patient_id = auth.uid());

-- Professional Availability
create policy "Professionals can manage their own availability" on public.professional_availability
  for all using (professional_id = auth.uid()) with check (professional_id = auth.uid());

-- Video Call Sessions
create policy "Users can view their own video call sessions" on public.video_call_sessions
  for select using (
    auth.uid() IN (SELECT patient_id FROM public.appointments WHERE id = appointment_id) OR
    auth.uid() IN (SELECT professional_id FROM public.appointments WHERE id = appointment_id)
  );
create policy "Users can create video call sessions linked to their appointments" on public.video_call_sessions
  for insert with check (
    auth.uid() IN (SELECT patient_id FROM public.appointments WHERE id = appointment_id) OR
    auth.uid() IN (SELECT professional_id FROM public.appointments WHERE id = appointment_id)
  );

import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { LockClosedIcon, UserIcon, ArrowRightIcon, EyeIcon, EyeOffIcon, BriefcaseIcon } from './Icons';
import { UserRole } from '../types';

const Auth: React.FC = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [isSignUp, setIsSignUp] = useState(false);
  // Hardcoded to professional for Boticare Pro
  const [role, setRole] = useState<UserRole>('professional');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [fullName, setFullName] = useState(''); // Only for Sign Up
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);
    setMessage(null);

    // Persist role selection
    localStorage.setItem('boticare-user-role', role);

    try {
      if (isSignUp) {
        const { error } = await (supabase!.auth as any).signUp({
          email,
          password,
          options: {
            data: {
              full_name: fullName,
              role: role,
            },
            emailRedirectTo: window.location.origin,
          },
        });
        if (error) throw error;
        setMessage('Check your email for the confirmation link!');
      } else {
        const { error } = await (supabase!.auth as any).signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      }
    } catch (error: any) {
      setError(error.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-900 px-4">
      <div className="max-w-md w-full space-y-8 bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-100 dark:border-gray-700">
        <div className="text-center">
            <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4 shadow-lg shadow-blue-200 dark:shadow-none">
                <BriefcaseIcon className="w-8 h-8 text-white" />
            </div>
          <h2 className="text-3xl font-extrabold text-gray-900 dark:text-white">
            Boticare Pro
          </h2>
          <p className="mt-2 text-sm text-gray-600 dark:text-gray-400 font-medium">
            {isSignUp ? 'Register your Practice' : 'Healthcare Professional Login'}
          </p>
        </div>

        <form className="mt-8 space-y-6" onSubmit={handleAuth}>
          <div className="rounded-md shadow-sm space-y-4">
            {isSignUp && (
              <div>
                <label htmlFor="fullName" className="sr-only">Full Name</label>
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <UserIcon className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                    id="fullName"
                    name="fullName"
                    type="text"
                    required
                    className="appearance-none rounded-lg relative block w-full px-3 py-3 pl-10 border border-gray-300 placeholder-gray-500 text-gray-900 bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 focus:z-10 sm:text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-white dark:placeholder-gray-400 transition-all"
                    placeholder="Full Name"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    />
                </div>
              </div>
            )}
            <div>
