import React, { useState, useEffect, useRef } from 'react';
import { SearchIcon, AppointmentsIcon, MedicationsIcon, UserIcon, HeartIcon, MenuIcon, BellIcon, CheckCircleIcon } from './Icons';
import { APPOINTMENTS_DATA, MEDICATIONS_DATA, PROFESSIONALS_DATA, HEALTH_METRICS_DATA } from '../constants';
import { UserProfile, Page, BoticareNotification } from '../types';

interface SearchSuggestion {
    type: 'Appointment' | 'Patient' | 'Professional';
    label: string;
    id: string | number;
    icon: React.ComponentType<{ className?: string }>;
}

interface HeaderProps {
    userProfile: UserProfile;
    onNavigate: (page: Page) => void;
    onToggleSidebar: () => void;
    notifications: BoticareNotification[];
    onMarkNotificationsAsRead: () => void;
}

const Header: React.FC<HeaderProps> = ({ userProfile, onNavigate, onToggleSidebar, notifications, onMarkNotificationsAsRead }) => {
    const [query, setQuery] = useState('');
    const [suggestions, setSuggestions] = useState<SearchSuggestion[]>([]);
    const [isSuggestionsVisible, setIsSuggestionsVisible] = useState(false);
    const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
    const searchContainerRef = useRef<HTMLDivElement>(null);
    const notificationsRef = useRef<HTMLDivElement>(null);

    const unreadCount = notifications.filter(n => !n.read).length;

    useEffect(() => {
        if (query.length < 2) {
            setSuggestions([]);
            return;
        }

        const handler = setTimeout(() => {
            const lowerCaseQuery = query.toLowerCase();
            // Search logic adapted for Professionals
            const appointmentResults = APPOINTMENTS_DATA.filter(item => item.patientName.toLowerCase().includes(lowerCaseQuery)).map(item => ({ type: 'Appointment' as const, label: `${item.patientName} - ${item.type}`, id: item.id, icon: AppointmentsIcon }));

            // Assuming MOCK_PATIENTS are searched here, reusing PROFESSIONALS_DATA structure for mock simplicity in search logic or using names from appointments for now
            const patientResults = APPOINTMENTS_DATA.filter(item => item.patientName.toLowerCase().includes(lowerCaseQuery)).map(item => ({ type: 'Patient' as const, label: item.patientName, id: item.patientId, icon: UserIcon }));

            setSuggestions([...appointmentResults, ...patientResults]);
        }, 300);

        return () => clearTimeout(handler);
    }, [query]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) setIsSuggestionsVisible(false);
            if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) setIsNotificationsOpen(false);
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleSuggestionClick = (suggestion: SearchSuggestion) => {
        let targetPage = Page.ProfessionalDashboard;
        switch(suggestion.type) {
            case 'Appointment': targetPage = Page.ProfessionalSchedule; break;
            case 'Patient': targetPage = Page.PatientList; break;
            case 'Professional': targetPage = Page.PatientList; break; // Fallback
        }
        onNavigate(targetPage);
        setIsSuggestionsVisible(false);
        setQuery('');
    };

    const handleNotificationsToggle = () => {
        setIsNotificationsOpen(!isNotificationsOpen);
        if (!isNotificationsOpen) { // If opening
            onMarkNotificationsAsRead();
        }
    };

  return (
    <header className="bg-white border-b border-boticare-gray-medium p-3 md:p-4 flex items-center justify-between sticky top-0 z-20 dark:bg-gray-800 dark:border-gray-700">
      <div className="flex items-center space-x-2 md:space-x-4">
        <button onClick={onToggleSidebar} className="lg:hidden p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg" aria-label="Toggle Menu"><MenuIcon className="w-6 h-6 text-gray-600 dark:text-gray-300" /></button>
        <h1 className="text-lg md:text-xl font-bold text-boticare-primary dark:text-white truncate">Boticare Pro</h1>
        <span className="hidden sm:inline-block text-[10px] md:text-xs font-medium bg-blue-100 text-blue-800 px-2 py-1 rounded-md dark:bg-blue-900/50 dark:text-blue-200 uppercase tracking-tighter">Practice Mode</span>
      </div>

      <div className="flex-1 max-w-sm md:max-w-md mx-2 md:mx-4">
        <div className="relative" ref={searchContainerRef}>
          <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none"><SearchIcon className="h-4 md:h-5 w-4 md:w-5 text-gray-400" /></div>
          <input type="text" placeholder="Search patients, appointments..." value={query} onChange={e => setQuery(e.target.value)} onFocus={() => setIsSuggestionsVisible(true)} className="w-full bg-boticare-gray rounded-lg border-none pl-9 md:pl-10 pr-3 md:pr-4 py-1.5 md:py-2 text-sm focus:ring-2 focus:ring-boticare-blue-dark focus:outline-none dark:bg-gray-700 dark:text-gray-200 dark:placeholder-gray-400" />
          {isSuggestionsVisible && suggestions.length > 0 && <SearchResults suggestions={suggestions} onSelect={handleSuggestionClick} />}
        </div>
      </div>

      <div className="flex items-center space-x-2 md:space-x-4 flex-shrink-0">
        <div ref={notificationsRef} className="relative">
            <button onClick={handleNotificationsToggle} className="p-2 text-gray-500 hover:text-boticare-primary hover:bg-gray-100 rounded-full transition-colors dark:text-gray-400 dark:hover:text-white dark:hover:bg-gray-700">
                <BellIcon className="w-6 h-6" />
                {unreadCount > 0 && <span className="absolute top-0 right-0 flex h-4 w-4"><span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span><span className="relative inline-flex rounded-full h-4 w-4 bg-red-500 text-[9px] text-white items-center justify-center font-bold">{unreadCount}</span></span>}
            </button>
            {isNotificationsOpen && <NotificationsPanel notifications={notifications} />}
        </div>

        <div className="flex items-center space-x-2 md:space-x-3">
            <img src={userProfile.avatar} alt={userProfile.name} className="w-8 h-8 md:w-10 md:h-10 rounded-full object-cover border-2 border-white shadow-sm dark:border-gray-600" />
            <div className="hidden sm:block">
                <p className="font-bold text-xs md:text-sm text-gray-900 dark:text-white leading-tight">{userProfile.name}</p>
                <p className="text-[10px] md:text-xs font-bold text-blue-600 dark:text-blue-400 uppercase tracking-wide">{userProfile.professionalTitle || 'Healthcare Pro'}</p>
            </div>
        </div>
      </div>
    </header>
  );
};

const SearchResults: React.FC<{ suggestions: SearchSuggestion[], onSelect: (s: SearchSuggestion) => void }> = ({ suggestions, onSelect }) => {
    const grouped = suggestions.reduce((acc, s) => ({...acc, [s.type]: [...(acc[s.type] || []), s]}), {} as Record<string, SearchSuggestion[]>);
    return (
        <div className="absolute top-full mt-2 left-0 right-0 md:w-full bg-white rounded-lg shadow-lg border border-boticare-gray-medium z-30 animate-fade-in dark:bg-gray-800 dark:border-gray-700 overflow-hidden max-h-80 md:max-h-96 overflow-y-auto">
            {Object.entries(grouped).map(([type, items]) => (
                <div key={type}>
                    <div className="px-4 py-2 bg-gray-50 text-[10px] font-semibold text-gray-500 uppercase tracking-wider dark:bg-gray-700/50 dark:text-gray-400">{type}s</div>
                    <ul>{items.map(s => <li key={`${s.type}-${s.id}`}><button onClick={() => onSelect(s)} className="w-full flex items-center space-x-3 px-4 py-2 text-sm text-gray-700 hover:bg-boticare-gray dark:text-gray-300 dark:hover:bg-gray-700"><div className="p-1.5 bg-gray-100 rounded-full dark:bg-gray-600"><s.icon className="w-3.5 h-3.5 text-boticare-gray-dark dark:text-gray-300" /></div><span className="truncate">{s.label}</span></button></li>)}</ul>
                </div>
            ))}
        </div>
    );
};

const NotificationsPanel: React.FC<{notifications: BoticareNotification[]}> = ({ notifications }) => (
    <div className="absolute top-full right-0 mt-3 w-80 bg-white dark:bg-gray-800 rounded-2xl shadow-2xl border border-gray-100 dark:border-gray-700 animate-fade-in overflow-hidden">
        <div className="p-4 border-b border-gray-100 dark:border-gray-700">
            <h3 className="font-bold text-lg">Notifications</h3>
        </div>
        <div className="max-h-96 overflow-y-auto">
            {notifications.length > 0 ? (
                notifications.map(n => (
                    <div key={n.id} className={`p-4 border-b border-gray-50 dark:border-gray-700/50 flex gap-3 hover:bg-gray-50 dark:hover:bg-gray-700/50 ${!n.read ? 'bg-blue-50 dark:bg-blue-900/10' : ''}`}>
                        <div className="mt-1"><CheckCircleIcon className="w-5 h-5 text-green-500" /></div>
                        <div>
                            <p className="text-sm font-semibold text-gray-800 dark:text-gray-200">{n.message}</p>
                            <p className="text-xs text-gray-400 mt-1">{n.timestamp}</p>
                        </div>
                    </div>
                ))
            ) : (
                <p className="p-8 text-center text-sm text-gray-400">No new notifications.</p>
            )}
        </div>
    </div>
);

export default Header;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ProfessionalDashboard from './components/ProfessionalDashboard';
import PatientList from './components/PatientList';
import Appointments from './components/Appointments';
import ChatBot from './components/Community';
import PersonalChat from './components/PersonalChat';
import Settings from './components/Settings';
import HelpSupport from './components/HelpSupport';
import VideoCall from './components/VideoCall';
import Auth from './components/Auth';
import { supabase } from './services/supabaseClient';
import { Page, Professional, UserProfile, UserRole, BoticareNotification, Patient, ProfessionalTitle, Appointment } from './types';

const App: React.FC = () => {
  const [session, setSession] = useState<any | null>(null);
  // Force userRole to always be professional for Boticare Pro
  const [userRole, setUserRole] = useState<UserRole>('professional');
  const [activePage, setActivePage] = useState<Page>(Page.ProfessionalDashboard);
  const [videoCallProfessional, setVideoCallProfessional] = useState<Professional | null>(null);
  const [videoCallPatient, setVideoCallPatient] = useState<Patient | null>(null);
  const [chatRecipient, setChatRecipient] = useState<Patient | Professional | UserProfile | null>(null);
  const [videoCallAppointment, setVideoCallAppointment] = useState<Appointment | null>(null); 
  const [notifications, setNotifications] = useState<BoticareNotification[]>([]);

  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Loading...',
    email: '',
    phone: '',
    avatar: 'https://i.pravatar.cc/150?u=placeholder',
    role: 'professional',
    professionalTitle: 'Doctor', 
    specialty: 'General Practice'
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('boticare-dark-mode');
    return saved ? saved === 'true' : window.matchMedia?.('(prefers-color-scheme: dark)').matches;
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (isDarkMode) { root.classList.add('dark'); } else { root.classList.remove('dark'); }
    localStorage.setItem('boticare-dark-mode', String(isDarkMode));
  }, [isDarkMode]);

  useEffect(() => {
    if (!supabase) return;

    // Always start on Professional Dashboard for this Pro App
    setActivePage(Page.ProfessionalDashboard);

    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchProfile(session.user.id);
    });
    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    if (!supabase) return;
    try {
        const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single();
        if (error) throw error;
        if (data) {
            setUserProfile({
                name: data.name || 'User',
                email: data.email || '',
                phone: data.phone || '',
                avatar: data.avatar_url || 'https://i.pravatar.cc/150?u=default',
                role: 'professional', // Enforce professional role in UI state
                professionalTitle: (data.professional_title as ProfessionalTitle) || 'Doctor',
                specialty: data.specialty || 'General Practice',
                supabaseId: data.id 
            });
            setUserRole('professional');
        }
    } catch (err) { console.error("Profile fetch error", err); }
  };

  const handleUpdateProfile = async (updatedProfile: UserProfile) => {
    if (!session || !supabase) return;
    try {
        const { error } = await supabase.from('profiles')
            .update({ 
                name: updatedProfile.name, 
                phone: updatedProfile.phone, 
                avatar_url: updatedProfile.avatar,
                professional_title: updatedProfile.professionalTitle,
                specialty: updatedProfile.specialty
            })
            .eq('id', session.user.id);
        if (error) throw error;
        setUserProfile(updatedProfile); 
        console.log("Profile updated successfully!");
    } catch (error) {
        console.error("Error updating profile:", error);
    }
  };


  const handleAddNotification = (msg: string) => {
      const newNotif: BoticareNotification = {
          id: Date.now().toString(),
          message: msg,
          type: 'success',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          read: false
      };
      setNotifications(prev => [newNotif, ...prev]);
  };

  const handleMarkNotificationsAsRead = () => {
      setTimeout(() => {
          setNotifications(prev => prev.map(n => ({...n, read: true})));
      }, 2000);
  };

  const handleStartVideoCall = (appointment: Appointment, professional: Professional | null = null, patient: Patient | null = null) => {
    setVideoCallAppointment(appointment);
    setVideoCallProfessional(professional);
    setVideoCallPatient(patient);
    setActivePage(Page.VideoCall);
  };


  const startPersonalChat = (recipient: Patient | Professional | UserProfile) => {
      setChatRecipient(recipient);
      setActivePage(Page.PersonalChat);
  };

  if (!session) {
    return <div className="bg-white text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200"><Auth /></div>;
  }

  const renderAppContent = () => {
    switch (activePage) {
        case Page.ProfessionalDashboard: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
        case Page.PatientList: return <PatientList setActivePage={setActivePage} onStartChat={startPersonalChat} />;
        case Page.ProfessionalSchedule: return <Appointments setActivePage={setActivePage} setVideoCallProfessional={handleStartVideoCall} isProfessionalView userRole={userRole} />;
        case Page.ChatBot: return <ChatBot userProfile={userProfile} />;
        case Page.PersonalChat: return <PersonalChat recipient={chatRecipient} userProfile={userProfile} onClose={() => setActivePage(Page.PatientList)} />;
        case Page.Settings: return <Settings userProfile={userProfile} onProfileUpdate={handleUpdateProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
        case Page.HelpSupport: return <HelpSupport />;
        case Page.VideoCall: return <VideoCall appointment={videoCallAppointment} professional={videoCallProfessional} patient={videoCallPatient} isProfessionalView onEndCall={() => setActivePage(Page.ProfessionalSchedule)} />;
        default: return <ProfessionalDashboard setActivePage={setActivePage} userProfile={userProfile} onAddNotification={handleAddNotification} />;
    }
  };

  return (
    <div className="bg-boticare-gray text-gray-800 font-sans dark:bg-gray-900 dark:text-gray-200">
      <Layout 
        activePage={activePage} 
        setActivePage={setActivePage} 
        userProfile={userProfile} 
        userRole={userRole}
        notifications={notifications}
        onMarkNotificationsAsRead={handleMarkNotificationsAsRead}
      >
        {renderAppContent()}
      </Layout>
    </div>
  );
};

