    return null;
  }
};

// Added analyzeVideo function to resolve errors in components/Community.tsx and components/VideoAnalyzer.tsx
export const analyzeVideo = async (videoFile: File, prompt: string): Promise<string> => {
    try {
        const base64Video = await new Promise<string>((resolve) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                if (typeof reader.result === 'string') {
                    resolve(reader.result.split(',')[1]);
                } else {
                    resolve('');
                }
            };
            reader.readAsDataURL(videoFile);
        });

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { data: base64Video, mimeType: videoFile.type } },
                    { text: prompt },
                ],
            },
        });
        return response.text || "I couldn't analyze the video.";
    } catch (error) {
        console.error("Error analyzing video:", error);
        return "Error analyzing video.";
    }
};

export const generateHealthReport = async (healthData: any, startDate: string, endDate: string): Promise<string> => {
    try {
        const prompt = `As a healthcare professional AI, generate a comprehensive patient health report for the period ${startDate} to ${endDate}.

        Data:
        - Patient: ${healthData.patientName}
        - Metrics: ${JSON.stringify(healthData.metrics)}
        - Medications: ${JSON.stringify(healthData.medications)}
        - Appointments: ${JSON.stringify(healthData.appointments)}

        Generate a structured medical report with Summary, Key Trends, and Recommendations. Use professional markdown formatting.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: { parts: [{ text: prompt }] },
            config: {
                thinkingConfig: { thinkingBudget: 32768 }
            }
        });

        return response.text || "No report generated.";
    } catch (error) {
        console.error("Error generating health report:", error);
        return "Could not generate the health report at this time.";
    }
};

export const getProfessionalAvailability = async (professionalId: string): Promise<AvailabilitySlot[]> => {
    if (!supabase) return [];
    const { data, error } = await supabase.from('professional_availability').select('*').eq('professional_id', professionalId);
    if (error) return [];
    return data.map(slot => ({
        id: slot.id,
        dayOfWeek: slot.day_of_week,
        startTime: slot.start_time,
        endTime: slot.end_time,
        isEnabled: true,
    }));
};

export const saveProfessionalAvailability = async (professionalId: string, slots: AvailabilitySlot[]): Promise<boolean> => {
    if (!supabase) return false;
    await supabase.from('professional_availability').delete().eq('professional_id', professionalId);
    const enabledSlotsToInsert = slots.filter(slot => slot.isEnabled).map(slot => ({
            professional_id: professionalId,
            day_of_week: slot.dayOfWeek,
            start_time: slot.startTime,
            end_time: slot.endTime,
        }));
    if (enabledSlotsToInsert.length === 0) return true;
    const { error: insertError } = await supabase.from('professional_availability').insert(enabledSlotsToInsert);
    return !insertError;
};

export const updateRefillRequest = async (requestId: number, updates: {drugName?: string, dosage?: string, status?: 'pending' | 'approved' | 'declined'}): Promise<boolean> => {
    if (!supabase) return false;
    const dbUpdates: any = {};
    if (updates.drugName !== undefined) dbUpdates.drug_name = updates.drugName;
    if (updates.dosage !== undefined) dbUpdates.dosage = updates.dosage;
    if (updates.status !== undefined) {
        dbUpdates.status = updates.status;
        dbUpdates.responded_at = new Date().toISOString();
    }
    const { error } = await supabase.from('requested_drug_refills').update(dbUpdates).eq('id', requestId);
    return !error;
};

export const logVideoCallSession = async (sId: string, aId: string, proId: string, patId: string, start: string, end: string, dur: number, url?: string): Promise<boolean> => {
    if (!supabase) return false;
    const { error } = await supabase.from('video_call_sessions').insert({
            id: sId, appointment_id: aId, professional_id: proId, patient_id: patId,
            started_at: start, ended_at: end, duration_seconds: dur, recording_url: url,
        });
    return !error;
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ChatMessage, Patient, UserProfile, Professional } from '../types';
import { SendIcon, XIcon, BackIcon, CheckCircleIcon, SparklesIcon } from './Icons';
import { getWordSuggestions } from '../services/geminiService';

interface PersonalChatProps {
    recipient: Patient | Professional | UserProfile | null;
    userProfile: UserProfile;
    onClose: () => void;
}

const formatChatTimestamp = (timestamp: string): string => {
    const messageDate = new Date(timestamp);
    const now = new Date();
    const timeOptions: Intl.DateTimeFormatOptions = { hour: '2-digit', minute: '2-digit', hour12: true };
    const time = messageDate.toLocaleTimeString([], timeOptions);
    if (now.toDateString() === messageDate.toDateString()) return `Today, ${time}`;
    return `${messageDate.toLocaleDateString([], { month: 'short', day: 'numeric' })}, ${time}`;
};

const PersonalChat: React.FC<PersonalChatProps> = ({ recipient, userProfile, onClose }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [input, setInput] = useState('');
    const [suggestions, setSuggestions] = useState<string[]>([]);
    const [isRecipientTyping, setIsRecipientTyping] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const suggestionTimeoutRef = useRef<number | null>(null);

    const isCurrentUserProfessional = userProfile.role === 'professional';

    const getLocalStorageKey = useCallback(() => {
        const userId = userProfile.email;
        const recipientIdentifier = recipient ? ('id' in recipient ? recipient.id.toString() : recipient.email) : 'unknown';
        const sortedIdentifiers = [userId, recipientIdentifier].sort().join('_');
        return `boticare_chat_history_${sortedIdentifiers}`;
    }, [userProfile.email, recipient]);

    useEffect(() => {
        const key = getLocalStorageKey();
        const savedMessages = localStorage.getItem(key);
        if (savedMessages) setMessages(JSON.parse(savedMessages));
    }, [getLocalStorageKey]);

    useEffect(() => {
        const key = getLocalStorageKey();
        localStorage.setItem(key, JSON.stringify(messages));
        scrollToBottom();
    }, [messages, getLocalStorageKey]);

    // Fetch AI suggestions based on conversation context
    useEffect(() => {
        if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current);
        suggestionTimeoutRef.current = window.setTimeout(async () => {
            if (messages.length > 0 || input.length > 2) {
                const fetched = await getWordSuggestions(input, messages);
                setSuggestions(fetched);
            } else {
                setSuggestions(["How are you today?", "Check progress", "Review tests"]);
            }
        }, 800);
        return () => { if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current); };
    }, [messages, input]);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const handleSend = (textToSend: string = input) => {
        const text = textToSend.trim();
        if (!text || isRecipientTyping) return;

        const currentTime = new Date().toISOString();
        const newMsg: ChatMessage = {
            sender: isCurrentUserProfessional ? 'professional' : 'user',
            text: text,
            timestamp: currentTime,
            isRead: false
        };
        setMessages(prev => [...prev, newMsg]);
        setInput('');
        setSuggestions([]);

        // Simulate "Read" receipt update
        setTimeout(() => {
            setMessages(prev => prev.map(m => (m.timestamp === currentTime ? { ...m, isRead: true } : m)));
        }, 2500);

        setIsRecipientTyping(true);
        setTimeout(() => {
            setIsRecipientTyping(false);
            const reply: ChatMessage = {
                sender: 'ai', // Distinct AI sender for UI differentiation
                text: "I've acknowledged your message. We'll update the patient records accordingly.",
                timestamp: new Date().toISOString(),
            };
            setMessages(prev => [...prev, reply]);
        }, 4000);
    };

    const handleSuggestionClick = (s: string) => {
        setInput(s);
        handleSend(s);
    };

    if (!recipient) return null;

    const recipientName = 'name' in recipient ? recipient.name : 'Unknown';
    const recipientAvatar = 'avatar' in recipient ? recipient.avatar : 'https://i.pravatar.cc/150';

    return (
        <div className="h-full flex flex-col bg-white dark:bg-gray-800 rounded-3xl border border-boticare-gray-medium dark:border-gray-700 shadow-xl animate-fade-in overflow-hidden">
            <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between bg-white dark:bg-gray-800 sticky top-0 z-10 shadow-sm">
                <div className="flex items-center gap-3">
                    <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg lg:hidden"><BackIcon className="w-5 h-5 text-gray-500" /></button>
                    <div className="relative">
                        <img src={recipientAvatar} className="w-10 h-10 rounded-full object-cover border-2 border-white dark:border-gray-700 shadow-sm" alt={recipientName} />
                        <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white dark:border-gray-800 rounded-full"></div>
                    </div>
                    <div>
                        <h3 className="font-bold text-gray-900 dark:text-white leading-tight">{recipientName}</h3>
                        <p className="text-[10px] text-green-600 font-bold uppercase tracking-wider">{isRecipientTyping ? 'Typing...' : 'Online'}</p>
                    </div>
                </div>
                <button onClick={onClose} className="hidden lg:block p-2 text-gray-400 hover:text-gray-600"><XIcon className="w-6 h-6"/></button>
            </div>

            <div className="flex-grow p-4 md:p-6 overflow-y-auto space-y-6 no-scrollbar bg-gray-50/50 dark:bg-gray-900/20">
                {messages.map((msg, idx) => {
                    const isSentByMe = msg.sender === 'user' || msg.sender === 'professional';
                    const isAI = msg.sender === 'ai';
                    return (
                        <div key={idx} className={`flex w-full ${isSentByMe ? 'justify-end' : 'justify-start'}`}>
                            <div className={`flex flex-col ${isSentByMe ? 'items-end' : 'items-start'} max-w-[85%]`}>
                                <div className={`px-4 py-3 rounded-2xl shadow-sm text-sm md:text-base border ${
                                    isSentByMe
                                        ? 'bg-blue-600 text-white border-blue-500 rounded-tr-none'
                                        : isAI 
                                            ? 'bg-purple-50 dark:bg-purple-900/20 text-purple-900 dark:text-purple-100 border-purple-100 dark:border-purple-800 rounded-tl-none'
                                            : 'bg-white dark:bg-gray-700 text-gray-800 dark:text-gray-100 border-gray-100 dark:border-gray-600 rounded-tl-none'
                                }`}>
                                    {isAI && <div className="flex items-center gap-1.5 mb-1 opacity-60"><SparklesIcon className="w-3 h-3" /><span className="text-[9px] font-black uppercase tracking-widest">Boticare AI</span></div>}
                                    <p className="leading-relaxed">{msg.text}</p>
                                </div>
                                <div className="flex items-center gap-1.5 mt-1.5 px-1 opacity-70">
                                    <span className="text-[10px] font-medium text-gray-400 dark:text-gray-500">{formatChatTimestamp(msg.timestamp)}</span>
                                    {isSentByMe && (
                                        <div className="flex items-center" title={msg.isRead ? "Read" : "Delivered"}>
                                            <CheckCircleIcon className={`w-3 h-3 transition-colors ${msg.isRead ? 'text-blue-500' : 'text-gray-300 dark:text-gray-600'}`} />
                                            <CheckCircleIcon className={`w-3 h-3 -ml-1.5 transition-colors ${msg.isRead ? 'text-blue-500' : 'text-gray-300 dark:text-gray-600'}`} />
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    );
                })}
                {isRecipientTyping && (
                    <div className="flex items-center space-x-2 text-gray-400 p-2">
                        <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                        <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                        <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce"></div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            <div className="p-4 bg-white dark:bg-gray-800 border-t border-gray-100 dark:border-gray-700">
                {suggestions.length > 0 && (
                    <div className="flex items-center gap-2 mb-3 overflow-x-auto no-scrollbar pb-1 animate-fade-in">
                        {suggestions.map((s, i) => (
                            <button 
                                key={i} 
                                onClick={() => handleSuggestionClick(s)} 
                                className="whitespace-nowrap px-3 py-1.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-300 rounded-full text-[11px] font-bold border border-blue-100 dark:border-blue-800 hover:bg-blue-100 transition-all shadow-sm"
                            >
                                {s}
                            </button>
                        ))}
                    </div>
                )}
                <div className="relative flex items-center">
                    <input 
                        type="text" 
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyPress={e => e.key === 'Enter' && handleSend()}
                        placeholder="Message your team..."
                        className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-600 rounded-2xl pl-4 pr-14 py-3.5 shadow-inner focus:ring-2 focus:ring-blue-500 focus:outline-none dark:text-white transition-all text-sm md:text-base"
                    />
                    <button 
                        onClick={() => handleSend()} 
                        disabled={!input.trim() || isRecipientTyping} 
                        className="absolute right-2 p-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-all disabled:bg-gray-200 dark:disabled:bg-gray-700 shadow-md active:scale-95"
                    >
                        <SendIcon className="w-5 h-5 ml-0.5" />
                    </button>
                </div>
            </div>
        </div>
    );
};

export default PersonalChat;

import React, { useState } from 'react';
