                            <button onClick={() => triggerReportFlow({name: app.patientName})} className="p-2.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-xl transition-all" title="Generate Report"><FileIcon className="w-5 h-5"/></button>
                        </div>
                    ))}
                </div>

                <div className="space-y-4">
                    <h3 className="text-lg font-black px-1">Refill Queue</h3>
                    <div className="bg-white p-3 rounded-2xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 shadow-sm space-y-3">
                        {refills.length > 0 ? refills.map((req) => (
                            <div key={req.id} className="p-4 bg-gray-50 dark:bg-gray-700/30 rounded-2xl border border-gray-100 dark:border-gray-600 transition-all hover:bg-gray-100/50">
                                <div className="flex justify-between items-start mb-2">
                                    <span className="text-[9px] font-black uppercase text-blue-600 bg-blue-50 dark:bg-blue-900/30 px-2 py-0.5 rounded-lg">Prescription</span>
                                    <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">{req.timeAgo}</span>
                                </div>
                                <p className="text-sm font-bold leading-tight">{req.patientName}</p>
                                <p className="text-[11px] text-gray-500 italic mb-4 dark:text-gray-400">{req.drugName} ({req.dosage})</p>
                                <div className="flex gap-2">
                                    <button onClick={() => handleApprove(req)} className="flex-1 bg-blue-600 text-white text-[10px] font-black uppercase py-2.5 rounded-lg hover:bg-blue-700 transition-all active:scale-95 shadow-sm">Approve</button>
                                    <button onClick={() => handleDecline(req)} className="flex-1 bg-white dark:bg-gray-600 text-gray-400 dark:text-gray-300 text-[10px] font-black uppercase py-2.5 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-500 transition-all border border-gray-100 dark:border-gray-500 active:scale-95">Decline</button>
                                </div>
                            </div>
                        )) : (
                            <div className="p-8 text-center"><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Queue empty</p></div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ProfessionalDashboard;

import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA, MOCK_PATIENTS } from '../constants';
import AppointmentCard from './AppointmentCard';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import { Appointment, AppointmentStatus, Page, Professional, UserRole, Patient } from '../types';
import { PlusIcon, SearchIcon, VideoIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const STATUS_TABS = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
  'Call History'
];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  setVideoCallProfessional: (appointment: Appointment, professional?: Professional | null, patient?: Patient | null) => void;
  defaultToScheduling?: boolean;
  isProfessionalView?: boolean;
  userRole?: UserRole;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false, isProfessionalView, userRole }) => {
  const [activeTab, setActiveTab] = useState<string>(AppointmentStatus.Upcoming);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => {
        if (activeTab === 'Call History') return appointment.status === AppointmentStatus.Completed;
        return appointment.status === activeTab;
    })
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        const targetSearchName = isProfessionalView ? appointment.patientName : appointment.doctorName;
        return targetSearchName.toLowerCase().includes(lowerCaseQuery) || appointment.specialty.toLowerCase().includes(lowerCaseQuery);
    });

  const handleJoinVideo = (appointment: Appointment) => {
    const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
    const patient = MOCK_PATIENTS.find(p => p.name === appointment.patientName) || null;
    setVideoCallProfessional(appointment, professional, patient);
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    const summaryText = appointment.summary || await getAppointmentSummary(appointment);
    setAppointments(prev => prev.map(app => app.id === appointment.id ? { ...app, summary: summaryText } : app));
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  return (
    <div className="space-y-6">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <AppointmentSummaryModal {...summaryModalState} onClose={() => setSummaryModalState({ ...summaryModalState, appointment: null })} />
      <EditNotesModal appointment={editingAppointment} onClose={() => setEditingAppointment(null)} onSave={(id, notes) => {
          setAppointments(prev => prev.map(a => a.id === id ? { ...a, notes } : a));
          setEditingAppointment(null);
          setToastMessage('Notes updated.');
      }} />
      <AppointmentDetailsModal appointment={detailsAppointment} onClose={() => setDetailsAppointment(null)} />

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h2 className="text-2xl font-black">Clinical Schedule</h2>
            <p className="text-sm text-gray-500 dark:text-gray-400">Track and manage your upcoming consultations.</p>
        </div>
        {!isProfessionalView && (
            <button onClick={() => setActivePage(Page.ScheduleAppointment)} className="bg-blue-600 text-white font-bold px-5 py-3 rounded-xl flex items-center space-x-2 shadow-lg">
              <PlusIcon className="w-5 h-5" /> <span>Schedule</span>
            </button>
        )}
      </div>

      <div className="bg-white p-4 rounded-2xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 shadow-sm space-y-4">
        <div className="flex flex-col gap-4">
            <nav className="flex flex-wrap gap-2 overflow-x-auto no-scrollbar pb-1">
                {STATUS_TABS.map((tab) => (
                <button
                    key={tab}
                    onClick={() => setActiveTab(tab)}
                    className={`px-3 py-2 text-[10px] md:text-xs font-black uppercase tracking-widest rounded-xl transition-all flex-grow sm:flex-grow-0 whitespace-nowrap ${
                    activeTab === tab
                        ? 'bg-blue-600 text-white shadow-md'
                        : 'text-gray-400 hover:bg-gray-50 bg-gray-50/50 dark:bg-gray-700 dark:hover:bg-gray-600'
                    }`}
                >
                    {tab}
                </button>
                ))}
            </nav>

            <div className="relative w-full">
                <SearchIcon className="h-4 w-4 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
                <input
                    type="text"
                    placeholder={`Search ${isProfessionalView ? 'patient' : 'doctor'} records...`}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-gray-50 rounded-xl border-none pl-10 pr-4 py-2.5 focus:ring-2 focus:ring-blue-500 text-sm dark:bg-gray-700 dark:text-white shadow-inner"
                />
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 animate-fade-in pb-20">
        {filteredAppointments.length > 0 ? (
          filteredAppointments.map((appointment) => (
              <AppointmentCard 
                  key={appointment.id} 
                  appointment={appointment} 
                  isProfessionalView={isProfessionalView}
                  onJoinVideo={handleJoinVideo}
                  onViewSummary={handleViewSummary}
                  onViewDetails={setDetailsAppointment}
              />
          ))
        ) : (
          <div className="lg:col-span-2 text-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-100 dark:bg-gray-800 dark:border-gray-700">
              <p className="text-gray-300 font-bold uppercase tracking-widest text-xs">No matching sessions</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Appointments;

import React from 'react';
import { HealthAlert, AlertLevel } from '../types';
import { ClockIcon } from './Icons';

interface AlertCardProps {
  alert: HealthAlert;
  onTakeAction: (alert: HealthAlert) => void;
}

const levelStyles = {
    [AlertLevel.High]: { border: 'border-l-red-500', bg: 'bg-red-50 dark:bg-red-900/20', text: 'text-red-700 dark:text-red-300', tagBg: 'bg-boticare-red dark:bg-red-900/50', tagText: 'text-boticare-red-dark dark:text-red-300' },
    [AlertLevel.Medium]: { border: 'border-l-yellow-500', bg: 'bg-yellow-50 dark:bg-yellow-900/20', text: 'text-yellow-700 dark:text-yellow-300', tagBg: 'bg-boticare-yellow dark:bg-yellow-900/50', tagText: 'text-boticare-yellow-dark dark:text-yellow-300' },
    [AlertLevel.Low]: { border: 'border-l-blue-500', bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-700 dark:text-blue-300', tagBg: 'bg-boticare-blue dark:bg-blue-900/50', tagText: 'text-boticare-blue-dark dark:text-blue-300' },
};

const AlertCard: React.FC<AlertCardProps> = ({ alert, onTakeAction }) => {
    const styles = levelStyles[alert.level];

    return (
        <div className={`bg-white p-3 md:p-4 rounded-xl border border-gray-100 border-l-4 ${styles.border} flex flex-row items-center justify-between dark:bg-gray-800 dark:border-gray-700 gap-2 shadow-sm hover:shadow-md transition-all`}>
            <div className="flex items-start space-x-2 md:space-x-3 min-w-0">
                <div className={`p-2 rounded-xl ${styles.bg} flex-shrink-0`}>
                    <alert.icon className={`w-5 h-5 md:w-6 md:h-6 ${styles.text}`} />
                </div>
                <div className="min-w-0">
                    <div className="flex flex-wrap items-center gap-1.5 md:gap-2">
                        <h4 className="font-bold text-[11px] md:text-sm truncate leading-tight">{alert.title}</h4>
                        <span className={`text-[7px] md:text-[9px] font-black uppercase px-1.5 py-0.5 rounded-lg ${styles.tagBg} ${styles.tagText}`}>
                            {alert.level}
                        </span>
                    </div>
                    <p className="text-[9px] md:text-xs text-gray-500 mt-1 line-clamp-1 dark:text-gray-400">{alert.description}</p>
                    <div className="flex items-center space-x-1 text-[8px] md:text-[9px] text-gray-400 mt-0.5 dark:text-gray-500 font-bold">
                        <ClockIcon className="w-2.5 h-2.5" />
                        <span>{alert.time}</span>
                    </div>
                </div>
            </div>
            <button 
                onClick={() => onTakeAction(alert)} 
                className="bg-boticare-primary text-[9px] md:text-xs text-white font-black uppercase tracking-widest px-2 py-2 md:px-4 rounded-lg dark:bg-blue-600 dark:hover:bg-blue-700 whitespace-nowrap flex-shrink-0 transition-transform active:scale-95 shadow-sm"
            >
                Action
            </button>
        </div>
    );
};

export default AlertCard;

import React, { useState } from 'react';
import { HEALTH_METRICS_DATA, HEALTH_ALERTS_DATA } from '../constants';
import HealthMetricCard from './HealthMetricCard';
import AlertCard from './AlertCard';
import MetricChart from './MetricChart';
import { PlusIcon } from './Icons';
import { HealthAlert, Page, Symptom } from '../types';
import MedicationReminderModal from './MedicationReminderModal';
import LogSymptomModal from './LogSymptomModal';
import Toast from './Toast';

interface HealthMetricsProps {
  setActivePage: (page: Page) => void;
}

const HealthMetrics: React.FC<HealthMetricsProps> = ({ setActivePage }) => {
  const [reminderModalAlert, setReminderModalAlert] = useState<HealthAlert | null>(null);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [selectedMetricId, setSelectedMetricId] = useState<string>(HEALTH_METRICS_DATA[0].id);
  const [isLogSymptomOpen, setIsLogSymptomOpen] = useState(false);
  const [symptoms, setSymptoms] = useState<Symptom[]>([
      { id: '1', name: 'Mild Headache', date: '2025-06-01', severity: 'Mild', description: 'Started in the afternoon after work.' }
  ]);

  const selectedMetric = HEALTH_METRICS_DATA.find(m => m.id === selectedMetricId);

  const handleTakeAction = (alert: HealthAlert) => {
    if (alert.title === 'Missed Medication') {
        setReminderModalAlert(alert);
    } else {
        setActivePage(Page.ScheduleAppointment);
    }
  };

  const handleAddSymptom = (newSymptom: Omit<Symptom, 'id'>) => {
      const symptom: Symptom = { ...newSymptom, id: Date.now().toString() };
      setSymptoms([symptom, ...symptoms]);
      setToastMessage('Symptom logged successfully');
  };

  return (
    <div className="space-y-6">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <MedicationReminderModal alert={reminderModalAlert} onClose={() => setReminderModalAlert(null)} onConfirm={() => {
              setReminderModalAlert(null);
              setToastMessage(`Reminder updated!`);
          }}
      />
      {isLogSymptomOpen && <LogSymptomModal onClose={() => setIsLogSymptomOpen(false)} onSave={handleAddSymptom} />}

      <div className="flex flex-row justify-between items-center px-1">
        <div>
            <h2 className="text-2xl font-black">Health Metrics</h2>
            <p className="text-xs md:text-sm text-gray-500 dark:text-gray-400">Deep dive into vital signs and clinical logs.</p>
        </div>
        <button 
            onClick={() => setIsLogSymptomOpen(true)}
            className="bg-boticare-primary text-white font-black uppercase tracking-widest text-[9px] md:text-xs px-2.5 py-2 md:px-5 rounded-xl flex items-center gap-1 hover:bg-opacity-90 transition-all dark:bg-blue-600 shadow-md active:scale-95 whitespace-nowrap"
        >
            <PlusIcon className="w-3.5 h-3.5 md:w-4 md:h-4" />
            <span>Symptom</span>
        </button>
      </div>

      <div className="bg-white p-4 md:p-6 rounded-3xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 animate-fade-in shadow-sm">
        <div className="flex justify-between items-center mb-6">
            <h3 className="text-[10px] md:text-sm font-black uppercase tracking-widest text-gray-400">Analytics Overview</h3>
            <div className="flex bg-gray-50 dark:bg-gray-900 p-1 rounded-xl">
                <button className="px-2.5 py-1 text-[9px] md:text-[10px] font-black uppercase rounded-lg bg-white dark:bg-gray-700 shadow-sm dark:text-white">7D</button>
                <button className="px-2.5 py-1 text-[9px] md:text-[10px] font-black uppercase rounded-lg text-gray-400">30D</button>
            </div>
        </div>
        {selectedMetric && <MetricChart data={selectedMetric.history} color="#3B82F6" label={selectedMetric.name} />}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {HEALTH_METRICS_DATA.map(metric => (
            <div key={metric.id} onClick={() => setSelectedMetricId(metric.id)} className={`cursor-pointer transition-all duration-200 rounded-3xl ${selectedMetricId === metric.id ? 'ring-2 ring-blue-500 shadow-lg scale-[1.01]' : 'hover:scale-[1.005]'}`}>
                <HealthMetricCard metric={metric} />
            </div>
          ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 pb-10">
        <div className="space-y-4">
            <h3 className="text-lg font-black px-1">Health Alerts</h3>
            {HEALTH_ALERTS_DATA.map(alert => <AlertCard key={alert.id} alert={alert} onTakeAction={handleTakeAction} />)}
        </div>

        <div className="space-y-4">
            <h3 className="text-lg font-black px-1">Recent Symptoms</h3>
            <div className="bg-white rounded-3xl border border-gray-100 overflow-hidden dark:bg-gray-800 dark:border-gray-700 shadow-sm">
                {symptoms.length > 0 ? (
                    <ul className="divide-y divide-gray-50 dark:divide-gray-700">
                        {symptoms.map(symptom => (
                            <li key={symptom.id} className="p-4 md:p-5 hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors">
                                <div className="flex justify-between items-start mb-2">
                                    <h4 className="font-bold text-xs md:text-sm">{symptom.name}</h4>
                                    <span className="text-[9px] md:text-[10px] font-bold text-gray-400 uppercase">{symptom.date}</span>
                                </div>
                                <span className={`text-[8px] md:text-[9px] font-black px-2 py-0.5 rounded-lg uppercase inline-block mb-2 ${
                                         symptom.severity === 'Severe' ? 'bg-red-50 text-red-600' :
                                         symptom.severity === 'Moderate' ? 'bg-yellow-50 text-yellow-600' : 'bg-green-50 text-green-600'
                                     }`}>
                                         {symptom.severity}
                                     </span>
                                <p className="text-[10px] md:text-xs text-gray-500 dark:text-gray-400 leading-relaxed line-clamp-2">{symptom.description}</p>
                            </li>
                        ))}
                    </ul>
                ) : (
                    <div className="p-10 text-center text-gray-400 text-[10px] font-black uppercase tracking-widest">No logs available</div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

export default HealthMetrics;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ChatMessage, Patient, UserProfile, Professional } from '../types';
import { SendIcon, XIcon, BackIcon, CheckCircleIcon, SparklesIcon } from './Icons';
import { getWordSuggestions } from '../services/geminiService';

interface PersonalChatProps {
    recipient: Patient | Professional | UserProfile | null;
    userProfile: UserProfile;
    onClose: () => void;
}

const formatChatTimestamp = (timestamp: string): string => {
    const messageDate = new Date(timestamp);
    const now = new Date();
    const timeOptions: Intl.DateTimeFormatOptions = { hour: '2-digit', minute: '2-digit', hour12: true };
    const time = messageDate.toLocaleTimeString([], timeOptions);
    if (now.toDateString() === messageDate.toDateString()) return `Today, ${time}`;
    return `${messageDate.toLocaleDateString([], { month: 'short', day: 'numeric' })}, ${time}`;
};

const PersonalChat: React.FC<PersonalChatProps> = ({ recipient, userProfile, onClose }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [input, setInput] = useState('');
    const [suggestions, setSuggestions] = useState<string[]>([]);
    const [isRecipientTyping, setIsRecipientTyping] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const suggestionTimeoutRef = useRef<number | null>(null);

    const isCurrentUserProfessional = userProfile.role === 'professional';

    const getLocalStorageKey = useCallback(() => {
        const userId = userProfile.email;
        const recipientIdentifier = recipient ? ('id' in recipient ? recipient.id.toString() : recipient.email) : 'unknown';
        const sortedIdentifiers = [userId, recipientIdentifier].sort().join('_');
        return `boticare_chat_history_${sortedIdentifiers}`;
    }, [userProfile.email, recipient]);

    useEffect(() => {
        const key = getLocalStorageKey();
        const savedMessages = localStorage.getItem(key);
        if (savedMessages) setMessages(JSON.parse(savedMessages));
    }, [getLocalStorageKey]);

    useEffect(() => {
        const key = getLocalStorageKey();
        localStorage.setItem(key, JSON.stringify(messages));
        scrollToBottom();
    }, [messages, getLocalStorageKey]);

    // Fetch AI suggestions based on conversation context
    useEffect(() => {
        if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current);
        suggestionTimeoutRef.current = window.setTimeout(async () => {
            if (messages.length > 0 || input.length > 2) {
                const fetched = await getWordSuggestions(input, messages);
                setSuggestions(fetched);
            } else {
                setSuggestions(["How are you feeling?", "Updates on labs?", "Next checkup?"]);
            }
        }, 800);
        return () => { if (suggestionTimeoutRef.current) clearTimeout(suggestionTimeoutRef.current); };
    }, [messages, input]);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const handleSend = (textToSend: string = input) => {
        const text = textToSend.trim();
        if (!text || isRecipientTyping) return;

        const currentTime = new Date().toISOString();
        const newMsg: ChatMessage = {
            sender: isCurrentUserProfessional ? 'professional' : 'user',
            text: text,
            timestamp: currentTime,
            isRead: false
        };
        setMessages(prev => [...prev, newMsg]);
        setInput('');
        setSuggestions([]);

        // Simulate "Delivered" then "Read" receipt update
        setTimeout(() => {
            setMessages(prev => prev.map(m => (m.timestamp === currentTime ? { ...m, isRead: false } : m)));
        }, 1000);

        setTimeout(() => {
            setMessages(prev => prev.map(m => (m.timestamp === currentTime ? { ...m, isRead: true } : m)));
        }, 3000);

        setIsRecipientTyping(true);
        setTimeout(() => {
            setIsRecipientTyping(false);
            const reply: ChatMessage = {
                sender: 'ai', // Differentiating sender for style purposes
                text: "I've received your message. Let me review your charts.",
                timestamp: new Date().toISOString(),
            };
            setMessages(prev => [...prev, reply]);
        }, 4500);
    };

    const handleSuggestionClick = (s: string) => {
        setInput(s);
        // We let the user see it in the input first as per "Allow users to tap a suggestion to insert it into the input field"
    };

    if (!recipient) return null;

    const recipientName = 'name' in recipient ? recipient.name : 'Unknown';
    const recipientAvatar = 'avatar' in recipient ? recipient.avatar : 'https://i.pravatar.cc/150';

    return (
        <div className="h-full flex flex-col bg-white dark:bg-gray-800 rounded-3xl border border-boticare-gray-medium dark:border-gray-700 shadow-xl animate-fade-in overflow-hidden">
            <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between bg-white dark:bg-gray-800 sticky top-0 z-10 shadow-sm">
                <div className="flex items-center gap-3">
                    <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg lg:hidden"><BackIcon className="w-5 h-5 text-gray-500" /></button>
                    <div className="relative">
                        <img src={recipientAvatar} className="w-10 h-10 rounded-full object-cover border-2 border-white dark:border-gray-700 shadow-sm" alt={recipientName} />
                        <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white dark:border-gray-800 rounded-full"></div>
                    </div>
                    <div>
                        <h3 className="font-bold text-gray-900 dark:text-white leading-tight">{recipientName}</h3>
                        <p className="text-[10px] text-green-600 font-bold uppercase tracking-wider">{isRecipientTyping ? 'Typing...' : 'Online'}</p>
                    </div>
                </div>
                <button onClick={onClose} className="hidden lg:block p-2 text-gray-400 hover:text-gray-600"><XIcon className="w-6 h-6"/></button>
            </div>

            <div className="flex-grow p-4 md:p-6 overflow-y-auto space-y-6 no-scrollbar bg-gray-50/50 dark:bg-gray-900/20">
                {messages.map((msg, idx) => {
                    const isSentByMe = msg.sender === 'user' || msg.sender === 'professional';
                    const isAI = msg.sender === 'ai';
                    return (
                        <div key={idx} className={`flex w-full ${isSentByMe ? 'justify-end' : 'justify-start'}`}>
                            <div className={`flex flex-col ${isSentByMe ? 'items-end' : 'items-start'} max-w-[85%]`}>
                                <div className={`px-4 py-3 rounded-2xl shadow-sm text-sm md:text-base border ${
                                    isSentByMe
                                        ? 'bg-blue-600 text-white border-blue-500 rounded-tr-none'
                                        : isAI 
                                            ? 'bg-purple-50 dark:bg-purple-900/20 text-purple-900 dark:text-purple-100 border-purple-100 dark:border-purple-800 rounded-tl-none'
                                            : 'bg-white dark:bg-gray-700 text-gray-800 dark:text-gray-100 border-gray-100 dark:border-gray-600 rounded-tl-none'
                                }`}>
                                    {isAI && <div className="flex items-center gap-1.5 mb-1 opacity-60"><SparklesIcon className="w-3 h-3" /><span className="text-[9px] font-black uppercase tracking-widest">Boticare AI</span></div>}
                                    <p className="leading-relaxed">{msg.text}</p>
                                </div>
                                <div className="flex items-center gap-1.5 mt-1.5 px-1 opacity-70">
                                    <span className="text-[10px] font-medium text-gray-400 dark:text-gray-500">{formatChatTimestamp(msg.timestamp)}</span>
                                    {isSentByMe && (
                                        <div className="flex items-center" title={msg.isRead ? "Read" : "Sent"}>
                                            <CheckCircleIcon className={`w-3 h-3 transition-colors ${msg.isRead ? 'text-blue-500' : 'text-gray-300 dark:text-gray-600'}`} />
                                            <CheckCircleIcon className={`w-3 h-3 -ml-1.5 transition-colors ${msg.isRead ? 'text-blue-500' : 'text-gray-300 dark:text-gray-600'}`} />
                                        </div>
                                    )}
                                    {isSentByMe && !msg.isRead && <span className="text-[9px] font-bold text-gray-400 uppercase">Delivered</span>}
                                    {isSentByMe && msg.isRead && <span className="text-[9px] font-bold text-blue-500 uppercase">Read</span>}
                                </div>
                            </div>
                        </div>
                    );
                })}
                {isRecipientTyping && (
                    <div className="flex items-center space-x-2 text-gray-400 p-2">
                        <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                        <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                        <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce"></div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            <div className="p-4 bg-white dark:bg-gray-800 border-t border-gray-100 dark:border-gray-700">
                {suggestions.length > 0 && (
                    <div className="flex items-center gap-2 mb-3 overflow-x-auto no-scrollbar pb-1 animate-fade-in">
                        {suggestions.map((s, i) => (
                            <button 
                                key={i} 
                                onClick={() => handleSuggestionClick(s)} 
                                className="whitespace-nowrap px-3 py-1.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-300 rounded-full text-[11px] font-bold border border-blue-100 dark:border-blue-800 hover:bg-blue-100 transition-all shadow-sm"
                            >
                                {s}
                            </button>
                        ))}
                    </div>
                )}
                <div className="relative flex items-center">
                    <input 
                        type="text" 
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyPress={e => e.key === 'Enter' && handleSend()}
                        placeholder="Type a secure message..."
                        className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-600 rounded-2xl pl-4 pr-14 py-3.5 shadow-inner focus:ring-2 focus:ring-blue-500 focus:outline-none dark:text-white transition-all text-sm md:text-base"
                    />
                    <button 
                        onClick={() => handleSend()} 
                        disabled={!input.trim() || isRecipientTyping} 
                        className="absolute right-2 p-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-all disabled:bg-gray-200 dark:disabled:bg-gray-700 shadow-md active:scale-95"
                    >
                        <SendIcon className="w-5 h-5 ml-0.5" />
                    </button>
                </div>
            </div>
        </div>
    );
};

export default PersonalChat;

import React, { useState } from 'react';
import { UsersIcon, CalendarIcon, AlertIcon, CheckCircleIcon, FileIcon } from './Icons';
import { APPOINTMENTS_DATA, MOCK_PATIENTS } from '../constants';
import { Page, PrescriptionRefillRequest, UserProfile } from '../types';
import Toast from './Toast';
import DateRangeModal from './DateRangeModal';
import HealthReportModal from './HealthReportModal';
import { updateRefillRequest, generateHealthReport } from '../services/geminiService';

interface ProfessionalDashboardProps {
    setActivePage: (page: Page) => void;
    userProfile: UserProfile;
    onAddNotification: (msg: string) => void;
}

const INITIAL_REFILLS: PrescriptionRefillRequest[] = [
    { id: 1, patientName: 'John Smith', drugName: 'Metformin', dosage: '500mg • Twice daily', timeAgo: '2h ago', patientId: 'patient2_supabase_id', professionalId: 'pro1_supabase_id' },
    { id: 2, patientName: 'Emily Davis', drugName: 'Lisinopril', dosage: '10mg • Once daily', timeAgo: '5h ago', patientId: 'patient5_supabase_id', professionalId: 'pro1_supabase_id' },
    { id: 3, patientName: 'Robert Brown', drugName: 'Artovastatin', dosage: '20mg • Once daily', timeAgo: '8h ago', patientId: 'patient4_supabase_id', professionalId: 'pro1_supabase_id' },
];

const ProfessionalDashboard: React.FC<ProfessionalDashboardProps> = ({ setActivePage, userProfile, onAddNotification }) => {
    const [refills, setRefills] = useState<PrescriptionRefillRequest[]>(INITIAL_REFILLS);
    const [toast, setToast] = useState<{ message: string; type: 'success' } | null>(null);

    // Health Report State
    const [isDateModalOpen, setIsDateModalOpen] = useState(false);
    const [isReportModalOpen, setIsReportModalOpen] = useState(false);
    const [isReportLoading, setIsReportLoading] = useState(false);
    const [reportContent, setReportContent] = useState('');
    const [reportDateRange, setReportDateRange] = useState<{start: string, end: string} | null>(null);
    const [selectedReportPatient, setSelectedReportPatient] = useState(MOCK_PATIENTS[0]);

    const stats = [
        { label: 'Patients', value: '1,248', icon: UsersIcon, color: 'bg-blue-500', trend: '+12' },
        { label: 'Today', value: '8', icon: CalendarIcon, color: 'bg-purple-500', trend: '2 left' },
        { label: 'Alerts', value: '3', icon: AlertIcon, color: 'bg-red-500', trend: 'Critical' },
        { label: 'Done', value: '15', icon: CheckCircleIcon, color: 'bg-green-500', trend: '95%' },
    ];

    const handleApprove = async (request: PrescriptionRefillRequest) => {
        const success = await updateRefillRequest(request.id, { status: 'approved' });
        if (success) {
            setRefills(prev => prev.filter(r => r.id !== request.id));
            setToast({ message: `Approved ${request.drugName}. Notification sent to Patient.`, type: 'success' });
            // This notification would be sent via Boticare App to the patient's device
            onAddNotification(`Patient ${request.patientName}: Your drug "${request.drugName}" has been approved by ${userProfile.name}.`);
        }
    };

    const handleDecline = async (request: PrescriptionRefillRequest) => {
        const success = await updateRefillRequest(request.id, { status: 'declined' });
        if (success) {
            setRefills(prev => prev.filter(r => r.id !== request.id));
            setToast({ message: `Refill request for ${request.drugName} declined.`, type: 'success' });
        }
    };

    const triggerReportFlow = (patient: any) => {
        setSelectedReportPatient(patient);
        setIsDateModalOpen(true);
    };

    const handleGenerateReport = async (start: string, end: string) => {
        setReportDateRange({ start, end });
        setIsDateModalOpen(false);
        setIsReportModalOpen(true);
        setIsReportLoading(true);

        const healthData = {
            patientName: selectedReportPatient.name,
            metrics: [], // Mocking empty for generation
            medications: [],
            appointments: []
        };
        const report = await generateHealthReport(healthData, start, end);
        setReportContent(report);
        setIsReportLoading(false);
    };

    return (
        <div className="space-y-6">
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

            <DateRangeModal isOpen={isDateModalOpen} onClose={() => setIsDateModalOpen(false)} onGenerate={handleGenerateReport} />
            <HealthReportModal isOpen={isReportModalOpen} isLoading={isReportLoading} content={reportContent} dateRange={reportDateRange} onClose={() => setIsReportModalOpen(false)} />

            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-black">Practice Dashboard</h2>
                    <p className="text-sm text-gray-500 dark:text-gray-400">Welcome back, {userProfile.name}.</p>
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                    <button onClick={() => triggerReportFlow(MOCK_PATIENTS[0])} className="flex-1 sm:flex-none px-4 py-2.5 bg-blue-50 text-blue-600 font-black uppercase tracking-tighter rounded-xl text-[10px] md:text-xs hover:bg-blue-100 transition-all border border-blue-100 shadow-sm active:scale-95">
                        <FileIcon className="w-3.5 h-3.5 inline mr-1" /> Health Report
                    </button>
                    <button className="flex-1 sm:flex-none px-4 py-2.5 bg-blue-600 text-white font-black uppercase tracking-tighter rounded-xl text-[10px] md:text-xs hover:bg-blue-700 shadow-lg active:scale-95">
                        + New Booking
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {stats.map((stat, i) => (
                    <div key={i} className="bg-white p-4 rounded-2xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 shadow-sm">
                        <div className="flex items-center gap-2 mb-2">
                            <stat.icon className={`w-4 h-4 text-blue-500`} />
                            <span className="text-[10px] font-black uppercase text-gray-400 tracking-widest">{stat.label}</span>
                        </div>
                        <div className="flex items-baseline gap-2">
                            <span className="text-xl font-black">{stat.value}</span>
                            <span className="text-[9px] font-bold text-blue-600">{stat.trend}</span>
                        </div>
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 pb-10">
                <div className="lg:col-span-2 space-y-4">
                    <h3 className="text-lg font-black px-1">Upcoming Sessions</h3>
                    {APPOINTMENTS_DATA.slice(0, 3).map((app) => (
                        <div key={app.id} className="bg-white p-4 rounded-2xl border border-gray-100 flex items-center justify-between dark:bg-gray-800 dark:border-gray-700">
                            <div className="flex items-center gap-3">
                                <img src={`https://i.pravatar.cc/150?u=${app.patientName}`} className="w-10 h-10 rounded-full border border-gray-100 dark:border-gray-600" alt="" />
                                <div>
                                    <p className="font-bold text-sm leading-tight">{app.patientName}</p>
                                    <p className="text-[10px] text-gray-500 font-bold uppercase">{app.time} • {app.type}</p>
                                </div>
                            </div>
                            <button onClick={() => triggerReportFlow({name: app.patientName})} className="p-2.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all" title="Generate Health Report"><FileIcon className="w-5 h-5"/></button>
                        </div>
                    ))}
                </div>

                <div className="space-y-4">
                    <h3 className="text-lg font-black px-1">Refill Queue</h3>
                    <div className="bg-white p-3 rounded-2xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 shadow-sm space-y-3">
                        {refills.length > 0 ? refills.map((req) => (
                            <div key={req.id} className="p-4 bg-gray-50 dark:bg-gray-700/30 rounded-2xl border border-gray-100 dark:border-gray-600">
                                <div className="flex justify-between items-start mb-2">
                                    <span className="text-[9px] font-black uppercase text-blue-600 bg-blue-50 dark:bg-blue-900/30 px-2 py-0.5 rounded-lg">Prescription</span>
                                    <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">{req.timeAgo}</span>
                                </div>
                                <p className="text-sm font-bold leading-tight">{req.patientName}</p>
                                <p className="text-[11px] text-gray-500 italic mb-4 dark:text-gray-400">{req.drugName} ({req.dosage})</p>
                                <div className="flex gap-2">
                                    <button onClick={() => handleApprove(req)} className="flex-1 bg-blue-600 text-white text-[10px] font-black uppercase py-2.5 rounded-lg hover:bg-blue-700 transition-all active:scale-95 shadow-sm">Approve</button>
                                    <button onClick={() => handleDecline(req)} className="flex-1 bg-white dark:bg-gray-600 text-gray-400 dark:text-gray-300 text-[10px] font-black uppercase py-2.5 rounded-lg hover:bg-gray-100 dark:hover:bg-gray-500 transition-all border border-gray-100 dark:border-gray-500 active:scale-95">Decline</button>
                                </div>
                            </div>
                        )) : (
                            <div className="p-8 text-center"><p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Queue empty</p></div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default ProfessionalDashboard;

import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA, MOCK_PATIENTS } from '../constants';
import AppointmentCard from './AppointmentCard';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import { Appointment, AppointmentStatus, Page, Professional, UserRole, Patient } from '../types';
import { PlusIcon, SearchIcon, VideoIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const STATUS_TABS = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
  'Call History'
];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  setVideoCallProfessional: (appointment: Appointment, professional?: Professional | null, patient?: Patient | null) => void;
  defaultToScheduling?: boolean;
  isProfessionalView?: boolean;
  userRole?: UserRole;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false, isProfessionalView, userRole }) => {
  const [activeTab, setActiveTab] = useState<string>(AppointmentStatus.Upcoming);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => {
        if (activeTab === 'Call History') return appointment.status === AppointmentStatus.Completed;
        return appointment.status === activeTab;
    })
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        const targetSearchName = isProfessionalView ? appointment.patientName : appointment.doctorName;
        return targetSearchName.toLowerCase().includes(lowerCaseQuery) || appointment.specialty.toLowerCase().includes(lowerCaseQuery);
    });

  const handleJoinVideo = (appointment: Appointment) => {
    const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
    const patient = MOCK_PATIENTS.find(p => p.name === appointment.patientName) || null;
    setVideoCallProfessional(appointment, professional, patient);
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    const summaryText = appointment.summary || await getAppointmentSummary(appointment);
    setAppointments(prev => prev.map(app => app.id === appointment.id ? { ...app, summary: summaryText } : app));
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  return (
    <div className="space-y-6">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <AppointmentSummaryModal {...summaryModalState} onClose={() => setSummaryModalState({ ...summaryModalState, appointment: null })} />
      <EditNotesModal appointment={editingAppointment} onClose={() => setEditingAppointment(null)} onSave={(id, notes) => {
          setAppointments(prev => prev.map(a => a.id === id ? { ...a, notes } : a));
          setEditingAppointment(null);
          setToastMessage('Notes updated.');
      }} />
      <AppointmentDetailsModal appointment={detailsAppointment} onClose={() => setDetailsAppointment(null)} />

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h2 className="text-2xl font-black">Clinical Schedule</h2>
            <p className="text-sm text-gray-500 dark:text-gray-400">Track and manage your upcoming consultations.</p>
        </div>
        {!isProfessionalView && (
            <button onClick={() => setActivePage(Page.ScheduleAppointment)} className="bg-blue-600 text-white font-bold px-5 py-3 rounded-xl flex items-center space-x-2 shadow-lg">
              <PlusIcon className="w-5 h-5" /> <span>Schedule</span>
            </button>
        )}
      </div>

      <div className="bg-white p-4 rounded-2xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 shadow-sm space-y-4">
        <div className="flex flex-col gap-4">
            <nav className="flex flex-wrap gap-2 overflow-x-auto no-scrollbar pb-1">
                {STATUS_TABS.map((tab) => (
                <button
                    key={tab}
                    onClick={() => setActiveTab(tab)}
                    className={`px-3 py-2 text-[10px] md:text-xs font-black uppercase tracking-widest rounded-xl transition-all whitespace-nowrap flex-grow sm:flex-grow-0 ${
                    activeTab === tab
                        ? 'bg-blue-600 text-white shadow-md'
                        : 'text-gray-400 hover:bg-gray-50 bg-gray-50/50 dark:bg-gray-700 dark:hover:bg-gray-600'
                    }`}
                >
                    {tab}
                </button>
                ))}
            </nav>

            <div className="relative w-full">
                <SearchIcon className="h-4 w-4 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
                <input
                    type="text"
                    placeholder={`Search ${isProfessionalView ? 'patient' : 'doctor'} records...`}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-gray-50 rounded-xl border-none pl-10 pr-4 py-2.5 focus:ring-2 focus:ring-blue-500 text-sm dark:bg-gray-700 dark:text-white shadow-inner"
                />
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 animate-fade-in pb-20">
        {filteredAppointments.length > 0 ? (
          filteredAppointments.map((appointment) => (
              <AppointmentCard 
                  key={appointment.id} 
                  appointment={appointment} 
                  isProfessionalView={isProfessionalView}
                  onJoinVideo={handleJoinVideo}
                  onViewSummary={handleViewSummary}
                  onViewDetails={setDetailsAppointment}
              />
          ))
        ) : (
          <div className="lg:col-span-2 text-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-100 dark:bg-gray-800 dark:border-gray-700">
              <p className="text-gray-300 font-bold uppercase tracking-widest text-xs">No matching sessions</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Appointments;

