const AvailabilitySettings: React.FC<AvailabilitySettingsProps> = ({ userProfile, onSave }) => {
    const daysOfWeek = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
    const [availability, setAvailability] = useState<Record<string, AvailabilitySlot>>({});
    const [isLoading, setIsLoading] = useState(false);

    useEffect(() => {
        const fetchAvailability = async () => {
            const userId = (await supabase.auth.getUser()).data.user?.id;
            if (!userId) return;

            setIsLoading(true);
            const fetchedSlots = await getProfessionalAvailability(userId);
            const initialAvailability: Record<string, AvailabilitySlot> = {};

            daysOfWeek.forEach(day => {
                const existing = fetchedSlots.find(slot => slot.dayOfWeek === day);
                initialAvailability[day] = existing || { dayOfWeek: day, startTime: '09:00', endTime: '17:00', isEnabled: false };
            });

            setAvailability(initialAvailability);
            setIsLoading(false);
        };
        fetchAvailability();
    }, []);

    const handleToggleDay = (day: string, enabled: boolean) => {
        setAvailability(prev => ({
            ...prev,
            [day]: { ...prev[day], isEnabled: enabled }
        }));
    };

    const handleTimeChange = (day: string, field: 'startTime' | 'endTime', value: string) => {
        setAvailability(prev => ({
            ...prev,
            [day]: { ...prev[day], [field]: value }
        }));
    };

    const handleSaveAvailability = async () => {
        const userId = (await supabase.auth.getUser()).data.user?.id;
        if (!userId) return;

        setIsLoading(true);
        const slotsToSave = Object.values(availability);
        const success = await saveProfessionalAvailability(userId, slotsToSave);
        if (success) {
            onSave("Your practice hours have been updated.", 'success');
        } else {
            onSave("Failed to update availability. Please try again.", 'success');
        }
        setIsLoading(false);
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex items-center space-x-3 mb-2">
                <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
