    const [availability, setAvailability] = useState<Record<string, AvailabilitySlot>>({});
    const [isLoading, setIsLoading] = useState(false);

    useEffect(() => {
        const fetchAvailability = async () => {
            if (!userProfile.supabaseId) return;

            setIsLoading(true);
            const fetchedSlots = await getProfessionalAvailability(userProfile.supabaseId);
            const initialAvailability: Record<string, AvailabilitySlot> = {};

            daysOfWeek.forEach(day => {
                const existing = fetchedSlots.find(slot => slot.dayOfWeek === day);
                initialAvailability[day] = existing || { dayOfWeek: day, startTime: '09:00', endTime: '17:00', isEnabled: false };
            });

            setAvailability(initialAvailability);
            setIsLoading(false);
        };
        fetchAvailability();
    }, [userProfile.supabaseId]);

    const handleToggleDay = (day: string, enabled: boolean) => {
        setAvailability(prev => ({
            ...prev,
            [day]: { ...prev[day], isEnabled: enabled }
        }));
    };

    const handleTimeChange = (day: string, field: 'startTime' | 'endTime', value: string) => {
        setAvailability(prev => ({
            ...prev,
            [day]: { ...prev[day], [field]: value }
        }));
    };

    const handleSaveAvailability = async () => {
        if (!userProfile.supabaseId) return;

        setIsLoading(true);
        const slotsToSave = Object.values(availability);
        const success = await saveProfessionalAvailability(userProfile.supabaseId, slotsToSave);
        if (success) {
            onSave("Your practice hours have been updated.", 'success');
        } else {
            onSave("Failed to update availability. Please try again.", 'success');
        }
        setIsLoading(false);
    };

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex items-center space-x-3 mb-2">
                <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
                    <ClockIcon className="w-6 h-6 text-blue-600 dark:text-blue-400" />
                </div>
                <div>
                    <h3 className="text-xl font-bold">Consultation Availability</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400">Set the hours when patients can book sessions with you.</p>
                </div>
            </div>

            <div className="p-6 border border-boticare-gray-medium rounded-2xl dark:border-gray-700 bg-gray-50/50 dark:bg-gray-900/20">
                {isLoading ? (
                    <div className="flex flex-col items-center justify-center py-20">
                        <div className="w-10 h-10 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                        <p className="mt-4 font-bold text-gray-500 uppercase tracking-widest text-[10px]">Loading Schedule...</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {daysOfWeek.map(day => (
                            <div key={day} className="flex flex-col md:flex-row items-start md:items-center justify-between p-4 bg-white dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm transition-all hover:shadow-md">
                                <div className="flex items-center space-x-4 mb-3 md:mb-0 min-w-[150px]">
                                    <ToggleSwitch
                                        id={`toggle-${day}`}
                                        enabled={availability[day]?.isEnabled || false}
                                        onChange={(enabled) => handleToggleDay(day, enabled)}
                                    />
                                    <span className={`font-bold transition-colors ${availability[day]?.isEnabled ? 'text-gray-900 dark:text-white' : 'text-gray-400'}`}>{day}</span>
                                </div>

                                {availability[day]?.isEnabled ? (
                                    <div className="flex items-center space-x-3 w-full md:w-auto animate-fade-in">
                                        <div className="flex-1 md:w-32 relative">
                                            <input
                                                type="time"
                                                value={availability[day]?.startTime || '09:00'}
                                                onChange={(e) => handleTimeChange(day, 'startTime', e.target.value)}
                                                className="w-full bg-boticare-gray dark:bg-gray-700 border-none rounded-lg px-4 py-2 text-sm font-bold focus:ring-2 focus:ring-blue-500 dark:text-white"
                                            />
                                        </div>
                                        <span className="text-gray-400 font-bold">to</span>
                                        <div className="flex-1 md:w-32 relative">
                                            <input
                                                type="time"
                                                value={availability[day]?.endTime || '17:00'}
                                                onChange={(e) => handleTimeChange(day, 'endTime', e.target.value)}
                                                className="w-full bg-boticare-gray dark:bg-gray-700 border-none rounded-lg px-4 py-2 text-sm font-bold focus:ring-2 focus:ring-blue-500 dark:text-white"
                                            />
                                        </div>
                                    </div>
                                ) : (
                                    <span className="text-xs font-black uppercase text-gray-300 dark:text-gray-600 tracking-widest italic">Closed for sessions</span>
                                )}
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <div className="flex justify-end pt-4">
                <button
                    onClick={handleSaveAvailability}
                    disabled={isLoading}
                    className="bg-blue-600 text-white font-black uppercase tracking-widest text-xs px-8 py-4 rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 dark:shadow-none transition-all active:scale-95 disabled:opacity-50"
                >
                    {isLoading ? 'Saving...' : 'Sync Schedule'}
                </button>
            </div>
        </div>
    );
};

const AccountSettings: React.FC = () => {
