interface SettingsProps {
    userProfile: UserProfile;
    onProfileUpdate: (p: UserProfile) => void;
    isDarkMode: boolean;
    setIsDarkMode: (d: boolean) => void;
}

const Settings: React.FC<SettingsProps> = ({ userProfile, onProfileUpdate, isDarkMode, setIsDarkMode }) => {
    const [activeView, setActiveView] = useState<SettingView>('main');
    const [toast, setToast] = useState<{message: string, type: 'success'} | null>(null);
    const isProfessional = userProfile.role === 'professional';

    const handleSaveProfile = (updated: UserProfile) => { 
        onProfileUpdate(updated); 
        setToast({message: "Profile updated successfully", type: 'success'}); 
        setActiveView('main');
    };

    const handleSaveAvailabilityToast = (message: string, type: 'success') => {
        setToast({ message, type });
        setActiveView('main');
    };

    const renderView = () => {
        switch (activeView) {
            case 'profile': return <ProfileSettings profile={userProfile} onSave={handleSaveProfile} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />;
            case 'practice': return <PracticeDetails profile={userProfile} onSave={handleSaveProfile} />;
            case 'availability': return <AvailabilitySettings userProfile={userProfile} onSave={handleSaveAvailabilityToast} />;
            case 'account': return <AccountSettings />;
            case 'notifications': return <AlertPreferences alertLevels={{[AlertLevel.High]: true, [AlertLevel.Low]: false, [AlertLevel.Medium]: true}} glucoseThresholds={{low: 70, high: 140}} appointmentReminders={{remind24h: true, remind1h: true}} onLevelChange={()=>{}} onThresholdChange={()=>{}} onReminderChange={()=>{}} onSaveChanges={()=>{}} onReset={()=>{}} />;
            default: return <MainSettingsView setView={setActiveView} isProfessional={isProfessional} />;
        }
    };

    return (
        <div className="max-w-4xl mx-auto pb-20">
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
            <div className="flex items-center mb-8">
                {activeView !== 'main' && (<button onClick={() => setActiveView('main')} className="p-2 bg-white dark:bg-gray-800 rounded-xl mr-4 shadow-sm border border-gray-100 dark:border-gray-700 hover:translate-x-[-2px] transition-transform"><BackIcon className="w-5 h-5 text-gray-500" /></button>)}
                <h2 className="text-3xl font-black tracking-tight">{activeView === 'main' ? 'Settings' : 'Manage ' + activeView.charAt(0).toUpperCase() + activeView.slice(1).replace('settings', ' Settings')}</h2>
            </div>
            <div className="bg-white p-6 md:p-10 rounded-3xl border border-boticare-gray-medium dark:bg-gray-800 dark:border-gray-700 shadow-xl shadow-gray-100 dark:shadow-none">{renderView()}</div>
        </div>
    );
};

export default Settings;

import React, { useState } from 'react';
import { APPOINTMENTS_DATA, PROFESSIONALS_DATA, MOCK_PATIENTS, VIDEO_CALL_HISTORY_DATA } from '../constants';
import AppointmentCard from './AppointmentCard';
import AppointmentSummaryModal from './AppointmentSummaryModal';
import EditNotesModal from './EditNotesModal';
import AppointmentDetailsModal from './AppointmentDetailsModal';
import Toast from './Toast';
import { Appointment, AppointmentStatus, Page, Professional, UserRole, Patient, VideoCallRecord } from '../types';
import { PlusIcon, SearchIcon, VideoIcon, CalendarIcon, ClockIcon } from './Icons';
import { getAppointmentSummary } from '../services/geminiService';

const STATUS_TABS = [
  AppointmentStatus.Upcoming,
  AppointmentStatus.Completed,
  AppointmentStatus.Canceled,
  AppointmentStatus.Rescheduled,
  'Call History'
];

interface AppointmentsProps {
  setActivePage: (page: Page) => void;
  setVideoCallProfessional: (appointment: Appointment, professional?: Professional | null, patient?: Patient | null) => void;
  defaultToScheduling?: boolean;
  isProfessionalView?: boolean;
  userRole?: UserRole;
}

const Appointments: React.FC<AppointmentsProps> = ({ setActivePage, setVideoCallProfessional, defaultToScheduling = false, isProfessionalView, userRole }) => {
  const [activeTab, setActiveTab] = useState<string>(AppointmentStatus.Upcoming);
  const [appointments, setAppointments] = useState<Appointment[]>(APPOINTMENTS_DATA);
  const [toastMessage, setToastMessage] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [detailsAppointment, setDetailsAppointment] = useState<Appointment | null>(null);
  const [summaryModalState, setSummaryModalState] = useState<{
    appointment: Appointment | null;
    summary: string;
    isLoading: boolean;
  }>({ appointment: null, summary: '', isLoading: false });

  const filteredAppointments = appointments
    .filter((appointment) => {
        if (activeTab === 'Call History') return false; // Handled separately
        return appointment.status === activeTab;
    })
    .filter((appointment) => {
        if (!searchQuery) return true;
        const lowerCaseQuery = searchQuery.toLowerCase();
        const targetSearchName = isProfessionalView ? appointment.patientName : appointment.doctorName;
        return targetSearchName.toLowerCase().includes(lowerCaseQuery) || appointment.specialty.toLowerCase().includes(lowerCaseQuery);
    });

  const handleJoinVideo = (appointment: Appointment) => {
    const professional = PROFESSIONALS_DATA.find(p => p.name === appointment.doctorName) || null;
    const patient = MOCK_PATIENTS.find(p => p.name === appointment.patientName) || null;
    setVideoCallProfessional(appointment, professional, patient);
  };

  const handleViewSummary = async (appointment: Appointment) => {
    setSummaryModalState({ appointment, summary: '', isLoading: true });
    const summaryText = appointment.summary || await getAppointmentSummary(appointment);
    setAppointments(prev => prev.map(app => app.id === appointment.id ? { ...app, summary: summaryText } : app));
    setSummaryModalState({ appointment, summary: summaryText, isLoading: false });
  };

  return (
    <div className="space-y-6">
      {toastMessage && <Toast message={toastMessage} type="success" onClose={() => setToastMessage(null)} />}
      <AppointmentSummaryModal {...summaryModalState} onClose={() => setSummaryModalState({ ...summaryModalState, appointment: null })} />
      <EditNotesModal appointment={editingAppointment} onClose={() => setEditingAppointment(null)} onSave={(id, notes) => {
          setAppointments(prev => prev.map(a => a.id === id ? { ...a, notes } : a));
          setEditingAppointment(null);
          setToastMessage('Notes updated.');
      }} />
      <AppointmentDetailsModal appointment={detailsAppointment} onClose={() => setDetailsAppointment(null)} />

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h2 className="text-2xl font-black">Clinical Schedule</h2>
            <p className="text-sm text-gray-500 dark:text-gray-400">Track and manage your upcoming consultations.</p>
        </div>
        {!isProfessionalView && (
            <button onClick={() => setActivePage(Page.ScheduleAppointment)} className="bg-blue-600 text-white font-bold px-5 py-3 rounded-xl flex items-center space-x-2 shadow-lg">
              <PlusIcon className="w-5 h-5" /> <span>Schedule</span>
            </button>
        )}
      </div>

      <div className="bg-white p-4 rounded-2xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 shadow-sm space-y-4">
        <div className="flex flex-col gap-4">
            <nav className="flex flex-wrap gap-2 overflow-x-auto no-scrollbar pb-1">
                {STATUS_TABS.map((tab) => (
                <button
                    key={tab}
                    onClick={() => setActiveTab(tab)}
                    className={`px-3 py-2 text-[10px] md:text-xs font-black uppercase tracking-widest rounded-xl transition-all flex-grow sm:flex-grow-0 whitespace-nowrap ${
                    activeTab === tab
                        ? 'bg-blue-600 text-white shadow-md'
                        : 'text-gray-400 hover:bg-gray-50 bg-gray-50/50 dark:bg-gray-700 dark:hover:bg-gray-600'
                    }`}
                >
                    {tab}
                </button>
                ))}
            </nav>

            <div className="relative w-full">
                <SearchIcon className="h-4 w-4 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
                <input
                    type="text"
                    placeholder={`Search ${isProfessionalView ? 'patient' : 'doctor'} records...`}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-gray-50 rounded-xl border-none pl-10 pr-4 py-2.5 focus:ring-2 focus:ring-blue-500 text-sm dark:bg-gray-700 dark:text-white shadow-inner"
                />
            </div>
        </div>
      </div>

      <div className="pb-20">
        {activeTab === 'Call History' ? (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 animate-fade-in">
              {VIDEO_CALL_HISTORY_DATA.map((record) => (
                  <div key={record.id} className="bg-white p-5 rounded-2xl border border-gray-100 dark:bg-gray-800 dark:border-gray-700 shadow-sm flex items-center justify-between group hover:shadow-md transition-shadow">
                      <div className="flex items-center space-x-4">
                          <img src={record.professionalAvatar} alt="" className="w-12 h-12 rounded-full border border-gray-100" />
                          <div>
                              <p className="font-bold text-gray-900 dark:text-white">{record.professionalName}</p>
                              <div className="flex items-center space-x-3 mt-1">
                                  <span className="flex items-center text-[10px] font-bold text-gray-400 uppercase"><CalendarIcon className="w-3 h-3 mr-1" />{record.date}</span>
                                  <span className="flex items-center text-[10px] font-bold text-gray-400 uppercase"><ClockIcon className="w-3 h-3 mr-1" />{record.time}</span>
                              </div>
                          </div>
                      </div>
                      <div className="text-right">
                          <span className="text-[10px] font-black uppercase text-blue-600 bg-blue-50 dark:bg-blue-900/30 px-2 py-1 rounded-lg">Duration: {record.duration}</span>
                          <button className="block text-[10px] font-bold text-gray-400 mt-2 hover:text-blue-600 transition-colors uppercase tracking-widest">View Transcript</button>
                      </div>
                  </div>
              ))}
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 animate-fade-in">
            {filteredAppointments.length > 0 ? (
              filteredAppointments.map((appointment) => (
                  <AppointmentCard 
                      key={appointment.id} 
                      appointment={appointment} 
                      isProfessionalView={isProfessionalView}
                      onJoinVideo={handleJoinVideo}
                      onViewSummary={handleViewSummary}
                      onViewDetails={setDetailsAppointment}
                  />
              ))
            ) : (
              <div className="lg:col-span-2 text-center py-20 bg-white rounded-3xl border-2 border-dashed border-gray-100 dark:bg-gray-800 dark:border-gray-700">
                  <p className="text-gray-300 font-bold uppercase tracking-widest text-xs">No matching sessions</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Appointments;

import React, { useState, useEffect, useRef } from 'react';
import { Patient, Professional, Appointment } from '../types';
import { MicIcon, MicOffIcon, VideoOnIcon, VideoOffIcon, EndCallIcon, UserIcon, AlertIcon } from './Icons';
import FeedbackModal from './FeedbackModal';
import { logVideoCallSession } from '../services/geminiService';

interface VideoCallProps {
  appointment: Appointment | null;
  professional?: Professional | null;
  patient?: Patient | null;
  isProfessionalView?: boolean;
  onEndCall: () => void;
}

const generateUUID = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};

const VideoCall: React.FC<VideoCallProps> = ({ appointment, professional, patient, isProfessionalView, onEndCall }) => {
  const [isMuted, setIsMuted] = useState(false);
  const [isCameraOn, setIsCameraOn] = useState(true);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [connectionState, setConnectionState] = useState<'connecting' | 'connected' | 'failed'>('connecting');
  const [mediaError, setMediaError] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);
  const userVideoRef = useRef<HTMLVideoElement>(null);
  const userStreamRef = useRef<MediaStream | null>(null);
  const callStartTimeRef = useRef<string | null>(null);
  const sessionIdRef = useRef<string>(generateUUID());

  useEffect(() => {
    let mounted = true;
    const startStream = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: 'user' }, 
            audio: { echoCancellation: true, noiseSuppression: true } 
        });

        if (mounted) {
            userStreamRef.current = stream;
            if (userVideoRef.current) {
                userVideoRef.current.srcObject = stream;
                await userVideoRef.current.play().catch(e => console.error("Video play failed", e));
            }
        }
      } catch (err: any) {
        console.error("Media Error:", err);
        if (mounted) {
            setMediaError("Unable to access camera or microphone. Please check permissions.");
            setConnectionState('failed');
        }
      }
    };
    startStream();
    return () => {
      mounted = false;
      if (userStreamRef.current) {
        userStreamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  useEffect(() => {
    if (mediaError) return;
    const connectTimer = setTimeout(() => {
        if (connectionState === 'connecting') {
            setConnectionState('connected');
            callStartTimeRef.current = new Date().toISOString();
        }
    }, 2500);
    return () => clearTimeout(connectTimer);
  }, [mediaError, connectionState]);

  useEffect(() => {
    if (connectionState !== 'connected') return;
    const timerId = setInterval(() => setElapsedTime(prev => prev + 1), 1000);
    return () => clearInterval(timerId);
  }, [connectionState]);

  const toggleMic = () => { 
      if (userStreamRef.current) { 
          userStreamRef.current.getAudioTracks().forEach(t => t.enabled = !t.enabled); 
          setIsMuted(!isMuted); 
      } 
  };

  const toggleCamera = () => { 
      if (userStreamRef.current) { 
          userStreamRef.current.getVideoTracks().forEach(t => t.enabled = !t.enabled); 
          setIsCameraOn(!isCameraOn); 
      } 
  };

  const handleEndCallClick = async () => { 
      if (userStreamRef.current) {
          userStreamRef.current.getTracks().forEach(t => t.stop()); 
      }

      if (connectionState === 'connected' && appointment && callStartTimeRef.current) {
        const endTime = new Date().toISOString();
        const durationSeconds = elapsedTime;
        const recordingUrl = `https://boticare-vault.medical/recording/${sessionIdRef.current}`;

        // Log to Supabase using IDs from the appointment object
        await logVideoCallSession(
            sessionIdRef.current,
            appointment.id.toString(),
            appointment.professionalId,
            appointment.patientId,
            callStartTimeRef.current,
            endTime,
            durationSeconds,
            recordingUrl
        );
      }
      setShowFeedback(true); 
  };

  const targetName = isProfessionalView ? (patient?.name || appointment?.patientName || 'Patient') : (professional?.name || appointment?.doctorName || 'Practitioner');
  const targetAvatar = isProfessionalView ? (patient?.avatar || `https://i.pravatar.cc/150?u=${appointment?.patientName}`) : (professional?.avatar || appointment?.avatar || 'https://i.pravatar.cc/150?u=pro');

  return (
    <div className="animate-fade-in space-y-4 pb-10 h-[calc(100vh-140px)] flex flex-col">
        {showFeedback && <FeedbackModal isOpen onClose={() => onEndCall()} onSubmit={() => onEndCall()} source="video_call" />}

        <div className="flex items-center space-x-4 p-4 bg-white dark:bg-gray-800 rounded-2xl border border-boticare-gray-medium dark:border-gray-700 shadow-sm flex-shrink-0">
            {connectionState === 'connected' ? (
                <span className="relative flex h-3 w-3">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
                </span>
            ) : (
                <div className="w-3 h-3 rounded-full bg-yellow-400 animate-pulse"></div>
            )}

            <span className={`text-[10px] font-black px-2.5 py-1 rounded-lg uppercase tracking-widest ${connectionState === 'connected' ? 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300' : 'bg-yellow-100 text-yellow-800'}`}>
                {connectionState === 'connected' ? 'Live Encrypted' : 'Connecting...'}
            </span>

            <h2 className="text-lg font-bold truncate">Session with {targetName}</h2>
            <span className="text-sm font-mono font-bold text-blue-600 ml-auto">{Math.floor(elapsedTime / 60)}:{String(elapsedTime % 60).padStart(2, '0')}</span>
        </div>

        <div className="relative flex-grow bg-gray-900 rounded-3xl overflow-hidden shadow-2xl group border border-gray-800">
            <div className="absolute inset-0 flex items-center justify-center">
                {connectionState === 'connected' ? (
                    <img src={targetAvatar} className="w-full h-full object-cover opacity-80" alt={targetName} />
                ) : connectionState === 'failed' ? (
                    <div className="text-center p-8 space-y-4">
                        <AlertIcon className="w-16 h-16 text-red-500 mx-auto" />
                        <p className="text-white font-bold text-lg">{mediaError || "Connection Failed"}</p>
                    </div>
                ) : (
                    <div className="flex flex-col items-center space-y-4">
                        <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                        <p className="text-white font-bold tracking-wider uppercase text-sm">Establishing Secure Connection...</p>
                    </div>
                )}
            </div>

            {connectionState === 'connected' && (
                <div className="absolute bottom-6 left-6 text-white bg-black/50 backdrop-blur-md px-4 py-2 rounded-xl border border-white/20 z-10">
                    <p className="font-bold text-sm">{targetName}</p>
                    <p className="text-[10px] opacity-70 uppercase tracking-wider">Remote Stream • HD</p>
                </div>
            )}

            <div className="absolute top-6 right-6 w-32 h-48 md:w-48 md:h-32 bg-gray-800 rounded-2xl overflow-hidden border-2 border-white/30 shadow-2xl z-20 transition-all hover:scale-105">
                <video 
                    ref={userVideoRef} 
                    autoPlay 
                    muted 
                    playsInline 
                    className={`w-full h-full object-cover transform scale-x-[-1] ${isCameraOn ? 'block' : 'hidden'}`} 
                />
                 {!isCameraOn && <div className="w-full h-full flex items-center justify-center bg-gray-700"><UserIcon className="w-12 h-12 text-gray-500" /></div>}
                <div className="absolute bottom-2 left-2 text-[10px] font-bold text-white bg-black/50 px-2 py-0.5 rounded-lg">You</div>
            </div>

            <div className="absolute bottom-8 left-0 right-0 flex items-center justify-center space-x-6 z-30">
                <button onClick={toggleMic} className={`p-4 rounded-full transition-all shadow-lg hover:scale-110 active:scale-95 ${isMuted ? 'bg-white text-red-600' : 'bg-white/20 backdrop-blur-md text-white hover:bg-white/30 border border-white/20'}`}>
                    {isMuted ? <MicOffIcon className="w-6 h-6" /> : <MicIcon className="w-6 h-6" />}
                </button>

                <button onClick={handleEndCallClick} className="w-16 h-16 rounded-full bg-red-600 hover:bg-red-700 text-white flex items-center justify-center shadow-xl hover:scale-110 active:scale-95 transition-all">
                    <EndCallIcon className="w-8 h-8" />
                </button>

                <button onClick={toggleCamera} className={`p-4 rounded-full transition-all shadow-lg hover:scale-110 active:scale-95 ${!isCameraOn ? 'bg-white text-red-600' : 'bg-white/20 backdrop-blur-md text-white hover:bg-white/30 border border-white/20'}`}>
                    {!isCameraOn ? <VideoOffIcon className="w-6 h-6" /> : <VideoOnIcon className="w-6 h-6" />}
                </button>
            </div>
        </div>
    </div>
  );
};

